INSERT INTO public.questions VALUES ('4dd0557f-6d79-48ac-900a-9f00df02f569', 'b0c2e2b5-b177-47e5-9138-86a84f281a4c', 'radio', 'Questions 21–24', '', '<p>Choose the correct letter, A, B or C.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A It was the most severe eruption in modern times"}, {"option_text": "B It led to the formal study of volcanoes"}, {"option_text": "C It had a profound effect on society"}], "question": "Why do the students think the Laki eruption of 1783 is so important?"}, {"correct": 0, "options": [{"option_text": "A the number of places producing them"}, {"option_text": "B the contradictions in them"}, {"option_text": "C the lack of scientific data to support them"}], "question": "What surprised Adam about observations made at the time?"}, {"correct": 1, "options": [{"option_text": "A People thought it was similar to ordinary fog"}, {"option_text": "B It was associated with health issues"}, {"option_text": "C It completely blocked out the sun for weeks"}], "question": "According to Michelle, what did the contemporary sources say about the Laki haze?"}, {"correct": 0, "options": [{"option_text": "A came to the wrong conclusion about the cause of the haze"}, {"option_text": "B was the first to identify the reason for the haze"}, {"option_text": "C supported the opinions of other observers about the haze"}], "question": "Adam corrects Michelle when she claims that Benjamin Franklin"}]', 'null', 'null', 'null', 'null', 0);
