INSERT INTO public.questions VALUES ('6220180d-db46-40cd-9df0-2ef0f9226361', 'b0c2e2b5-b177-47e5-9138-86a84f281a4c', 'matrix', 'Questions 27–30', '', '<p data-start="1330" data-end="1429">What comment do the students make about the impact of the Laki eruption on the following countries?</p>
<p data-start="1431" data-end="1523">Choose <strong>FOUR</strong> answers from the box and write the correct letter, A–F, next to Questions 27–30.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "Iceland ", "correctCategoryLetter": "D"}, {"itemText": "Egypt", "correctCategoryLetter": "A"}, {"itemText": "UK", "correctCategoryLetter": "C"}, {"itemText": "USA", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "This country suffered the most severe loss of life", "categoryLetter": "A"}, {"categoryText": "The impact on agriculture was predictable", "categoryLetter": "B"}, {"categoryText": "There was a significant increase in deaths of young people", "categoryLetter": "C"}, {"categoryText": "Animals suffered from a sickness", "categoryLetter": "D"}, {"categoryText": "This country saw the highest rise in food prices in the world", "categoryLetter": "E"}, {"categoryText": "It caused a particularly harsh winter", "categoryLetter": "F"}]}', 'null', 2);
