INSERT INTO public.questions VALUES ('dd8281aa-0401-4056-a243-b6899a7b669a', '39dd93c3-65bc-4cf3-9dfa-b8f820e5ecbc', 'radio', 'Questions 11–13', '', '<p>Choose the correct answers</p>
<p><span style="font-size: 12pt;"><strong>Information for new employees</strong></span></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "some staff work for only part of the year."}, {"option_text": "there are two different finishing times."}, {"option_text": "extra production staff are taken on when necessary."}], "question": "Because demand for the company’s products is seasonal"}, {"correct": 1, "options": [{"option_text": "Holiday leave is organised on a rota."}, {"option_text": "Some holiday leave must be taken during a fixed period."}, {"option_text": "All employees are entitled to the same amount of holiday leave."}], "question": "What does the speaker say about annual holiday leave?"}, {"correct": 2, "options": [{"option_text": "enter the building."}, {"option_text": "clock in."}, {"option_text": "be at their place of work."}], "question": "Start times indicate when employees should"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('386d4bfe-4037-4dd4-ac24-629e404bfb07', '39dd93c3-65bc-4cf3-9dfa-b8f820e5ecbc', 'matrix', 'Questions 14–20', '', '<p>Label the plan below.</p>
<p>Choose the correct letter, A–J, next to questions 14–20.</p>
<p><img src="data:image/png;base64," width="545" height="594" loading="lazy"></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Training Room", "correctCategoryLetter": "I"}, {"itemText": "Locker Rooms", "correctCategoryLetter": "J"}, {"itemText": "Loading Bay", "correctCategoryLetter": "E"}, {"itemText": "Storeroom", "correctCategoryLetter": "A"}, {"itemText": "Production manager’s Office", "correctCategoryLetter": "B"}, {"itemText": "Security Office", "correctCategoryLetter": "D"}, {"itemText": "Cafeteria", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}, {"categoryText": "J", "categoryLetter": "J"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('5e8f6c06-b084-4c73-8a04-d760a8086144', 'd2e8a9c0-927e-4bc2-a682-356c8e781c33', 'radio', 'Questions 21–24', '', '<p data-start="90" data-end="116">Choose the correct answer.</p>
<p data-start="118" data-end="157"><strong><span style="font-size: 12pt;">Bachelor of Communications Degree</span></strong></p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "will help him get work in other countries"}, {"option_text": "has easier courses than the Public Relations major"}, {"option_text": "could lead to a well-paid job in New Zealand"}], "question": "Simon thinks the Global Communications major"}, {"correct": 1, "options": [{"option_text": "too challenging for him"}, {"option_text": "uninteresting as a subject"}, {"option_text": "similar to other courses on the major"}], "question": "Simon says that the Economic Principles course was"}, {"correct": 0, "options": [{"option_text": "give students a better understanding of the whole major"}, {"option_text": "are less useful than the courses dealing with culture"}, {"option_text": "should remain optional to students"}], "question": "Anna thinks that the foreign language courses"}, {"correct": 2, "options": [{"option_text": "it was a language she had previously studied"}, {"option_text": "it would enable her to travel"}, {"option_text": "it could be useful in commerce"}], "question": "What reason does Anna give for her choice of foreign language?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: BACHELOR OF COMMUNICATIONS DISCUSSION</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Simon:</strong> Excuse me, are you Anna Jenkins?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Anna:</strong> Yes.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Simon:</strong> My name is Simon. I’m on the Bachelor of Communications course, Year 1, and I really need some advice from someone who’s ahead of me. I was told you were in Year 3.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Anna:</strong> That’s right. How’s it going?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Simon:</strong> Hmm, I’m not convinced I chose the right major. At present, I’m doing Public Relations. That’s why I want to talk to you. You’re doing the Global Communications major, right?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Anna:</strong> Yes. Are you going to change to that?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Simon:</strong> Possibly, if it helps my career.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Anna:</strong> Won’t the Public Relations course do that?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Simon:</strong> If I just wanted to work in New Zealand, yes. I mean, I’ve heard of graduates finding work here almost immediately and with good salaries. But <strong data-path-to-node=\"11\" data-index-in-node=\"150\">(21) I’d like to go abroad, and I imagine the Global major would give me the skills so I could go and work anywhere [Answer: A]</strong>. I know it’ll be hard work starting again, but I would be motivated.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Anna:</strong> I see. But I’m still not sure you need to change majors to achieve your goal. Aren’t some of the courses the same for both majors?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Simon:</strong> Some are the same, yes. But I’m not sure I’m cut out for the business aspects of Public Relations. Economic Principles, for example. I understand what it’s all about—I did economics at high school—but <strong data-path-to-node=\"13\" data-index-in-node=\"208\">(22) I just found it dull [Answer: B – uninteresting]</strong>. I want to study something creative, something that connects you to people.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Anna:</strong> Well, the Global major certainly does that.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Simon:</strong> Is it right you have to learn a language?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Anna:</strong> Well, it was compulsory when I started, but it’s up to you now.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Simon:</strong> Do you think it’s necessary to learn one?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Anna:</strong> Well, so much of the major is looking at ways that culture and language influence communication, and <strong data-path-to-node=\"18\" data-index-in-node=\"107\">(23) if you learn a second language yourself, you definitely get more of an insight into what the theory is all about [Answer: A]</strong>.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Simon:</strong> But I’m no good at languages. Which one is the easiest?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Anna:</strong> I’m not sure that’s the best rationale for a choice. In my first year, we could go for Chinese, Japanese or Maori. <strong data-path-to-node=\"20\" data-index-in-node=\"121\">(24) I went for Chinese because New Zealand has so many trade deals with China now [Answer: C – commerce]</strong>. But Japanese would be good if you think you might end up in tourism. I did Maori at high school and it was fascinating, but it would restrict you to doing business within New Zealand.</p>\n<hr data-path-to-node=\"21\">\n<h3 data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">LECTURERS AND COURSES (Questions 25–30)</strong></h3>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Simon:</strong> What did you think of your lectures?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Anna:</strong> Oh, I have to say they’re great. And when we were working on our individual proposals for the internships, <strong data-path-to-node=\"24\" data-index-in-node=\"113\">(25-26) they pushed us to keep working on producing the best work possible [Answer: E – improve]</strong>. And even though I kept having to adapt it, I actually felt proud of mine eventually.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Simon:</strong> Yes, ours push us too, which is good. Sometimes you don’t know what you’re capable of, and it makes you a lot more enthusiastic. Sometimes if the lecturer sits down with you for a chat, it’s more motivating than a written report.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Anna:</strong> I completely agree. And I suppose one thing I really like is <strong data-path-to-node=\"26\" data-index-in-node=\"67\">(25-26) the way they encourage us to challenge their opinions [Answer: A – freedom of thought]</strong>, as long as we can come up with a sound argument to support our case. I think that’s helped me develop some useful critical thinking skills.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Simon:</strong> That’s good. I think whatever major you do, all the lecturers want to encourage that. At least, that’s my experience. What did you enjoy most about the Global Communications major?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Anna:</strong> Well, <strong data-path-to-node=\"28\" data-index-in-node=\"12\">Communication 1</strong> was really useful. I was never very confident at speaking in front of large groups, but that showed us how to use different voice techniques and <strong data-path-to-node=\"28\" data-index-in-node=\"173\">(27) how to give interactive presentations [Answer: D – talking in public]</strong>. I had to give a presentation to some executives during my internship and I did quite well after that.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Simon:</strong> Sounds interesting.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Anna:</strong> <strong data-path-to-node=\"30\" data-index-in-node=\"6\">Psychology</strong> was absolutely fascinating. You get to look at what motivates people and <strong data-path-to-node=\"30\" data-index-in-node=\"90\">(28) how people operate within a big team [Answer: B – working in large groups]</strong>. That’s really essential when you’re trying to get all the people to cooperate on a project that has the pressure of a deadline.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Simon:</strong> In the brochure, <strong data-path-to-node=\"31\" data-index-in-node=\"24\">Interpersonal Skills</strong> looks good.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Anna:</strong> I didn’t do that course.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Simon:</strong> It says it’s about how to listen properly, how to <strong data-path-to-node=\"33\" data-index-in-node=\"57\">(29) manage conflict in relationships—you know, when colleagues are arguing [Answer: C – co-workers]</strong>. The first step to improve things is better communication. That’s pretty logical. And this one, <strong data-path-to-node=\"33\" data-index-in-node=\"254\">Communication 3</strong>…</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Anna:</strong> <strong data-path-to-node=\"34\" data-index-in-node=\"6\">(30) What kinds of behaviour are likely to cause offence or misunderstanding between nationalities in the global business world [Answer: E – cultural differences]</strong>. Yes, I enjoyed that.</p>"}]', 0);
INSERT INTO public.questions VALUES ('9f34fc86-a4b0-4a5f-824c-0bc7e53d9a40', 'd2e8a9c0-927e-4bc2-a682-356c8e781c33', 'checkbox', 'Questions 25–26', '', '<p data-start="951" data-end="978">Choose <strong>TWO </strong>correct answers.</p>
<p data-start="980" data-end="1059">Which <strong>TWO </strong>things do Anna and Simon both appreciate about their lecturers?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "They encourage freedom of thought"}, {"correct": false, "option_text": "They help individual students in seminars"}, {"correct": false, "option_text": "They are willing to adapt courses"}, {"correct": false, "option_text": "They are enthusiastic about their subject"}, {"correct": true, "option_text": "They encourage students to improve"}]', 'null', 'null', '[{"content": "<h2>DICTATION</h2>\n<div class=\"chat-turn-container code-block-aligner model render ng-star-inserted cdk-focused cdk-mouse-focused\" tabindex=\"-1\">\n<div class=\"virtual-scroll-container model-prompt-container\" data-turn-role=\"Model\">\n<div class=\"turn-content\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">SECTION 3: BACHELOR OF COMMUNICATIONS DISCUSSION</span></strong></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Excuse me, are you Anna Jenkins?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Yes.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> My name is Simon. I’m on the Bachelor of Communications course, Year 1, and I </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(1) ________________________________</span></strong><span class=\"ng-star-inserted\"> someone who’s ahead of me. I was told you were in Year 3.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> That’s right. How’s it going?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Hmm, I’m not </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(2) ________________________________</span></strong><span class=\"ng-star-inserted\"> major. At present, I’m doing Public Relations. That’s why I want to talk to you. You’re doing the Global Communications major, right?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Yes. Are you going to change to that?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Possibly, if it helps my career.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Won’t the Public Relations course do that?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> If I just wanted to work in New Zealand, yes. I mean, I’ve heard of graduates finding work here almost immediately and with good salaries. But </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(3) ________________________________</span></strong><span class=\"ng-star-inserted\">, and I imagine the Global major would </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(4) ________________________________</span></strong><span class=\"ng-star-inserted\"> I could go and work anywhere. I know it’ll be hard work starting again, but I would be motivated.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> I see. But I’m still not sure you need to change majors to achieve your goal. Aren’t some of the courses the same for both majors?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Some are the same, yes. But I’m not sure I’m cut out for the business aspects of Public Relations. Economic Principles, for example. I understand what it’s all about—I did economics at high school—but </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(5) ________________________________</span></strong><span class=\"ng-star-inserted\">. I want to study something creative, something that connects you to people.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Well, the Global major certainly does that.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Is it right you have to learn a language?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Well, it </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(6) ________________________________</span></strong><span class=\"ng-star-inserted\">, but it’s up to you now.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Do you think it’s necessary to learn one?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Well, so much of the major is looking at ways that culture and language influence communication, and </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(7) ________________________________</span></strong><span class=\"ng-star-inserted\"> yourself, you definitely get more of an insight into what the theory is all about.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> But I’m </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(8) ________________________________</span></strong><span class=\"ng-star-inserted\">. Which one is the easiest?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> I’m not sure that’s the best rationale for a choice. In my first year, we could go for Chinese, Japanese or Maori. </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(9) ________________________________</span></strong><span class=\"ng-star-inserted\"> New Zealand has </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(10) ________________________________</span></strong><span class=\"ng-star-inserted\"> China now. But Japanese would be good if you think you </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(11) ________________________________</span></strong><span class=\"ng-star-inserted\">. I did Maori at high school and it was fascinating, but it would restrict you to doing business within New Zealand.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> What did you think of your lectures?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Oh, I have to say they’re great. And when we were working on our </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(12) ________________________________</span></strong><span class=\"ng-star-inserted\">, they pushed us to keep working on </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(13) ________________________________</span></strong><span class=\"ng-star-inserted\">. And even though I kept having to adapt it, I actually felt proud of mine eventually.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Yes, ours push us too, which is good. Sometimes you don’t know what you’re capable of, and it makes you a lot more enthusiastic. Sometimes if the lecturer </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(14) ________________________________</span></strong><span class=\"ng-star-inserted\"> a chat, it’s more motivating than a written report.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> I completely agree. And I suppose one thing I really like is the way they </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(15) ________________________________</span></strong><span class=\"ng-star-inserted\"> opinions, as long as we can come up with a sound argument to support our case. I think that’s helped me develop some </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(16) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> That’s good. I think whatever major you do, all the lecturers want to encourage that. At least, that’s my experience. What did you enjoy most about the Global Communications major?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Well, Communication 1 was really useful. I was never very confident at </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(17) ________________________________</span></strong><span class=\"ng-star-inserted\"> groups, but that showed us how to use different voice techniques and </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(18) ________________________________</span></strong><span class=\"ng-star-inserted\">. I had to give a presentation to some executives during my internship and I did quite well after that.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> Sounds interesting.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> Psychology was absolutely fascinating. You get to look at what motivates people and </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(19) ________________________________</span></strong><span class=\"ng-star-inserted\"> big team. That’s really essential when you’re trying to get all the people to cooperate on a project that has the pressure of a deadline.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> In the brochure, Interpersonal Skills looks good.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> I didn’t do that course.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Simon:</span></strong><span class=\"ng-star-inserted\"> It says it’s about how to listen properly, how to </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(20) ________________________________</span></strong><span class=\"ng-star-inserted\">—you know, when colleagues are arguing. The first step to improve things is better communication. That’s pretty logical. And this one, Communication 3…</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Anna:</span></strong><span class=\"ng-star-inserted\"> What kinds of behaviour are likely to cause offence or misunderstanding between nationalities in the global business world. Yes, I enjoyed that.</span></p>\n<hr class=\"ng-star-inserted\">\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">ĐÁP ÁN (ANSWER KEY)</span></strong></h3>\n<ol class=\"ng-star-inserted\">\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">really need some advice from</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">convinced I chose the right</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">I’d like to go abroad</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">give me the skills so</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">I just found it dull</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">was compulsory when I started</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">if you learn a second language</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">no good at languages</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">I went for Chinese because</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">so many trade deals with</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">might end up in tourism</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">individual proposals for the internships</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">producing the best work possible</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">sits down with you for</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">encourage us to challenge their</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">useful critical thinking skills</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">speaking in front of large</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">how to give interactive presentations</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">how people operate within a</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">manage conflict in relationships</span></strong></p>\n</li>\n</ol>\n</div>\n</div>\n<div class=\"turn-footer ng-star-inserted\"> </div>\n</div>"}]', 1);
INSERT INTO public.questions VALUES ('c2c785f3-3276-4b5c-a25e-3e6cb13ab50b', 'd2e8a9c0-927e-4bc2-a682-356c8e781c33', 'matching', 'Questions 27–30', '', '<p>Which skills are developed in the following courses?<br data-start="1352" data-end="1355">Choose <strong>FOUR </strong>correct answers, <strong>A</strong>–<strong>F</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Courses</strong></span></p>\n<p> </p>\n<p>Communication 1 {talking in public}</p>\n<p> </p>\n<p>Psychology {working in large groups}</p>\n<p> </p>\n<p>Interpersonal Skills {reducing problems between co-workers}</p>\n<p> </p>\n<p>Communication 3 {understanding cultural differences}</p>", "answerOptions": [{"optionText": "making decisions under pressure"}, {"optionText": "working in large groups"}, {"optionText": "reducing problems between co-workers"}, {"optionText": "talking in public"}, {"optionText": "understanding cultural differences"}, {"optionText": "using logical argument"}], "matchingItems": []}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('0288df44-06bb-416c-aaae-f10a0eb9e7c0', '9287e0ae-8cd9-4adc-88ad-f0580f784798', 'checkbox', 'Questions 21 and 22', '', '<p>Choose <strong>TWO </strong>letters A–E</p>
<p>What are the <strong>TWO </strong>benefits of including work experience in the first year of the engineering course?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "It encourages students to develop their sense of responsibility."}, {"correct": true, "option_text": "It familiarises students with engineering equipment."}, {"correct": true, "option_text": "It helps students understand work-related terms."}, {"correct": false, "option_text": "It helps students decide in which area to specialize."}, {"correct": false, "option_text": "It frees students from doing work experience in the second year."}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('cd5b3f86-18e2-4731-ae00-dcba46c0c500', '97c3e18c-6bbd-4aec-8e00-99b74cfd93a0', 'fillup', 'Questions 14–19', '<p><span class="fontstyle0">Complete the flow-chart below.</span></p>
<p><span class="fontstyle0">Write </span><span class="fontstyle2"><strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> </span><span class="fontstyle0">from the passage for each answer.</span></p>
<p><span class="fontstyle0">Write your answers in boxes 14-19 on your answer sheet.</span> </p>
<p style="text-align: center;"><strong><span style="font-size: 14pt;"><span class="fontstyle0">Step-by-step guide to making Flynn’s water filters</span> </span></strong></p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Make the mixture for the filter from organic material (e.g., tea, coffee, rice), {clay} and {water}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Shape into pots and place them in a fire made from {straw} and {cow manure}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9582%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8745%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Fuel the fire to reach a maximum temperature of {950 degrees}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9582%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8745%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Remove the filters from the fire.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9582%; height: 33.7083px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8745%;"></colgroup>
<tbody>
<tr style="height: 33.7083px;">
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Bake the filters in the fire for a maximum period of {60 minutes}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14 &amp; 15. clay — water — {Make the mixture for the filter from organic material (e.g., tea, coffee, rice), clay and water}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Take a handful of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"39\">clay</strong>, mix it with a handful of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"70\">organic material</strong> such as used tea leaves, coffee grounds or rice hulls, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"142\">add water</strong> in a sufficient quantity to make a stiff mixture...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để làm ra hỗn hợp làm bộ lọc, bài đọc hướng dẫn lấy một nắm đất sét (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"81\">clay</strong>), trộn với một nắm nguyên liệu hữu cơ (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"125\">organic material</em> như trà, cà phê, vỏ trấu) và thêm nước (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"182\">water</strong>). Do đó hai từ cần điền ở đây là <em data-path-to-node=\"5,1,0\" data-index-in-node=\"221\">clay</em> và <em data-path-to-node=\"5,1,0\" data-index-in-node=\"229\">water</em>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16 &amp; 17. straw — cow manure — {Shape into pots and place them in a fire made from straw and cow manure}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“...Next, surround the pots with <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"53\">straw</strong>, put them in a mound of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"83\">cow manure</strong>, light the straw and then top up the burning manure as required.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi nặn thành các chậu gốm, bước tiếp theo là bao bọc chúng bằng rơm (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"86\">straw</strong>), đặt vào một đống phân bò (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"120\">cow manure</strong>) rồi đốt rơm để mồi lửa. Lửa này được tạo ra từ hai chất liệu là <em data-path-to-node=\"7,1,0\" data-index-in-node=\"196\">straw</em> và <em data-path-to-node=\"7,1,0\" data-index-in-node=\"205\">cow manure</em>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">18. 950 degrees — {Fuel the fire to reach a maximum temperature of 950 degrees}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“...as the fuel can reach a temperature of 700 degrees in half an hour, and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"96\">will be up to 950 degrees after another 20 to 30 minutes</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"up to\" trong bài đọc đồng nghĩa với từ \"maximum\" (tối đa). Đống lửa sau khi cháy thêm một thời gian sẽ đạt đến nhiệt độ tối đa là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"150\">950 degrees</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">19. 60 minutes — {Bake the filters in the fire for a maximum period of 60 minutes}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The filters are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"37\">finished in 45 to 60 minutes</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Quá trình nung bánh/lọc này sẽ hoàn thành (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"55\">finished</em>) trong khoảng từ 45 đến 60 phút. Vì đề bài dùng chữ \"maximum period\" (thời gian tối đa) nên con số lớn nhất cần điền chính là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"190\">60 minutes</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('469ac5ed-e66b-4a40-bf2c-ac24ba8a769c', 'cb0d737c-34e4-4f9a-9f0a-d8ea017c9c23', 'radio', 'Questions 11–15', '', '<p><span class="citation-63752">Choose the correct letter, </span><strong data-path-to-node="15" data-index-in-node="27"><span class="citation-63752">A</span></strong><span class="citation-63752">, </span><strong data-path-to-node="15" data-index-in-node="30"><span class="citation-63752">B</span></strong><span class="citation-63752"> or </span><strong data-path-to-node="15" data-index-in-node="35"><span class="citation-63752">C</span></strong><span class="citation-63752 citation-end-63752">.</span></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A going to a theme park."}, {"option_text": "B experiencing a river trip."}, {"option_text": "C visiting a cheese factory."}], "question": "During the visit to Malatte, in France, members especially enjoyed"}, {"correct": 0, "options": [{"option_text": "A A tree will be planted."}, {"option_text": "B A garden seat will be bought."}, {"option_text": "C A footbridge will be built."}], "question": "What will happen in Stanthorpe to mark the 25th anniversary of the Twinning Association?"}, {"correct": 1, "options": [{"option_text": "A the film show"}, {"option_text": "B the pancake evening"}, {"option_text": "C the cookery demonstration"}], "question": "Which event raised most funds this year?"}, {"correct": 2, "options": [{"option_text": "A take them for a walk round the town."}, {"option_text": "B go to a local restaurant."}, {"option_text": "C have a meal at home."}], "question": "For the first evening with the French visitors host families are advised to"}, {"correct": 0, "options": [{"option_text": "A listen to a concert."}, {"option_text": "B watch a match."}, {"option_text": "C take part in a competition."}], "question": "On Saturday evening there will be the chance to"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('295651bc-8403-4410-9023-0ca59bf94f63', '9287e0ae-8cd9-4adc-88ad-f0580f784798', 'checkbox', 'Questions 23 and 24', '', '<p>Choose <strong>TWO </strong>letters, A–E</p>
<p>Which do the students agree are the <strong>TWO </strong>best criteria for choosing a work experience placement?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "the chance to have paid holiday"}, {"correct": true, "option_text": "the chance to see interaction between staff members"}, {"correct": false, "option_text": "the chance to see examples of problem-solving by management"}, {"correct": false, "option_text": "the chance to participate in a range of work activities"}, {"correct": true, "option_text": "the chance to be employed there after graduation"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('a9aded63-3698-4074-b493-9a0bee71ce38', 'bddbf0c8-07ea-4839-853a-0963e07a00ba', 'fillup', 'Questions 1 – 5', '<p> Complete the table below.</p>
<p data-start="190" data-end="230"><span role="text"><strong data-start="194" data-end="230">Ohope Holiday Park Accommodation</strong></span></p>
<div class="TyagGW_tableContainer">
<div class="group TyagGW_tableWrapper flex flex-col-reverse w-fit" tabindex="-1">
<table class="w-fit min-w-(--thread-content-width)" style="width: 99.9989%; height: 229.75px; border-collapse: collapse; border-spacing: 2px; border: 2px solid rgb(0, 0, 0);" border="1" data-start="232" data-end="640">
<thead data-start="232" data-end="292">
<tr style="height: 53.1875px;" data-start="232" data-end="292">
<th class="" style="width: 11.5011%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="232" data-end="248" data-col-size="sm">
<p><strong>Type of cabin</strong></p>
</th>
<th class="" style="width: 15.2877%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="248" data-end="259" data-col-size="sm">
<p><strong>Location</strong></p>
</th>
<th class="" style="width: 27.9231%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="259" data-end="272" data-col-size="sm">
<p><strong>Facilities</strong></p>
</th>
<th class="" style="width: 37.3025%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="272" data-end="292" data-col-size="md">
<p><strong>Cost and charges</strong></p>
</th>
</tr>
</thead>
<tbody data-start="354" data-end="640">
<tr style="height: 70.1875px;" data-start="354" data-end="436">
<td style="width: 11.5011%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="354" data-end="362" data-col-size="sm">
<p>Basic</p>
</td>
<td style="width: 15.2877%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="sm" data-start="362" data-end="381">
<p>next to the pool</p>
</td>
<td style="width: 27.9231%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="sm" data-start="381" data-end="419">
<p>kitchen has a fridge and a {Microwave}</p>
</td>
<td style="width: 37.3025%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="md" data-start="419" data-end="436">
<p>$35 per night</p>
</td>
</tr>
<tr style="height: 53.1875px;" data-start="437" data-end="525">
<td style="width: 11.5011%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="437" data-end="448" data-col-size="sm">
<p>Standard</p>
</td>
<td style="width: 15.2877%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="sm" data-start="448" data-end="468">
<p>close to {Reception}</p>
</td>
<td style="width: 27.9231%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="sm" data-start="468" data-end="508">
<p>fully-equipped kitchen and a {Shower}</p>
</td>
<td style="width: 37.3025%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="md" data-start="508" data-end="525">
<p>$55 per night</p>
</td>
</tr>
<tr style="height: 53.1875px;" data-start="526" data-end="640">
<td style="width: 11.5011%; border-color: #000000; padding: 2px; border-width: 2px;" data-start="526" data-end="542" data-col-size="sm">
<p>Standard Plus</p>
</td>
<td style="width: 15.2877%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="sm" data-start="542" data-end="564">
<p>facing the {Lake}</p>
</td>
<td style="width: 27.9231%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="sm" data-start="564" data-end="585">
<p>comes with own spa</p>
</td>
<td style="width: 37.3025%; border-color: #000000; padding: 2px; border-width: 2px;" data-col-size="md" data-start="585" data-end="640">
<p>discount of {18} % for bookings over ten nights</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 1: OHOPE HOLIDAY PARK ACCOMMODATION</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Woman:</strong> Good morning, Ohope Holiday Park.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Man:</strong> Oh hello. We''re planning on coming to Ohope for a couple of weeks during the summer holidays, and some friends of mine recommended your holiday park, particularly the wooden cabins you have.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Woman:</strong> That''s good to hear. Well, we have different types of cabin available.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Man:</strong> Can you tell me about the most basic type?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Woman:</strong> Yes, we have a couple of cabins still available which are right beside the pool.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Man:</strong> That sounds great.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Woman:</strong> Yes, they are in a good spot. They have one main living area and there''s another room with the beds. If you want to do any cooking, there''s a communal kitchen that everyone uses, but otherwise, the kitchen in the cabin just has a fridge—a small one—and also a <span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"267\">(Q1) microwave</strong></span></span> for heating things up.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Man:</strong> I see. And what''s the cost of that?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Woman:</strong> That''s $35 per night.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Man:</strong> Okay. And what other types of cabin do you have?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Woman:</strong> Right, we have our standard cabins. These are near <span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"58\">(Q2) reception</strong></span></span>, so that''s handy if you want to come in and get us to book a trip or anything. The kitchen is fully equipped too, so you can do all your cooking there.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Man:</strong> What other facilities does it have? Is there a television?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Woman:</strong> In the standard cabin.I''m afraid not, but it has a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"36\">(Q3) shower</strong></span>, which you don''t get in the basic cabin.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Man:</strong> Okay.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Woman: </strong>And that''s $55 a night inclusive.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Man: </strong>And is there another cabin type?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Woman:</strong> Yes, the standard plus. All of these cabins are directly opposite the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"77\">(Q4) lake</strong></span>, and they all come with a private spa as well.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Man:</strong> Sounds good.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Woman: </strong>I should tell you that these cabins are quite popular, so I''d advise you to book as soon as possible.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Man: </strong>I don''t suppose there''s a discount for booking for a longer period?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Woman:</strong> There is actually for the standard plus. Once you go up to five nights, there''s a 15% discount and anything more than 10 nights, it''s <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"141\">(Q5) 18%</strong></span>.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Man: </strong>I''ll give it some thought. I think we''ll probably go for the standard.</p>\n<hr data-path-to-node=\"21\">\n<h3 data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">GENERAL INFORMATION (Questions 6–10)</strong></h3>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Man:</strong> So for children, what kind of activities can they do at the holiday park? Do you have a trampoline or anything?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Woman:</strong> No, but a lot of the kids who come here do <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"50\">(Q6) tennis</strong></span>. It cost nothing to use our court, and they can come borrow the rackets from us as long as they bring them back, of course.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Man:</strong> Great, my kids would be into that. And we''re planning to bring our boat with us and get out on the water. Is it possible for an afternoon or something to hire some equipment? We''re hoping to go <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"199\">(Q7) fishing</strong></span>, but we don''t have our own stuff.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Woman:</strong> Yes, for a small charge, we can let you have some equipment.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Man:</strong> Fantastic. Is there anything else for kids to do in the Ohope area?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Woman:</strong> Well, on Saturday or Sunday, you might like to go to the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"64\">(Q8) farm</strong></span>. It''s only a short drive from the holiday park. You can go riding there and see how everything works. It''s quite a popular thing to do.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Man:</strong> Okay, I''ll just make a note of that.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Woman:</strong> Actually, one thing I would recommend, depending on whether your children don''t mind a late night...</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"7\" data-index-in-node=\"1064\">Man:</strong> I''m sure they wouldn''t.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"7\" data-index-in-node=\"1093\">Woman: </strong>Well, it''s a guided tour, $20 for a family every evening, and you go along with the guide into the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"207\">(Q9) forest</strong></span>. That''s when the native birds wake up, and it''s a great chance to see them in their natural habitat.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Man:</strong> My daughter would love that. Now I just wanna check all this with my wife. Will you still be there in 30 minutes?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Woman:</strong> No, I''m going on my lunch break, but I''ll pass your details on to someone else who can confirm your reservation. Her name''s <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"32\" data-index-in-node=\"131\">(Q10) Arataki</strong></span>. That''s A-R-A-T-A-K-I.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Man:</strong> Alright, thank you.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Woman:</strong> You''re welcome.</p>"}]', 0);
INSERT INTO public.questions VALUES ('e7c17608-19f7-41d1-a5e3-bc1155c0dfe1', 'e58ca488-6cf2-4205-8f71-9988d592e3eb', 'matching', ' Questions 21–26', NULL, '<p>Choose <strong>SIX</strong> correct answers, <strong>A-I</strong>, next to questions 21-26.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Environmental Science modules</strong></p>\r\n<p> </p>\r\n<p>Statistics for environmental research {F was too basic to be useful}</p>\r\n<p> </p>\r\n<p>Sewage and drainage systems {A was surprisingly interesting}</p>\r\n<p> </p>\r\n<p>Agriculture and food security {C included out-of-date materials}</p>\r\n<p> </p>\r\n<p>Sustainable energy {D involved practical applications}</p>\r\n<p> </p>\r\n<p>Government policy {I seemed too limited geographically}</p>\r\n<p> </p>\r\n<p>Water management {G provided unnecessary detail}</p>", "answerOptions": [{"optionText": "A was surprisingly interesting"}, {"optionText": "B covered too many topics"}, {"optionText": "C included out-of-date materials"}, {"optionText": "D involved practical applications"}, {"optionText": "E supplied useful technical information"}, {"optionText": "F was too basic to be useful"}, {"optionText": "G provided unnecessary detail"}, {"optionText": "H was relevant to a topic in the news"}, {"optionText": "I seemed too limited geographically"}], "matchingItems": null}', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 3</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Jamie:</strong> Hi Martha, do you have time to talk? We have to submit our evaluations of our course next week, and I thought it’d be useful to discuss what we both think.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Martha:</strong> Good idea. That would help refresh my memory, especially about things we did in previous years.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Jamie:</strong> I agree. So let’s talk about the modules we took. What about <strong data-path-to-node=\"5\" data-index-in-node=\"68\">Statistics for environmental research</strong>? I’ve always been hopeless with numbers, so I thought that I’d learn a lot, but you know <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"5\" data-index-in-node=\"195\">(21) it wasn’t at a high enough level for me (F: too basic to be useful)</strong></span>. I actually had to do a lot of reading on my own.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Martha:</strong> Me too. I had to get an additional reading list from the tutor. Now <strong data-path-to-node=\"6\" data-index-in-node=\"76\">Sewage and drainage systems</strong>. I wasn’t looking forward to that one. Not exactly a pleasant subject, but you know, the module convinced me that it’s an essential topic to understand for both cities and rural environments.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Jamie:</strong> Right, and in the end, not a boring subject?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Martha:</strong> Not at all. <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"8\" data-index-in-node=\"20\">(22) It was quite a revelation (A: surprisingly interesting)</strong></span>.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Jamie:</strong> The module on <strong data-path-to-node=\"9\" data-index-in-node=\"21\">Agriculture and food security</strong> could have been good, but <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"9\" data-index-in-node=\"77\">(23) the assigned readings were only those ancient government publications and the lecture notes clearly hadn’t been updated for years (C: out-of-date materials)</strong></span>.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Martha:</strong> I know. What about the module on <strong data-path-to-node=\"10\" data-index-in-node=\"41\">Sustainable energy</strong>? I really got into the project we had to do to invent something functional. I devised a windmill to power my laptop.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Jamie:</strong> Yep, the <strong data-path-to-node=\"11\" data-index-in-node=\"16\"><span style=\"text-decoration: underline; background-color: #fbeeb8;\">(24) projects were great, so hands-on (D: involved practical applications)</span></strong>. Though the personal battery charger I built never really worked.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Martha:</strong> Too bad, but I’m sure you learned a lot nonetheless.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Jamie:</strong> I did. And the <strong data-path-to-node=\"13\" data-index-in-node=\"22\">Government policy</strong> module. I wish it had included policy in other countries. <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"13\" data-index-in-node=\"98\">(25) It was a bit inward-looking, I thought, focused just on this country (I: too limited geographically)</strong></span>. I mentioned that to the lecturer, but she said it was best to concentrate on one country in depth at first, maybe.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Martha:</strong> And there was that module called <strong data-path-to-node=\"14\" data-index-in-node=\"41\">Water management</strong>. I must admit I got lost in the discussion about the issues of groundwater levels and flood risk management, which <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"14\" data-index-in-node=\"173\">(26) weren’t that essential (G: provided unnecessary detail)</strong></span>.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Jamie:</strong> You weren’t the only one.</p>\n<hr data-path-to-node=\"16\" />\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Jamie:</strong> Okay, I thought some aspects of the course organization were particularly helpful. Can we talk a bit about that?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Martha:</strong> Of course. Actually, I was disappointed that I couldn’t take any module whenever I wanted.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Jamie:</strong> That’s true, but <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"19\" data-index-in-node=\"24\">(27/28) the variety of modules on offer was a strong point (D)</strong></span> and meant I managed to cover a lot of subjects.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Martha:</strong> Me too, more than I expected. And I was pleased that the course organizers were able to <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"20\" data-index-in-node=\"96\">(27/28) provide modules focusing on real-life issues (E)</strong></span>, which we can apply later when looking for jobs.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Jamie:</strong> True, and I would have hated it if it had all been theory. What about the written paper we had to do for Doctor Brown? Are there any things we could suggest to improve the way that’s handled?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Martha:</strong> Well, choosing a topic right at the beginning of the module was difficult. <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"22\" data-index-in-node=\"83\">(29/30) Maybe he could postpone the decision until halfway through the term (A)</strong></span>.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Jamie:</strong> Good idea. I was happy with the word limit for the assignment, though. I wish I could have had a session with Doctor Brown after he’d marked my written paper.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Martha:</strong> I know it would be time-consuming, but it would have been really useful. Actually, I was satisfied with Doctor Brown’s written feedback. But <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"24\" data-index-in-node=\"149\">(29/30) I wish they could arrange sessions where students get together and help each other before submitting their written work (C)</strong></span>.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Jamie:</strong> Good idea. If they provided time for that, it would be quite convenient. Right, now that we’ve almost finished our course, it’s time to think about our career prospects…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('26619359-57ee-4ab8-9e40-6513a4949005', '68c8d11b-2a01-4c97-adb6-3bc0f470a4bb', 'matrix', 'Questions 20–23', '', '<p data-path-to-node="11">Write the correct letter, <strong data-path-to-node="11" data-index-in-node="176">A, B, C</strong> or <strong data-path-to-node="11" data-index-in-node="187">D</strong>, in boxes 20–23 on your answer sheet.</p>
<p data-path-to-node="12"><strong data-path-to-node="12" data-index-in-node="0">NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Researchers", "matrixItems": [{"itemText": "It is not clear why one small animal is moving from its natural environment.", "correctCategoryLetter": "D"}, {"itemText": "Hot weather might positively affect the health of a species.", "correctCategoryLetter": "A"}, {"itemText": "Sydney’s residential gardens suit some species better than others.", "correctCategoryLetter": "C"}, {"itemText": "Research into the natural world’s responses to urban settings is vital.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Dieter Hochuli", "categoryLetter": "A"}, {"categoryText": "John Martin", "categoryLetter": "B"}, {"categoryText": "Richard Major", "categoryLetter": "C"}, {"categoryText": "Catherine Price", "categoryLetter": "D"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">20. It is not clear why one small animal is moving from its natural environment. — {D. Catherine Price}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"21\">Catherine Price</strong>, a research associate… says: ‘<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"69\">We don’t know</strong> if it’s an overflow from the park, or if they’ve got particular survival traits…’”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “We don’t know” (Chúng tôi không biết) đồng nghĩa với “It is not clear” (Không rõ ràng). Catherine Price đang nói về loài <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"138\">bandicoot</strong> (small animal) và lý do tại sao chúng lại rời công viên để vào khu dân cư.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">21. Hot weather might positively affect the health of a species. — {A. Dieter Hochuli}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Professor Hochuli</strong> and his team are trying to understand why… the golden orb spiders in Sydney are <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"121\">fatter and fitter</strong> than species found elsewhere… whether it’s more food or the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"201\">urban heat</strong>…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Fatter and fitter” (béo hơn và khỏe hơn) tương ứng với “positively affect the health”. “Urban heat” (nhiệt độ đô thị – thường cao hơn 4 độ) tương ứng với “Hot weather”. Dieter Hochuli đang nghiên cứu xem liệu cái nóng có phải là lý do khiến nhện khỏe hơn không.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">22. Sydney’s residential gardens suit some species better than others. — {C. Richard Major}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Richard Major</strong> says: ‘The predominant driver in the decline of small birds is that <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"103\">we’ve made a suitable environment for native noisy miners</strong>.’”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Richard Major chỉ ra rằng cách làm vườn hiện nay (residential gardens) đã tạo ra một môi trường phù hợp (suitable environment) cho loài <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"148\">noisy miners</strong> nhưng lại khiến các loài chim nhỏ suy giảm (suit some species better than others).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">23. Research into the natural world’s responses to urban settings is vital. — {A. Dieter Hochuli}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">Associate Professor Dieter Hochuli</strong>… believes that ‘<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"74\">we need to understand</strong> how cities are changing the ecology…’”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “We need to understand” (Chúng ta cần phải hiểu) thể hiện tính chất quan trọng, cấp thiết (vital). “Urban settings” chính là môi trường thành phố (cities). Dieter Hochuli nhấn mạnh tầm quan trọng của việc nghiên cứu cách các loài thích nghi với đô thị.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('afaa4b1e-e19e-427b-80c4-d5719c04863b', '68c8d11b-2a01-4c97-adb6-3bc0f470a4bb', 'fillup', 'Questions 24–26', '<p data-path-to-node="17">Complete the summary below.</p>
<p data-path-to-node="17">Choose <strong data-path-to-node="17" data-index-in-node="35">ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-path-to-node="17">Write your answers in boxes 24–26 on your answer sheet.</p>
<p data-path-to-node="18"><span style="font-size: 14pt;"><strong data-path-to-node="18" data-index-in-node="0">Seeking comfort in city living</strong></span></p>
<p data-path-to-node="19">It’s not only native plants and animals that are adapting to city life; non-native plants and animals are also adapting. Examples of successful ‘city dwellers’ include small, non-native rats and non-native insects such as {cockroaches} However, what causes most problems in the city is weeds. Michelle Leishman, a scientist from Macquarie University, has proven that Sydney’s large areas of {concrete} and its drainage network favour the growth of weeds. Water gathers {chemicals} as it passes from gardens and streets into the city drainage network. This, in turn, creates very good soil for several varieties of rapidly growing non-native plants.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. cockroaches — {Examples… include small, non-native rats and non-native insects such as cockroaches}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Non-native species such as black <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"54\">rodents</strong>, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"63\">cockroaches</strong> and foxes have developed survival strategies too.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê các loài không bản địa (non-native) bao gồm loài gặm nhấm (rodents – tương ứng với “rats”) và gián (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"128\">cockroaches</strong>). Vì câu hỏi yêu cầu ví dụ về côn trùng (insects), từ chính xác cần điền là “cockroaches”.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. concrete — {Sydney’s large areas of concrete and its drainage network favour the growth of weeds.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…Leishman and her colleagues have shown how Sydney’s huge stretches of impermeable <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"106\">concrete</strong>, together with the storm-water system, have helped <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"166\">weeds</strong> infiltrate…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Michelle Leishman đã chứng minh rằng những dải bê tông (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"68\">concrete</strong>) không thấm nước cùng với hệ thống thoát nước mưa (storm-water system / drainage network) đã tạo điều kiện thuận lợi cho cỏ dại phát triển và xâm nhập.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. chemicals — {Water gathers chemicals as it passes from gardens and streets into the city drainage network.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“As rain washes over <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"41\">backyards and roadways</strong>, it collects <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"77\">chemicals</strong> which enter the storm-water system…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi nước mưa chảy qua các sân sau (gardens/backyards) và đường sá (roadways/streets), nó thu gom các loại hóa chất (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"128\">chemicals</strong>) trước khi đổ vào hệ thống thoát nước. Lượng nước giàu dưỡng chất và hóa chất này sau đó tạo môi trường lý tưởng cho các loài cây ngoại lai phát triển nhanh.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('8beb042b-593c-4930-a14d-55ddca82d282', '97c3e18c-6bbd-4aec-8e00-99b74cfd93a0', 'radio', 'Questions 20–23', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information,<strong>FALSE</strong> if the statement contradicts the information,<strong>NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The clay in the Manatuto project was initially unsuitable for the purpose of the project."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Coffee grounds produce filters that are twice as efficient as those using other organic materials."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It takes half an hour for a cow manure fire to reach 950 degrees."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "E. coli is the most difficult bacterium to remove from water by filtration"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">20. TRUE — {The clay in the Manatuto project was initially unsuitable for the purpose of the project.}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">“A charity operating there wanted to help set up a small industrial site manufacturing water filters, but <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"126\">initial research found the local clay to be too fine — a problem solved by the addition of organic material</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dự án ban đầu muốn dùng đất sét địa phương để làm bộ lọc, nhưng nghiên cứu ban đầu thấy đất sét này bị <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"115\">quá mịn (too fine)</strong> và đây là một <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"148\">vấn đề (problem)</strong> cần giải quyết bằng cách trộn thêm chất hữu cơ. Điều này đồng nghĩa với việc ban đầu (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"251\">initially</em>) loại đất sét này chưa phù hợp/chưa dùng ngay được (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"313\">unsuitable</strong>) cho mục đích của dự án.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">21. NOT GIVEN — {Coffee grounds produce filters that are twice as efficient as those using other organic materials.}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“According to Flynn, <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"41\">used coffee grounds have given the best results to date</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ khẳng định bã cà phê cho kết quả tốt nhất từ trước đến nay (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"84\">the best results</em>). Tuy nhiên, bài viết <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"123\">không hề đưa ra số liệu so sánh cụ thể</strong> xem nó hiệu quả gấp đôi (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"187\">twice as efficient</strong>) hay gấp mấy lần so với các nguyên liệu hữu cơ khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">22. FALSE — {It takes half an hour for a cow manure fire to reach 950 degrees.}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“...as the fuel <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"36\">can reach a temperature of 700 degrees in half an hour</strong>, and <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"96\">will be up to 950 degrees after another 20 to 30 minutes</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Theo bài đọc, đống lửa phân bò mất <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"47\">nửa tiếng (half an hour) để đạt 700 độ</strong>, và phải mất <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"99\">thêm 20 đến 30 phút nữa (another 20 to 30 minutes)</strong> thì mới lên được 950 độ. Câu hỏi nói chỉ mất nửa tiếng để đạt 950 độ là sai lệch mốc thời gian của bài (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"254\">FALSE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">23. NOT GIVEN — {E. coli is the most difficult bacterium to remove from water by filtration.}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“Tests with the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"36\">deadly E. coli bacterium</strong> have seen the filters remove 96.4 to 99.8 per cent of the pathogen...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến vi khuẩn E. coli là một loại vi khuẩn chết người (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"82\">deadly</em>) và bộ lọc có thể loại bỏ tới 99.8% loại khuẩn này. Tuy nhiên, bài đọc <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"160\">không hề có sự so sánh</strong> xem E. coli có phải là loại vi khuẩn cứng đầu/khó loại bỏ nhất (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"247\">the most difficult</strong>) bằng phương pháp lọc hay không.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('e4754351-341c-4e00-932d-8dc326f79a51', '97c3e18c-6bbd-4aec-8e00-99b74cfd93a0', 'radio', 'Questions 24—26', '', '<p><span class="fontstyle0">Choose the correct letter, </span><strong><span class="fontstyle2">A</span></strong><span class="fontstyle0">, </span><strong><span class="fontstyle2">B</span></strong><span class="fontstyle0">, </span><strong><span class="fontstyle2">C </span></strong><span class="fontstyle0">or </span><strong><span class="fontstyle2">D</span></strong><span class="fontstyle0">.</span></p>
<p><span class="fontstyle0">Write the correct letter in boxes 24–26 on your answer sheet.</span> </p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A charitable trust"}, {"option_text": "B filtration experiment."}, {"option_text": "C water filter factory."}, {"option_text": "D community kiln."}], "question": "The Manatuto project aimed to set up a"}, {"correct": 1, "options": [{"option_text": "A remove all dangerous pathogens"}, {"option_text": "B be a particular thickness"}, {"option_text": "C filter water as quickly as possible"}, {"option_text": "D be made from 100 per cent clay."}], "question": "To be effective, the Flynn filters must"}, {"correct": 0, "options": [{"option_text": "A wants it to be freely available"}, {"option_text": "B has produced a very simple design."}, {"option_text": "C cannot make a profit in poor countries."}, {"option_text": "D has already given the idea to a charity."}], "question": "Flynn does not intend to patent his filter because he"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. C. water filter factory. — {The Manatuto project aimed to set up a}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“A charity operating there wanted to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"57\">help set up a small industrial site manufacturing water filters</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dự án Manatuto hướng tới việc thiết lập một địa điểm công nghiệp quy mô nhỏ để sản xuất các bộ lọc nước (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"117\">industrial site manufacturing water filters</em>). Cụm từ này đồng nghĩa hoàn toàn với một nhà máy/xưởng sản xuất bộ lọc nước (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"239\">water filter factory</strong>).</p>\n<ul data-path-to-node=\"5,1,1\">\n<li>\n<p data-path-to-node=\"5,1,1,0,0\"><em data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"0\">Loại A:</em> Tổ chức từ thiện (<em data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"26\">charity</em>) là bên vận hành/thực hiện dự án chứ không phải là mục tiêu xây dựng của dự án.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,1,1,0\"><em data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"0\">Loại D:</em> Việc dùng lò nung (<em data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"27\">kiln</em>) chỉ là giải pháp kỹ thuật tạm thời chứ không phải đích đến ban đầu.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. B. be a particular thickness. — {To be effective, the Flynn filters must}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">The thickness of the clay container needs to be the same thickness as an adult finger for the process to be effective</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ rõ để quá trình lọc đạt hiệu quả (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"58\">for the process to be effective</em>), độ dày của thành bình bằng đất sét bắt buộc phải bằng đúng độ dày của một ngón tay người lớn. Ý này trùng khớp với việc bộ lọc phải có một độ dày cụ thể (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"246\">be a particular thickness</strong>).</p>\n<ul data-path-to-node=\"7,1,1\">\n<li>\n<p data-path-to-node=\"7,1,1,0,0\"><em data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"0\">Loại A:</em> Bộ lọc loại bỏ từ 96.4 đến 99.8% vi khuẩn E. coli (đưa về mức an toàn) chứ không loại bỏ hoàn toàn 100% (<em data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"113\">remove all</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,1,1,0\"><em data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"0\">Loại D:</em> Bộ lọc được làm từ hỗn hợp đất sét trộn vật liệu hữu cơ (bã trà, bã cà phê...) và nước chứ không phải 100% đất sét nguyên chất.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. A. wants it to be freely available. — {Flynn does not intend to patent his filter because he}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p id=\"p-rc_558861272e2e5dc1-20\" data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\"><span class=\"citation-68 citation-69\">Without a patent, there will be no illegality in it being adopted in any community that needs it. “Everyone has a right to clean water</span></strong><span class=\"citation-68 citation-69 citation-end-69\">, and these filters have the potential to enable anyone in the world to drink water<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span><span class=\"citation-68 citation-end-68\"> safely,” says Flynn.”<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span></em></p>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý do Flynn không đăng ký bản quyền thương mại (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"60\">patent</em>) cho sáng chế của mình là vì ông muốn bất kỳ cộng đồng nghèo nào cần đều có thể tự do sao chép và áp dụng một cách hợp pháp. Điều này thể hiện mong muốn sản phẩm được cung cấp và tiếp cận một cách miễn phí/rộng rãi cho tất cả mọi người (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"304\">wants it to be freely available</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('a147fd93-2fa8-4eeb-bed1-996875b1e29a', 'e58ca488-6cf2-4205-8f71-9988d592e3eb', 'checkbox', 'Questions 27–28', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>aspects of the course organisation did both Jamie and Martha like?</p>
', 'multiple_choice_many', 'null', '[{"option": "the amount of reading", "correct": false}, {"option": "the flexibility in the length of the course", "correct": false}, {"option": "the convenience of choosing when take modules", "correct": false}, {"option": "the range of different modules offered", "correct": true}, {"option": "the relevance of the module content", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ca1dedaa-928d-48eb-82d7-154ab54e35cb', 'e58ca488-6cf2-4205-8f71-9988d592e3eb', 'checkbox', 'Questions 29–30', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>suggestions for written assignment do Jamie and Martha agree to recommend to Dr Brown?</p>
', 'multiple_choice_many', 'null', '[{"option": "The time for choosing a topic should be changed.", "correct": true}, {"option": "The permitted word limit should be increased.", "correct": false}, {"option": "Discussions with fellow students should be arranged.", "correct": true}, {"option": "Face-to-face feedback sessions with the tutor should be scheduled.", "correct": false}, {"option": "Tutors should give more help in topic selection.", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('89359253-e120-4d3e-9d0e-7cf9d73bebdb', '9287e0ae-8cd9-4adc-88ad-f0580f784798', 'matching', 'Questions 25–30', '', '<p>What potential problem do the students identify for each of the following aspects of the work experience report?</p>
<p>Choose <strong>Six </strong>answers from the box and write the correct letter, A–H next to 25–30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Aspects of the work experience report</strong></p>\n<p> </p>\n<p>the use of a computer {not referencing other people’s material}</p>\n<p> </p>\n<p>the photos and diagrams {including irrelevant material}</p>\n<p> </p>\n<p>the formatting of the report {making it difficult for the tutor to correct}</p>\n<p> </p>\n<p>the section on staffing {not outlining the management organisation}</p>\n<p> </p>\n<p>the section on ‘Company Description’ {not relating the work experience to the course}</p>\n<p> </p>\n<p>the conclusion {being too critical}</p>", "answerOptions": [{"optionText": "being too critical"}, {"optionText": "not noticing errors in language"}, {"optionText": "making it difficult for the tutor to correct"}, {"optionText": "including irrelevant material"}, {"optionText": "not relating the work experience to the course"}, {"optionText": "omitting the official record"}, {"optionText": "not referencing other people’s material"}, {"optionText": "not outlining the management organisation"}], "matchingItems": []}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('93ce45a4-9e68-4ac9-bec8-c93c87fdc706', 'a1d5d15c-0c86-4ad5-b1ee-b182e9823044', 'fillup', 'Questions 31-40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 14pt;"><strong>The Early History of Salt</strong></span></p>
<p><strong>Introduction</strong></p>
<ul>
<li>
<p>Salt is essential for human {health} .</p>
</li>
</ul>
<p><strong>Ancient Rome</strong></p>
<ul>
<li>
<p>The word {salary} comes from the Latin word''s solarium argetum, which was used to describle the payment to Roman soldiers.</p>
</li>
</ul>
<p><strong>Ancient Sweden</strong></p>
<ul>
<li>
<p>Animals were kept in the local {forest} at the right time of year.</p>
</li>
<li>
<p>Fresh meat was only available in {October} .</p>
</li>
<li>
<p>Salt has been used widely: we can tell from the diet of the {king} in Sweden.</p>
</li>
<li>
<p>{beer} Consumption increased rapidly because the food was much too salty.</p>
</li>
</ul>
<p><strong>Salt source</strong></p>
<ul>
<li>
<p>People mainly extract salt from oceans and {deserts} in the basins.</p>
</li>
<li>
<p>Salt from spring water is more {concentrated} . And purer compared to that from sea water</p>
</li>
</ul>
<p><strong>Salt distribution</strong></p>
<ul>
<li>
<p>In ancient Sweden</p>
</li>
</ul>
<p>           -Locals needed to protect the {shipping} By which they imported salt.</p>
<ul>
<li>
<p>In other ancient countries</p>
</li>
</ul>
<p>           - People carrying salt around were seen as a natural means of {transport}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('9691e568-050b-47d6-a8f5-9499cf55e3b5', '2c286ffc-99b3-488f-a01c-49b2e1708edc', 'fillup', 'Questions 31- 40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Canadian Maple Syrup</strong></span></p>
<p><strong>Description</strong></p>
<ul>
<li>
<p>It is a sweet liquid poured over pancakes etc.</p>
</li>
<li>
<p>The production of sap needs a climate where night and day temperatures are very {different}</p>
</li>
</ul>
<p><strong>History</strong></p>
<ul>
<li>
<p>Folk stories claim that maple syrup was first used to cook {meat}</p>
</li>
<li>
<p>Sap collection in spring developed into a First Nations {tradition}</p>
</li>
<li>
<p>The sap was collected in buckets.</p>
</li>
<li>
<p>The sap was concentrated into syrup by:</p>
<ul>
<li>
<p>using hot stones to produce {steam}</p>
</li>
<li>
<p>leaving it outside at night and then removing the layer of {ice} on top.</p>
</li>
</ul>
</li>
</ul>
<p><strong>Uses</strong></p>
<ul>
<li>
<p>First Nations people drank the fresh sap to give them energy.</p>
</li>
<li>
<p>European settlers put the syrup in various types of {medicine}</p>
</li>
<li>
<p>They also used it for drinks and for candy.</p>
</li>
<li>
<p>Its use for making sugar declined after 1880, when the {tax} on Caribbean sugar was removed.</p>
</li>
</ul>
<p><strong>Threats</strong></p>
<p><strong>Natural</strong></p>
<ul>
<li>
<p>Harvests may be affected by storms and destructive {insects}</p>
</li>
<li>
<p>Climate change may also affect sap production.</p>
</li>
</ul>
<p><strong>Social</strong></p>
<ul>
<li>
<p>Maple syrup is expensive and faces considerable {competition}</p>
</li>
<li>
<p>The obesity issue is affecting sales.</p>
</li>
</ul>
<p><strong>Reasons for optimism</strong></p>
<ul>
<li>
<p>Maple syrup is an important export.</p>
</li>
<li>
<p>It is quite {healthy} compared with other sweeteners.</p>
</li>
<li>
<p>Its taste is the main reason for its popularity.</p>
</li>
</ul>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">PART 4: </strong></p>\n<p data-path-to-node=\"2\">Maple syrup can be described as very sweet. Canadians pour it generously over things like pancakes for breakfast. The syrup is produced from the maple tree, and it actually comes from the tree’s sap, which is the watery substance that comes out of the trunk of the tree when this is cut. In order for enough sap to be produced, very special climate conditions are needed in spring. The temperatures need to drop to well below zero at night, but then they need to rise sharply during the day. So they’re hugely<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"2\" data-index-in-node=\"503\">(31) different</strong></span> over a 24-hour period, and that’s exactly what happens in northeastern Canada every spring.</p>\n<p data-path-to-node=\"3\">The indigenous peoples of North America, known as the First Nations, discovered the maple secret long before the Europeans arrived. Early folk stories say it was first discovered by a chief who threw his tomahawk, which is similar to an axe, into the trunk of a tree. Clear sap started to run from the cut. His wife used this sap to boil <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"3\" data-index-in-node=\"338\">(32) meat</strong>,</span> and the heat turned it into a sweet syrup, which they found delicious.</p>\n<p data-path-to-node=\"4\">Whether or not that story is true, we do know that the maple tree was very important to <strong>First Nations</strong> peoples for hundreds of years. Collecting the sap each spring became a <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"173\">(33) tradition</strong></span> among them. Whole families would migrate to the areas where the maple trees grew and set up camp there.</p>\n<p data-path-to-node=\"5\">They collected the sap from the trees using buckets. Then they needed to concentrate the sap, removing some of the water from it to create syrup. They had two ways of doing this. One way was to drop hot stones from a fire into the buckets to create <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"249\">(34) steam</strong></span>. If repeated often enough, this would eventually concentrate the syrup. Another method that they used to concentrate the syrup was to leave the sap outside overnight, exposed to freezing temperatures. This would mean that a thick layer of<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"5\" data-index-in-node=\"499\">(35) ice</strong></span> would form on top, which could be discarded, leaving the sugary sap below. Again, this process could be repeated over several days and eventually a sweet brown syrup was produced.</p>\n<p data-path-to-node=\"6\">The First Nation’s people had various uses for the sap and syrup. They drank the sap fresh from the tree as a tonic, knowing that it was an important source of energy. But for the most part, they reduced the syrup further and then cooled it so that it crystallized into sugar. This was easy to carry and kept indefinitely</p>\n<p data-path-to-node=\"6\">European settlers who arrived in Canada began to learn about the syrup from First Nations peoples and further expanded its uses. For example, they incorporated it into <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"336\">(36) medicine</strong></span> of different kinds. They also discovered that by adding yeast to the sap, they could make a maple drink, and by throwing the hot syrup into the snow, they could make a toffee-like candy.</p>\n<p data-path-to-node=\"7\">But like the First Nations, they turned most of their sap into maple sugar. For most people, it was the only type of sugar they could afford, since the only alternative was the sugar imported from the Caribbean, which was made from sugar cane and this was very expensive. However, after 1880, the Canadian government decided to stop charging<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"7\" data-index-in-node=\"342\">(37) tax</strong></span> on Caribbean sugar, and this made it much cheaper. That meant it was no longer cost-effective to produce maple sugar, and so syrup making became the only viable industry remaining for Canadians, and that’s what we’ve been doing ever since.</p>\n<p data-path-to-node=\"8\">At present, maple syrup is enjoying a boom. However, serious threats remain. Like any agricultural product, the harvest is subject to such things as major storms or the arrival of invasive <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"189\">(38) insects</strong></span>, both of which have happened and these could destroy everything. It is predicted with some certainty that in the longer term, climate change will also have an adverse effect on the sap run.</p>\n<p data-path-to-node=\"9\">Then there are the social factors. Producing maple syrup is a very labor-intensive process, making it an expensive purchase, and of equal concern is the fact that nowadays there’s a lot of <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"189\">(39) competition</strong></span> from cheaper, artificially flavored brands. Furthermore, we’re at a time khi obesity is a major issue, making a product that is 67% sugar increasingly difficult to sell.</p>\n<p data-path-to-node=\"10\">Nevertheless, there are reasons to be optimistic. Producers are developing markets abroad. Our syrup is currently being exported to over 50 countries. Back here at home, chefs use it enthusiastically. It’s certainly high in calories, but it also contains proteins, minerals, and antioxidants. As such, it is still relatively <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"325\">(40) healthy</strong></span> when you compare it with sugar or corn syrup. Canadians are proud of maple syrup and its deep roots in our history and geography.</p>\n<p>However, the primary reason for maple syrup’s success around the world remains its taste.There’s nothing quite like it.</p>"}]', 0);
INSERT INTO public.questions VALUES ('21188f84-726a-4f12-abab-d6ae116bce0e', '804f2912-0ecf-4d07-a836-bb75583f0058', 'fillup', 'Questions 31–40', '<p>Complete the notes below..</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: left;"><span style="font-size: 14pt;"><strong>The Africa clawed frog (Xenopus laevis)</strong></span></p>
<p><strong>Description</strong></p>
<p>∙ Skin is {smooth} and can vary in colour</p>
<p>∙ Skin is coated with a slippery film for {protection}</p>
<p>∙ Males are {half} the size of females</p>
<p><strong>Habitats</strong></p>
<p>∙ Native to Africa</p>
<p>∙ Live in fresh water – prefered water that is {still}</p>
<p>∙ Can survive high levels of {salt} in water</p>
<p>∙ Cannot survive if there is any metal in water</p>
<p>∙ In drought conditions, may live in {mud} for up to a year</p>
<p><strong>Diet</strong></p>
<p>∙ Eat living or dead water creatures</p>
<p>∙ Find food using their sense of {smell}, their fingers, and their lateral lines</p>
<p>∙ Take food into their mouths using from legs and a {pump} system</p>
<p><strong>Other information</strong></p>
<p>∙ Now popular as a pet in the US</p>
<p>∙ In some US states they are identified as a {pest}</p>
<p>∙ Used in laboratories for developmental research</p>
<p>∙ Mucus from the skin was {antibiotic} properties</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('8c094752-c296-4c62-b4f6-e6203d13aa0c', 'bddbf0c8-07ea-4839-853a-0963e07a00ba', 'fillup', 'Questions 6-10', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong>General information about the holiday park and the Ohope area:</strong></p>
<ul>
<li>
<p>The children can play {tennis} for free.</p>
</li>
<li>
<p>It’s possible to hire equipment for {fishing} for an afternoon.</p>
</li>
<li>
<p>The children could visit the local {farm} on Saturday and Sunday.</p>
</li>
<li>
<p>There are guided tours of the {forest} every evening to see the birds.</p>
</li>
<li>
<p>Contact  {arataki} to confirm the booking</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('d73b5ec4-0cc1-424b-bd98-dbbd7b4f448c', '0883d372-432a-405b-bf16-fd4e22a0461e', 'radio', 'Questions 11–14', '', '<p>Choose the correct answers.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "employees did badly in the last annual fire drill."}, {"option_text": "there have been changes in the building layout."}, {"option_text": "new staff have joined the company."}], "question": "The company is having this meeting about fire procedures because"}, {"correct": 2, "options": [{"option_text": "the sprinkler system."}, {"option_text": "the fire extinguishers."}, {"option_text": "the alarm system."}], "question": "There has been a recent upgrade to"}, {"correct": 2, "options": [{"option_text": "were unable to read fire notices."}, {"option_text": "left fire doors open."}, {"option_text": "were unwilling to start the fire alarm."}], "question": "During the minor fire in January, some staff working in the factory"}, {"correct": 2, "options": [{"option_text": "refused to leave personal items behind."}, {"option_text": "moved too slowly during the evacuation."}, {"option_text": "did not move far away enough from the building."}], "question": "In the fire in January, the problem with office staff was that they"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 2: FIRE PROCEDURES AT WORK</strong></p>\n<p id=\"p-rc_8764aa6cd6260079-30\" data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong> <span class=\"citation-699 citation-end-699\">Hello and thanks to everyone for being on time. The meeting will be fairly short and we''ll only be looking at fire procedures. I had a similar meeting with the senior fire officers earlier today, but you''re all here because you''v<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>e <span class=\"citation-698 citation-end-698\">volunteered to act as fire wardens for your own particular department.<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-31\" data-path-to-node=\"4\"><span class=\"citation-697 citation-end-697\">And for some of you, this will be your first time in the role, although you''ll probably have taken part in several fire drills since you''ve been he<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span>re. <strong data-path-to-node=\"4\" data-index-in-node=\"151\"><span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\">(Q11) </span></span><span class=\"citation-695 citation-696\"><span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\">But now the construction work is finished and we have a couple of new corridors and stairways, we need the meeting to update everyone</span></span>.</span></strong><span class=\"citation-695 citation-696 citation-end-696\"><sup class=\"superscript\" data-turn-source-index=\"4\"><!----></sup></span><span class=\"citation-695 citation-end-695\"><sup class=\"superscript\" data-turn-source-index=\"5\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-32\" data-path-to-node=\"5\"><span class=\"citation-693 citation-694 citation-end-694\">And before I forget, you might have noticed a bit of upgrading last week. The handheld fire extinguishers, the standard ones on the wall, the report<sup class=\"superscript\" data-turn-source-index=\"6\"><!----></sup></span><span class=\"citation-693 citation-end-693\"> says they''re all working well, as is the overhead sprinkler system.<sup class=\"superscript\" data-turn-source-index=\"7\"><!----></sup></span> <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"217\">(Q12) <span class=\"citation-690 citation-691 citation-692\">But the old alarm system has been replaced and should be a lot more reliable.</span></strong></span><span class=\"citation-690 citation-691 citation-692 citation-end-692\"><sup class=\"superscript\" data-turn-source-index=\"8\"><!----></sup></span><span class=\"citation-690 citation-691 citation-end-691\"><sup class=\"superscript\" data-turn-source-index=\"9\"><!----></sup></span><span class=\"citation-690 citation-end-690\"><sup class=\"superscript\" data-turn-source-index=\"10\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-33\" data-path-to-node=\"6\"><span class=\"citation-687 citation-688 citation-689 citation-end-689\">Anyway, as fire wardens, you have a number of responsibilities. Okay, those wardens responsible for the factory buildings, you''ll remember we had a minor fir<sup class=\"superscript\" data-turn-source-index=\"11\"><!----></sup></span><span class=\"citation-687 citation-688 citation-end-688\">e back in January. Luckily the fire doors around the room stopped most of the smoke from getting out, but the alarm should have been pressed<sup class=\"superscript\" data-turn-source-index=\"12\"><!----></sup></span><span class=\"citation-687 citation-end-687\"> a lot earli<sup class=\"superscript\" data-turn-source-index=\"13\"><!----></sup></span>er. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"313\">(Q13) <span class=\"citation-685 citation-686\">From what I understand, staff felt somewhat reluctant to activate it themselves and were looking for someone senior</span></strong></span><span class=\"citation-685 citation-686 citation-end-686\">, so please ensure that everyone knows it''s their responsibility to take action immediately. Can you also make sure that if anyone new has been hired sinc<sup class=\"superscript\" data-turn-source-index=\"14\"><!----></sup></span><span class=\"citation-685 citation-end-685\">e then, that they''ve read the fire notices.<sup class=\"superscript\" data-turn-source-index=\"15\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-34\" data-path-to-node=\"7\"><span class=\"citation-684 citation-end-684\">And wardens for office departments, <sup class=\"superscript\" data-turn-source-index=\"16\"><!----></sup></span>you will also have to have a word with your staff. When the fire alarm went off in January in that minor fire, people got out of the office building pretty quickly. That was fine, but <strong data-path-to-node=\"7\" data-index-in-node=\"220\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q14) once they were out, they stood right in front of the doors, so if the fire crews had needed to access the offices, they would have been prevented</span>.</strong> Good to see that everyone had left their bags and stuff behind though.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<hr data-path-to-node=\"8\">\n<h3 data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">FIRE SAFETY ASPECTS (Questions 15–20)</strong></h3>\n<p id=\"p-rc_8764aa6cd6260079-35\" data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Manager:</strong> <span class=\"citation-683 citation-end-683\">Okay, next on the agenda, there''s a few aspects of fire safety that we need to go through with all you wardens.<sup class=\"superscript\" data-turn-source-index=\"17\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-36\" data-path-to-node=\"11\"><span class=\"citation-682 citation-end-682\">Firstly, we want to make sure that when we have the next fire drill, there''s nothing blocking the way in the escape routes—no obstacles I mea<sup class=\"superscript\" data-turn-source-index=\"18\"><!----></sup></span>n. <strong data-path-to-node=\"11\" data-index-in-node=\"144\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q15) So please have a look at that as soon as possible</span>.</strong> We want to be able to get outside very quickly.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-37\" data-path-to-node=\"12\"><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">(Q16) <span class=\"citation-680 citation-681\">One thing that should definitely be on your to-do list is making sure no one''s locked the fire doors and that it''s easy enough to get through them.</span></strong></span><span class=\"citation-680 citation-681 citation-end-681\"><sup class=\"superscript\" data-turn-source-index=\"19\"><!----></sup></span><span class=\"citation-680 citation-end-680\"><sup class=\"superscript\" data-turn-source-index=\"20\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-38\" data-path-to-node=\"13\"><span class=\"citation-678 citation-679 citation-end-679\">Now you might remember that last year we had a fire officer come and<sup class=\"superscript\" data-turn-source-index=\"21\"><!----></sup></span><span class=\"citation-678 citation-end-678\"> visit and show us what to do if we see a colleague starting to suffer from the effects of smoke inhalation. Well,<sup class=\"superscript\" data-turn-source-index=\"22\"><!----></sup></span> <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"183\">(Q17) the same officer is coming back to lead another session.</strong></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-39\" data-path-to-node=\"14\">Another issue is how to handle the fire extinguishers. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"55\">(Q18) <span class=\"citation-677\">Someone from the local fire department is booked in to teach people how to do that.</span></strong></span><span class=\"citation-677\"> I think it would be a good idea if fire wardens </span><span class=\"citation-676 citation-677 citation-end-677\">and department staff attended those sessions.<sup class=\"superscript\" data-turn-source-index=\"23\"><!----></sup></span><span class=\"citation-676 citation-end-676\"><sup class=\"superscript\" data-turn-source-index=\"24\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-40\" data-path-to-node=\"15\"><span class=\"citation-674 citation-675 citation-end-675\">Let''s see what else is on the list... Oh yes, the evacuation points: the<sup class=\"superscript\" data-turn-source-index=\"25\"><!----></sup></span> <span class=\"citation-673 citation-674 citation-end-674\">green area behind the main car park, the pavement on Hunter Street, and the unused area behind the factory car park. Fi<sup class=\"superscript\" data-turn-source-index=\"26\"><!----></sup></span><span class=\"citation-673 citation-end-673\">re wardens need to make sure all staff are familiar with these locations for evacuati<sup class=\"superscript\" data-turn-source-index=\"27\"><!----></sup></span>on. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"281\">(Q19) So please send out emails directly after the meeting.</strong></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"16\">And the last point is to do with flammable liquids. I believe there have been a few concerns about where they were being stored in the warehouse, but <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"150\">(Q20) that''s been resolved now.</strong></span> However, if anyone has anything else to report, do let me know.</p>"}]', 0);
INSERT INTO public.questions VALUES ('665640f1-67f5-4007-a23c-5f4a0bc25d4a', '0883d372-432a-405b-bf16-fd4e22a0461e', 'matrix', 'Questions 15–20', '', '<div class="quests-list">
<div id="2078" class="quests-item quests-numctn active" data-question-id="684" data-numctn="6" data-count="6" data-quest="6">
<div class="tt-head">
<p>What comment does the speaker make about each of the following aspects of fire safety?</p>
<p>Choose the correct letter, <strong>A</strong>, <strong>В</strong> or <strong>C</strong>, next to questions 15-20.</p>
</div>
</div>
</div>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "ensuring there are no obstacles in fire escape routes", "correctCategoryLetter": "A"}, {"itemText": " checking that fire doors are easily opened", "correctCategoryLetter": "A"}, {"itemText": "showing staff how to look after each other", "correctCategoryLetter": "B"}, {"itemText": "training staff to use fire extinguishers correctly", "correctCategoryLetter": "B"}, {"itemText": "checking that staff are aware of evacuation points", "correctCategoryLetter": "A"}, {"itemText": "checking that flammable liquids are properly stored", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "It should be a priority for fire wardens.", "categoryLetter": "A"}, {"categoryText": "It will be dealt with by an external specialist.", "categoryLetter": "B"}, {"categoryText": "It does not require attention.", "categoryLetter": "C"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('3e444eb2-4f09-42eb-82b4-536824d44936', '167699bc-1181-40cb-9d9a-00010be59b77', 'checkbox', 'Questions 21 and 22', '', '<p>What do the speakers agree are the two reasons why children play outdoors less now than in the past?</p>
<p>Choose <strong>TWO </strong>letters, A-E.</p>', 'list_selection', 'null', '[{"correct": true, "option_text": " A. Concerns about traffic"}, {"correct": false, "option_text": " B. Limited outdoor play facilities"}, {"correct": false, "option_text": " C. Increased time spent online"}, {"correct": false, "option_text": " D. Preference for indoor play"}, {"correct": true, "option_text": " E. Reduction in free time"}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: CHILDREN''S OUTDOOR PLAY RESEARCH</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Dr Chang:</strong> Right Robbie, tell me how the research for your assignment about children''s outdoor play is going.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Ravi:</strong> Yes, well, I''ve been reading about why children spend less time playing outside now than 20 or 30 years ago.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Dr Chang:</strong> So, is it just because of the amount of online time that children have now, which obviously happens indoors?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Ravi:</strong> Well, if that was the case, there''d be a correlation between high internet use and low levels of outdoor play. And it''s nothing to do with whether there are adequate facilities outside—playgrounds, for example—as any open space will do. <strong data-path-to-node=\"6\" data-index-in-node=\"243\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q21/22) There''s perhaps no single more important factor than parental worries about the dangers of vehicles on the streets</span>.</strong></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Dr Chang:</strong> But it could also be that children today prefer playing indoors to outdoors.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Ravi:</strong> Well, a study in Tokyo suggests it''s the other way around. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"65\">(Q21/22) But children are spending more time in structured activities and out-of-school clubs than before, and this has a knock-on effect on</strong></span></p>\n<p data-path-to-node=\"8\"><strong>Dr Chang:</strong><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong> W</strong><strong data-path-to-node=\"8\" data-index-in-node=\"65\">hat''s left for outdoor play.</strong></span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ravi:</strong> Right.</p>\n<p data-path-to-node=\"9\"><strong>Dr Chang: </strong>Your premise is that outdoor play is good. What exactly do you want to focus on in your assignment?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ravi:</strong> Well, not so much on things that apply to exercise in general, like children''s muscles getting stronger because they run around, and not on what seems, for instance, self-evident—that outdoor play helps children to concentrate on things other than lessons.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Dr Chang: </strong>Sure.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ravi: </strong> <strong data-path-to-node=\"10\" data-index-in-node=\"269\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23/24) I''d like to investigate some of the more unexpected benefits like to children''s digestion. This is because fresh air tends to stimulate hunger</span>.</strong>Perhaps leaving to one side the question of whether climbing trees helps educate children about the natural world?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Dr Chang:</strong> No, not really relevant. <strong data-path-to-node=\"12\" data-index-in-node=\"31\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23/24) What sort of decisions do outdoor games and activities force children to make?</span></strong></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Ravi:</strong> <strong data-path-to-node=\"12\" data-index-in-node=\"31\"><span style=\"text-decoration: underline; background-color: #f1c40f;\"> Well, for example, how they decide how dangerous something might be, and I''d like to outline the main findings on that</span>.</strong></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Dr Chang:</strong> Okay. And as you''re arguing that there''s been a shift in play patterns over the last generation or so, how are you going to substantiate this?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Ravi:</strong> Yes, surveys have compared parents'' recollections of their childhood play 30 years ago with what their children do now. And the nature of what children do when they are playing outdoors has changed.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Dr Chang:</strong> How exactly?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Ravi:</strong> Well, surprisingly, it''s not so much how often children play outside or preferences for large or small groups, <strong data-path-to-node=\"16\" data-index-in-node=\"117\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q25/26) but the fact that the play sessions don''t go on for as long</span>.</strong> And games involving one child running after another who tries to get away—these are still as popular as ever. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"297\">(Q25/26) But one thing that has declined is improvised games, and I''d like to examine why this might be.</strong></span></p>\n<p data-path-to-node=\"16\"><strong>Dr. Chang: </strong>Interesting. And what about safety?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"7\" data-index-in-node=\"2770\">Ravi:</strong> Well, from my reading, serious accidents are still rare. More kids hurt themselves falling out of bed than out of trees!</p>\n<hr data-path-to-node=\"17\">\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">FUTURE IMPLICATIONS (Questions 27–30)</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Ravi:</strong> I think the decline of outdoor play is a problem which should worry parents. I mean, perhaps the children themselves don''t miss it, they may be happy to spend lots of time indoors. <strong data-path-to-node=\"19\" data-index-in-node=\"187\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q27) But the links between inactivity and physical problems when they''re adults are so well established that I think kids should be encouraged to spend more time outdoors</span></strong><strong> </strong>with their brothers and sisters and friends.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Dr Chang:</strong> What about schools?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Ravi:</strong> Well, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"12\">(Q28) what I think they should do differently regarding outdoor play—and it wouldn''t actually require a great deal of expenditure—is base their policy on different outcomes, like developing children''s confidence, not just thinking about exam results</strong></span>, although I don''t know how it would go down with the parents.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Dr Chang:</strong> And do children get more contact with nature in rural areas?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Ravi:</strong> There''s research on this by Smith and Barker. Intuitively you''d expect children in rural areas to spend more time out in the open, but <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"141\">(Q29) in fact, they are generally told to keep off agricultural land, plus there are difficulties with supervision outside towns and cities.</strong></span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Dr Chang:</strong> Right. And Smith and Barker''s paper was published in</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Ravi: </strong>2001</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Dr Chang: </strong>Not the most up to date but still valid to use. But you''ll need to stipulate very precisely that their focus was, if I remember correctly, just on rural areas. <strong data-path-to-node=\"24\" data-index-in-node=\"228\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q30) So, you''d need to consider how far their restricted findings might be applicable to urban areas as well</span>.</strong></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Ravi: </strong>Okay.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Dr Chang: R</strong>ight. So now, I''d suggest you produce an overview of what you''re going to cover.</p>"}]', 0);
INSERT INTO public.questions VALUES ('ad1900ca-3917-4e95-97f9-1cfd5c2e66a3', '45eb14aa-3495-43c8-a788-fb342b5e068f', 'radio', 'Questions 27–30', '', '<p>Choose <strong data-start="154" data-end="161">YES</strong> – if the statement agrees with the claims of the writer, <strong data-start="220" data-end="226">NO</strong> – if the statement contradicts the claims of the writer, <strong data-start="285" data-end="298">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Human beings have a fixed supply of energy"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People tend to experience hunger at the end of an energy cycle"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Taking regular breaks is seen as inappropriate in the majority of organisations"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Negative emotions in the workplace can increase staff absences"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. NO</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“The problem with working longer hours is that time is a finite resource. However, energy is a different story. Energy comes from four main wellsprings... and in each area, energy can be systematically expanded.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định con người có một nguồn cung cấp năng lượng cố định (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"83\">fixed supply</em>). Tuy nhiên, bài đọc chỉ ra rằng thời gian mới là tài nguyên hữu hạn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"166\">finite resource</em>), còn năng lượng thì ngược lại (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"214\">a different story</em>) vì nó có thể được mở rộng một cách có hệ thống (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"281\">systematically expanded</strong>). Vì thông tin mâu thuẫn trực tiếp nên đáp án là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"354\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“Toward the end of each cycle, our systems crave recovery. The signals include restlessness and difficulty concentrating, but we often ignore them and keep working.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về dấu hiệu khi cơ thể rơi vào cuối chu kỳ năng lượng là thèm sự phục hồi (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"102\">crave recovery</em>), biểu hiện qua sự bồn chồn (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"146\">restlessness</em>) và khó tập trung (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"178\">difficulty concentrating</em>). Bài viết <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"214\">hoàn toàn không đề cập</strong> đến việc con người có xu hướng cảm thấy đói bụng (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"287\">experience hunger</em>) vào thời điểm này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. YES</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“While having breaks every hour or so goes against the culture of most organizations, their value is multifaceted.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói việc nghỉ giải lao thường xuyên bị xem là không phù hợp/không đúng mực ở phần lớn các tổ chức (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"119\">seen as inappropriate in the majority of organisations</em>). Điều này trùng khớp hoàn toàn với thông tin trong bài: việc nghỉ ngơi mỗi giờ hoặc mớ tương tự là đi ngược lại với văn hóa của hầu hết các tổ chức (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"324\">goes against the culture of most organizations</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“This drains energy, causes friction between workers and makes it impossible to think clearly.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn có nêu tác hại của cảm xúc tiêu cực nơi công sở là làm cạn kiệt năng lượng, gây xích mích giữa các đồng nghiệp (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"133\">causes friction between workers</em>) và không thể suy nghĩ thấu đáo. Tuy nhiên, việc những cảm xúc tiêu cực này có làm gia tăng tỷ lệ nghỉ việc hay vắng mặt của nhân viên (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"301\">increase staff absences</em>) hay không thì <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"340\">không được nhắc tới</strong> trong bài.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e85181d7-8cb6-4639-a7d5-2bb0e5a74f84', 'b7e3acee-8466-4ed7-b2dc-23efde324a30', 'radio', 'Questions 21–25', '', '<p>Choose the correct letter, <strong data-path-to-node="18" data-index-in-node="27">A</strong>, <strong data-path-to-node="18" data-index-in-node="30">B</strong> or <strong data-path-to-node="18" data-index-in-node="35">C</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A   common sense."}, {"option_text": "B   hard to follow."}, {"option_text": "C   over-protective."}], "question": "Kieran thinks the packing advice given by Jane''s grandfather is"}, {"correct": 2, "options": [{"option_text": "A   They are not worth keeping."}, {"option_text": "B   They should go to a collector."}, {"option_text": "C   They have sentimental value for her."}], "question": "How does Jane feel about the books her grandfather has given her?"}, {"correct": 0, "options": [{"option_text": "A   put out on display."}, {"option_text": "B   given as gifts to visitors."}, {"option_text": "C   more attractively designed."}], "question": "Jane and Kieran agree that hardback books should be"}, {"correct": 1, "options": [{"option_text": "A   describes the mistakes other people make doing it."}, {"option_text": "B   reflects on a significant childhood experience."}, {"option_text": "C   explains why some books are easier to remove than others."}], "question": "While talking about taking a book from a shelf, Jane"}, {"correct": 2, "options": [{"option_text": "A   Their parents liked buying them as presents."}, {"option_text": "B   They would like to buy more of them."}, {"option_text": "C   Not everyone can afford them."}], "question": "What do Jane and Kieran suggest about new books?"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('44252b26-4bd0-4669-a5e1-f5391befd58c', 'b7e3acee-8466-4ed7-b2dc-23efde324a30', 'matching', 'Questions 26–30', '', '<p>Choose <strong data-path-to-node="5" data-index-in-node="7">FIVE</strong> answers from the box and write the correct letter, <strong data-path-to-node="5" data-index-in-node="63">A–G</strong>, next to Questions 26–30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>rare books {D   on a high shelf}</p>\n<p> </p>\n<p>children''s books {F   in a specially designed space}</p>\n<p> </p>\n<p>unwanted books {A   near the entrance}</p>\n<p> </p>\n<p>requested books {C   at the back of the shop}</p>\n<p> </p>\n<p>coursebooks {G   within the café}</p>", "answerOptions": [{"optionText": "A   near the entrance"}, {"optionText": "B   in the attic"}, {"optionText": "C   at the back of the shop"}, {"optionText": "D   on a high shelf"}, {"optionText": "E   near the stairs"}, {"optionText": "F   in a specially designed space"}, {"optionText": "G   within the café"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('cec5466c-c9bf-43b0-8309-232558cf6273', '804b78c1-1f7c-4890-8ab4-2114dd5f838e', 'fillup', 'Questions 31–40', '<p data-path-to-node="12">Complete the notes below.</p>
<p data-path-to-node="13">Write <strong data-path-to-node="13" data-index-in-node="6">ONE WORD ONLY</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: left;" data-path-to-node="14,0"><span style="font-size: 14pt;"><strong data-path-to-node="14,0" data-index-in-node="0">Tree planting</strong></span></p>
<p data-path-to-node="14,1"><strong data-path-to-node="14,1" data-index-in-node="0">Reforestation projects should:</strong></p>
<ul data-path-to-node="14,2">
<li>
<p><span class="citation-70432 citation-70433 citation-70434 citation-end-70434">include a range of tree species<sup class="superscript" data-turn-source-index="1"><!----></sup></span><span class="citation-70432 citation-70433 citation-end-70433"><sup class="superscript" data-turn-source-index="2"><!----></sup></span><span class="citation-70432 citation-end-70432"><sup class="superscript" data-turn-source-index="3"><!----></sup></span><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p><span class="citation-70429 citation-70430 citation-70431">not include invasive species because of possible {competition}</span><span class="citation-70429 citation-70430 citation-70431 citation-end-70431"> with native species<sup class="superscript" data-turn-source-index="4"><!----></sup></span><span class="citation-70429 citation-70430 citation-end-70430"><sup class="superscript" data-turn-source-index="5"><!----></sup></span><span class="citation-70429 citation-end-70429"><sup class="superscript" data-turn-source-index="6"><!----></sup></span><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p><span class="citation-70426 citation-70427 citation-70428">aim to capture carbon, protect the environment and provide sustainable sources of {food}</span><span class="citation-70426 citation-70427 citation-70428 citation-end-70428"> for local people<sup class="superscript" data-turn-source-index="7"><!----></sup></span><span class="citation-70426 citation-70427 citation-end-70427"><sup class="superscript" data-turn-source-index="8"><!----></sup></span><span class="citation-70426 citation-end-70426"><sup class="superscript" data-turn-source-index="9"><!----></sup></span><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p><span class="citation-70423 citation-70424 citation-70425 citation-end-70425">use tree se<sup class="superscript" data-turn-source-index="10"><!----></sup></span><span class="citation-70423 citation-70424">eds with a high genetic diversity to increase resistance to {disease}</span><span class="citation-70423 citation-70424 citation-end-70424"> and climate change<sup class="superscript" data-turn-source-index="11"><!----></sup></span><span class="citation-70423 citation-end-70423"><sup class="superscript" data-turn-source-index="12"><!----></sup></span><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p><span class="citation-70421 citation-70422 citation-end-70422">plan<sup class="superscript" data-turn-source-index="13"><!----></sup></span><span class="citation-70421 citation-end-70421">t trees on previously forested land which is in a bad condition, not select land which is being used f<sup class="superscript" data-turn-source-index="14"><!----></sup></span>or {agriculture} .<!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
<p><strong data-path-to-node="14,3" data-index-in-node="0">Large-scale reforestation projects</strong></p>
<ul data-path-to-node="14,4">
<li>
<p>Base planning decisions on information from accurate {maps} .</p>
</li>
<li>
<p>Drones are useful for identifying areas in Brazil which are endangered by keeping {cattle} and illegal logging.</p>
</li>
</ul>
<p><strong data-path-to-node="14,5" data-index-in-node="0">Lampang Province, Northern Thailand</strong></p>
<ul data-path-to-node="14,6">
<li>
<p>A forest was restored in an area damaged by mining.</p>
</li>
<li>
<p>A variety of native fig trees were planted, which are important for</p>
<ul data-path-to-node="14,6,1,1">
<li>
<p>supporting many wildlife species</p>
</li>
<li>
<p>increasing the {speed} of recovery by attracting animals and birds, e.g., {monkeys} were soon attracted to the area.</p>
</li>
</ul>
</li>
</ul>
<p><strong data-path-to-node="14,7" data-index-in-node="0">Involving local communities</strong></p>
<ul data-path-to-node="14,8">
<li>
<p>Destruction of mangrove forests in Madagascar made it difficult for people to make a living from {fishing} .</p>
</li>
<li>
<p>The mangrove reforestation project:</p>
<ul data-path-to-node="14,8,1,1">
<li>
<p>provided employment for local people</p>
</li>
<li>
<p>restored a healthy ecosystem</p>
</li>
<li>
<p>protects against the higher risk of {flooding} .</p>
</li>
</ul>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="13"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('fb8867ca-1f87-41c5-a3e1-3f4211d0f396', '167699bc-1181-40cb-9d9a-00010be59b77', 'checkbox', 'Questions 25 and 26', '', '<p>According to Ravi, in which <strong>TWO </strong>ways are children’s periods of outdoor play now different from a generation ago?</p>
<p>Choose <strong>TWO</strong> letters, <strong>A-E.</strong></p>', 'list_selection', 'null', '[{"correct": false, "option_text": "A. They are less dangerous."}, {"correct": false, "option_text": "B. They involve fewer children."}, {"correct": true, "option_text": "C. They usually last a shorter time."}, {"correct": true, "option_text": "D. They include fewer made-up games."}, {"correct": false, "option_text": "E. They involve fewer chasing games."}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('91e6711a-a9ce-4839-836f-7e545e8c59a6', '167699bc-1181-40cb-9d9a-00010be59b77', 'radio', 'Questions 27 - 30', '', '<p>Choose the correct answers</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. It affects family relationships."}, {"option_text": "B. It leads to health problems later in life."}, {"option_text": "C. It makes childhood less enjoyable."}], "question": "Ravi thinks parents should be more concerned about the decline of outdoor play because"}, {"correct": 0, "options": [{"option_text": "A. Revise their aims."}, {"option_text": "B. Spend more money on it."}, {"option_text": "C. Listen to the views of parents."}], "question": "What does Ravi say that schools should do with regard to outdoor play?"}, {"correct": 0, "options": [{"option_text": "A. They tend not to be allowed on farmland."}, {"option_text": "B. They receive more supervision outdoors."}, {"option_text": "C. They spend more time outdoors than city children."}], "question": "What did Smith and Barker say about children in rural areas?"}, {"correct": 2, "options": [{"option_text": "A. Its findings are inconclusive."}, {"option_text": "B. It is too old to be useful."}, {"option_text": "C. Its focus is limited. "}], "question": " What problem does Dr Chang highlight about Smith and Barker’s research?"}]', 'null', 'null', 'null', 'null', 3);
INSERT INTO public.questions VALUES ('eae66c47-e4ef-48b5-b96f-2ad292b460aa', 'c61be127-708d-4db2-8509-27f457f43a59', 'fillup', 'Questions 31-40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<div id="model-response-message-contentr_23aadb103e869a14" class="markdown markdown-main-panel enable-updated-hr-color" dir="ltr" aria-live="polite" aria-busy="false">
<p data-path-to-node="2"><span style="font-size: 14pt;"><strong data-path-to-node="2" data-index-in-node="0">Human Memory</strong></span></p>
<p data-path-to-node="3"><strong data-path-to-node="3" data-index-in-node="0">Early Cultures</strong></p>
<ul>
<li data-path-to-node="4">
<p>Before 3000 BC, people were unable to {write}, so they relied on memory.</p>
</li>
<li data-path-to-node="5">
<p>Memory helped with navigation and family history.</p>
</li>
<li data-path-to-node="6">
<p>People used memory to identify dangerous foods, such as some types of {plants}.</p>
</li>
</ul>
<p data-path-to-node="7"><strong data-path-to-node="7" data-index-in-node="0">Ancient Greeks</strong></p>
<ul>
<li data-path-to-node="8">
<p>Simonides believed that memories linked to a {place} are easier to recall.</p>
</li>
<li data-path-to-node="9">
<p>In the 1st century, Greeks believed the senses, especially {sight}, could help memory.</p>
</li>
</ul>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">Ancient Romans</strong></p>
<ul>
<li data-path-to-node="11">
<p>Making a good {speech} depended on memory.</p>
</li>
<li data-path-to-node="12">
<p>From 100 BC, they developed techniques to improve memory. Cicero believed people have a memory that can be developed, in addition to their {natural} memory.</p>
</li>
</ul>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">Later European History</strong></p>
<ul>
<li data-path-to-node="14">
<p>Scholastics used earlier memory techniques to teach {religion}.</p>
</li>
<li data-path-to-node="15">
<p>In the 17th century, people believed {science} could provide explanations.</p>
</li>
<li data-path-to-node="16">
<p>In the 19th century, schoolchildren learned facts, such as {dates}, using repetition.</p>
</li>
</ul>
<p data-path-to-node="17"><strong data-path-to-node="17" data-index-in-node="0">Modern Times</strong></p>
<ul>
<li data-path-to-node="18">
<p>In the 1940s, important research on ‘S,’ who worked as a {journalist}, but people started to rely on computers.</p>
</li>
</ul>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4: THE HISTORY OF HUMAN MEMORY</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Good morning everyone. In today''s psychology lecture, I''ll be talking about human memory, and what I want to do first is establish the historical context. So I''ll outline various ideas about human memory and how they''ve changed over time.</p>\n<p data-path-to-node=\"4\">So first, early cultures. Now in the earliest times, let''s say before 3,000 years BC, people were dependent on being able to remember things, perhaps even more than we are today. That''s because <span style=\"background-color: #ffffff;\">humans could not </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"194\">(Q31) write</strong></span>; the skill hadn''t been developed, so a good memory was important. For one thing, it helped people navigate in the area around their homes, and it was the only way to access family history and ancestry. What''s more, a good memory might be the difference between life and death. Most people were hunters and gatherers, so it was essential to understand which foods were poisonous and which were not. <span style=\"background-color: #ffffff;\"> This was particularly true of </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"621\">(Q32) plants</strong></span>, because they sometimes looked very similar, and the only way to store this information and pass it on to the next generation was to remember it. Unfortunately, because it was so long ago, there''s limited information about what techniques we used to assist memory.</p>\n<p data-path-to-node=\"5\">Okay, so moving on now to the ancient Greeks. And the Greek poet named Simonides, who lived around 500 BC, was the man sometimes described as the father of memory training. Simonides''s most important idea was that <span style=\"background-color: #ffffff;\"><strong data-path-to-node=\"5\" data-index-in-node=\"214\"> </strong>it''s much easier to remember information if we connect it with one particular<strong data-path-to-node=\"5\" data-index-in-node=\"214\"> </strong></span><strong data-path-to-node=\"5\" data-index-in-node=\"214\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q33) place</span>.</strong> Then over hundreds of years, other Greek scholars developed his ideas about memory, and a lot of this information has survived. So we know that by the 1st century, the Greeks believed that people could use their human senses to improve their memory, and <span style=\"background-color: #ffffff;\"> this was particularly true when it came to</span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"559\"> (Q34) sight</strong></span>; there was a strong connection there, they believed.</p>\n<p data-path-to-node=\"6\">Well next, I should talk about the ancient Romans who, like the Greeks, believed memory training was extremely important. They used memory in many different ways obviously, but most of all in ancient Rome, people thought that <span style=\"background-color: #f1c40f;\"><span style=\"background-color: #ffffff;\">one of the greatest skills was the ability to give an impressive </span></span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"226\">(Q35) speech</strong></span><span style=\"background-color: #ffffff;\"> in public</span>, and memory was one of the keys to doing that. So this was why from about 100 BC, the Romans wanted to develop techniques to improve memory, and an important figure here was Cicero, a Roman political leader. One of Cicero''s ideas was that humans actually have two types of memory: there''s a memory that can be developed, which he called the artificial memory, a<span style=\"background-color: #ffffff;\">nd  there''s another type of memory which he called <span style=\"background-color: #f1c40f;\"><strong>(Q36) natural</strong></span>. </span>And the point is that you can learn techniques to help improve your artificial memory, an idea that''s interested some academics ever since.</p>\n<p data-path-to-node=\"7\">So moving next to later European history. And the first thing to note is that during the Middle Ages, a group of academics called the scholastics were also interested in memory techniques. The scholastics used these techniques <span style=\"background-color: #ffffff;\">when they were instructing pupils about </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"227\">(Q37) religion</strong></span>, and this raised the profile of memory techniques.</p>\n<p data-path-to-node=\"8\">But later, attitudes towards memory began to change, and this started in the 17th century. People began to see memory training as an art form, and that didn''t interest them so much anymore<strong> </strong><span style=\"background-color: #ffffff;\">because they thought that </span><strong data-path-to-node=\"8\" data-index-in-node=\"189\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q38) science</span></strong><span style=\"background-color: #ffffff;\"> had the answers to most human questions</span><strong data-path-to-node=\"8\" data-index-in-node=\"189\">.</strong> This attitude really continued into the 19th century as well. Children weren''t taught memory techniques but were expected to learn lots of facts and to do this by constantly repeating things <span style=\"background-color: #ffffff;\"><strong data-path-to-node=\"8\" data-index-in-node=\"461\">like </strong></span><strong data-path-to-node=\"8\" data-index-in-node=\"461\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q39) dates</span></strong><span style=\"background-color: #ffffff;\"> and so on</span><strong data-path-to-node=\"8\" data-index-in-node=\"461\">.</strong></p>\n<p data-path-to-node=\"9\">Okay, so then we come to modern times. And in the 1940s, a remarkable series of studies was conducted with a man known simply as S. <span style=\"background-color: #ffffff;\">Psychologists found that S never made notes about anything, although he was a</span><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"132\"> </strong></span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"132\">(Q40) journalist</strong></span>, and never forgot facts. The researchers concluded that S had an unusual medical condition which meant he developed incredible memory skills. This was important as it seemed to support the ideas of the ancient Greeks and other much earlier scholars. But in the later part of the 20th century, the focus switched to computers.</p>\n<p data-path-to-node=\"10\">Okay well, that''s the historical context. Let''s now turn to...</p>"}]', 0);
