INSERT INTO public.questions VALUES ('661ee60e-5a53-47b9-b395-5985e11c782e', '55fa7f02-7d20-4cda-afe8-fa63f4135406', 'radio', 'Questions 27-31', '', '<p>Choose the correct letter, A, B, C or D.</p>
<p>Write the correct letter</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. It started earlier than previously thought"}, {"option_text": "B. Historians have overlooked its importance"}, {"option_text": "C. It impacts on research into the wider region"}, {"option_text": "D. Researchers have calculated its effects on the environment"}], "question": "In the first paragraph, what is the writer’s main point about migration to Patagonia?"}, {"correct": 2, "options": [{"option_text": "A. to challenge previous research"}, {"option_text": "B. to propose new areas to investigate"}, {"option_text": "C. to summarise a scholarly debate"}, {"option_text": "D. to suggest reasons for human migration"}], "question": "In the second paragraph, what is the writer’s purpose?"}, {"correct": 0, "options": [{"option_text": "A. compare it with another theory of migration"}, {"option_text": "B. evaluate the success of American migration"}, {"option_text": "C. criticise the speed of research into migration"}, {"option_text": "D. compare migration in different parts of the world"}], "question": "The writer refers to the ‘late’ model in order to"}, {"correct": 3, "options": [{"option_text": "A. Scholars support the idea of fast migrations"}, {"option_text": "B. It is too random to be a convincing theory"}, {"option_text": "C. South America was more habitable at an earlier time"}, {"option_text": "D. It is more consistent with the physical conditions of the land"}], "question": "What is the writer’s main point about the ‘early’ model?"}, {"correct": 1, "options": [{"option_text": "A. It is much younger than researchers once estimated"}, {"option_text": "B. It provides supporting evidence for relatively early settlement"}, {"option_text": "C. Archaeologists believe the site is of questionable value"}, {"option_text": "D. Streams exposed the site, making new research possible"}], "question": "What does the writer suggest about the Monte Verde site?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. In the first paragraph, what is the writer’s main point about migration to Patagonia? — {C. It impacts on research into the wider region.}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"11\">“…it gives a baseline that all calculations regarding the rate of dispersion of humans throughout both continents must take into account.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc cho thấy việc con người đến Patagonia giúp thiết lập một mốc cơ sở quan trọng. Mốc này ảnh hưởng đến mọi tính toán về sự phân bổ con người trên toàn bộ hai lục địa (toàn châu Mỹ) → Đây là tầm ảnh hưởng đến nghiên cứu khu vực rộng lớn hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. In the second paragraph, what is the writer’s purpose? — {C. to summarise a scholarly debate}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“Some scholars accepted… 20,000 years ago, while others proposed… no earlier than 8,000 years ago…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra hai luồng quan điểm trái ngược nhau về thời gian di cư. Việc liệt kê các ý kiến đối lập này chính là tóm tắt một cuộc tranh luận học thuật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. The writer refers to the ‘late’ model in order to — {A. compare it with another theory of migration.}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“…many scholars now support the idea of an ‘early’ model…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra khái niệm “late model” để làm tiền đề đối chiếu và so sánh với “early model” (giả thuyết đang chiếm ưu thế hơn trong giới nghiên cứu hiện nay).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What is the writer’s main point about the ‘early’ model? — {D. It is more consistent with the physical conditions of the land.}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“…migrants slowly adapted to the diverse natural habitats…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô hình “early” mô tả quá trình di cư diễn ra chậm rãi, cho phép con người thích nghi dần với các môi trường sống khác nhau. Điều này phù hợp với thực tế địa lý và điều kiện tự nhiên hơn là việc di chuyển quá nhanh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. What does the writer suggest about the Monte Verde site? — {B. It provides supporting evidence for relatively early settlement.}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“…dated to around 12,500 years ago… casts doubt on the ‘late’ model.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Niên đại 12,500 năm của Monte Verde là một mốc thời gian sớm. Nó trực tiếp gây nghi ngờ cho mô hình “muộn” (late model), từ đó ủng hộ cho lý thuyết định cư sớm.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('35936bcc-9a5b-445b-8824-7f0e9c4e9c50', '55fa7f02-7d20-4cda-afe8-fa63f4135406', 'radio', 'Questions 32-35', '', '<p>Choose <strong data-path-to-node="11,0,0" data-index-in-node="0">YES</strong>: if the statement agrees with the information,<strong data-path-to-node="11,1,0" data-index-in-node="0">NO</strong>: if the statement contradicts the information,<strong data-path-to-node="11,2,0" data-index-in-node="0">NOT <span class="citation-1745 citation-1746">GIVEN</span></strong><span class="citation-1745 citation-1746 citation-end-1746">: if there is no information on this</span></p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "Yes"}, {"option_text": "No"}, {"option_text": "Not Given"}], "question": "The conditions encountered by the first migrants to Patagonia were unique"}, {"correct": 2, "options": [{"option_text": "Yes"}, {"option_text": "No"}, {"option_text": "Not Given"}], "question": "In the high country the first migrants hunted wild animals for food"}, {"correct": 1, "options": [{"option_text": "Yes"}, {"option_text": "No"}, {"option_text": "Not Given"}], "question": "Archaeologists have failed to draw conclusions from the evidence found at rock shelters in Argentina and Chile"}, {"correct": 0, "options": [{"option_text": "Yes"}, {"option_text": "No"}, {"option_text": "Not Given"}], "question": "Archaeological evidence can be moved from place to place in a variety of ways"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. The conditions encountered by the first migrants to Patagonia were unique. — {NO}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">“…similar to that of early post-glacial Europe.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc mô tả điều kiện ở đây “tương tự” (similar) với châu Âu thời kỳ sau băng hà. Vì có sự tương đồng nên không thể coi là “độc nhất” (unique).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. In the high country the first migrants hunted wild animals for food. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Không có thông tin trực tiếp về hoạt động săn bắn tại khu vực này.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài có nhắc đến con người và động vật, nhưng không có câu nào khẳng định mục đích của việc săn bắn tại “high country” là để lấy thức ăn. Dữ kiện không đủ để kết luận.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Archaeologists have failed to draw conclusions from the evidence found at rock shelters in Argentina and Chile. — {NO}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"11\">“…reliable evidence… to confirm the presence of humans…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định các nhà khảo cổ đã tìm thấy bằng chứng đáng tin cậy để xác nhận sự hiện diện của con người. Do đó, việc nói họ “thất bại” (failed) trong việc rút ra kết luận là sai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. Archaeological evidence can be moved from place to place in a variety of ways. — {YES}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"11\">“…bones… may be deposited… by floods or predators…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các hiện vật (như xương) có thể bị di chuyển và tích tụ ở nơi khác do lũ lụt hoặc các loài thú ăn thịt. Điều này đúng với nhận định bằng chứng có thể bị thay đổi vị trí bởi các tác nhân tự nhiên.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b3441abe-712c-49c9-9f66-7da7f1bc6b9f', '55fa7f02-7d20-4cda-afe8-fa63f4135406', 'matching', 'Questions 36-40', '', '<p>Complete the summary using the list of words and phrases, <strong>A</strong>–<strong>J </strong>below.</p>
<p>Write the correct letter</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\" data-start=\"2487\" data-end=\"2533\"><span style=\"font-size: 12pt;\"><strong data-start=\"2487\" data-end=\"2533\">The archaeological evidence from Patagonia</strong></span></p>\n<p data-start=\"2535\" data-end=\"3432\">Building remains and other evidence have been found in {D. good condition} at the Chinchihuapi Creek site, and because of this it has been possible to date them to around 12,500 years ago. However, the {B. random collection} of the samples taken from Los Toldos means that this site is of doubtful value. El Ceibo is a more promising dig, where the examination of artefacts would be beneficial in order to confirm the usefulness of discoveries there. The remains found at the Arroyo Feo site show {C. similar properties} and date from around 9,000 years ago. Unfortunately no {H. reliable connection} can be made between the samples taken from Las Buitreras and human presence. The findings of the work carried out at Cueva Fell cannot provide useful information beyond the {J. immediate surroundings}. In conclusion, though the evidence is mixed, it is believed that human population of Patagonia began about 11,000 years ago.</p>", "answerOptions": [{"optionText": "A. fixed date"}, {"optionText": "B. random collection"}, {"optionText": "C. similar properties"}, {"optionText": "D. good condition"}, {"optionText": "E. scientific evaluation"}, {"optionText": "F. huge quantities"}, {"optionText": "G. new samples"}, {"optionText": "H. reliable connection"}, {"optionText": "I. skilled preservation"}, {"optionText": "J. immediate surroundings"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. Building remains… have been found in {D. good condition} at the Chinchihuapi Creek site…</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"26,0,0\" data-index-in-node=\"11\">“…peat… preserving wood remarkably well…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lớp than bùn (peat) giúp bảo quản gỗ cực kỳ tốt, tương ứng với tình trạng tốt (good condition).</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. However, the {B. random collection} of the samples taken from Los Toldos means…</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"28,0,0\" data-index-in-node=\"11\">“…taken unsystematically…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc lấy mẫu “không có hệ thống” đồng nghĩa với một sự thu thập ngẫu nhiên (random collection).</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. The remains found at the Arroyo Feo site show {C. similar properties} and date from around 9,000 years ago.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"30,0,0\" data-index-in-node=\"11\">“…same depth and… same origins…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các mẫu vật được tìm thấy có cùng độ sâu và nguồn gốc, cho thấy chúng có các đặc tính/tính chất tương đồng nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. Unfortunately no {H. reliable connection} can be made between the samples taken from Las Buitreras and human presence.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"32,0,0\" data-index-in-node=\"11\">“…no way of securely relating…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “không có cách nào liên hệ một cách chắc chắn” tương ứng với việc không có sự kết nối đáng tin cậy (reliable connection).</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. The findings… at Cueva Fell cannot provide useful information beyond the {J. immediate surroundings}.</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"34,0,0\" data-index-in-node=\"11\">“…must be restricted to its direct vicinity…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Direct vicinity” (khu vực lân cận trực tiếp) đồng nghĩa với “immediate surroundings”. Thông tin chỉ có giá trị trong phạm vi hẹp quanh di chỉ đó.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('8a61bc3b-faa1-4350-9d61-159dfe1902ab', '2eca7386-054f-41ea-94ef-da768169cb00', 'radio', 'Questions 11–14', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. a factory"}, {"option_text": "B. a private home"}, {"option_text": "C. a hall of residence"}], "question": "The museum building was originally"}, {"correct": 0, "options": [{"option_text": "A. teaching rooms"}, {"option_text": "B. a research library"}, {"option_text": "C. administration offices"}], "question": "The university uses part of the museum building as"}, {"correct": 0, "options": [{"option_text": "A. Visitors decide whether or not they wish to pay"}, {"option_text": "B. Only children and students receive a discount"}, {"option_text": "C. The museum charges extra for special exhibitions"}], "question": "What does the guide say about the entrance fee?"}, {"correct": 2, "options": [{"option_text": "A. cameras"}, {"option_text": "B. coats"}, {"option_text": "C. bags"}], "question": "What are visitors advised to leave in the cloakroom?"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('1de0f991-3dae-4a33-9fdf-8ef84c5d35c7', '2eca7386-054f-41ea-94ef-da768169cb00', 'matching', 'Questions 15–20', '', '<p data-start="649" data-end="740"><strong data-start="649" data-end="740">What information does the speaker give about each of the following areas of the museum?</strong></p>
<p data-start="742" data-end="845">Choose <strong data-start="749" data-end="756">SIX</strong> answers from the box and write the correct letter, <strong data-start="808" data-end="815">A–H</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<div class=\"text-base my-auto mx-auto [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)\">\n<div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" data-conversation-screenshot-content=\"\">\n<div class=\"flex max-w-full flex-col gap-4 grow\">\n<div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal outline-none keyboard-focused:focus-ring [.text-message+&amp;]:mt-1\" dir=\"auto\" data-message-author-role=\"assistant\" data-message-id=\"26d8b6bc-eb81-47f7-911d-25dfc9793d59\" data-message-model-slug=\"gpt-5-5\">\n<div class=\"flex w-full flex-col gap-1 empty:hidden\">\n<div class=\"markdown prose dark:prose-invert wrap-break-word w-full light markdown-new-styling\">\n<h3 data-section-id=\"156x0pp\" data-start=\"1148\" data-end=\"1167\">Areas of museum</h3>\n<p>15. Four Seasons {F. It features something created by students}</p>\n<p>16. Farmhouse Kitchen {G. An expert is here today}</p>\n<p>17. A Year on the Farm {E. There is a quiz for visitors}</p>\n<p>18. Wagon Walk {A. Parents must supervise their children}</p>\n<p>19. Bees are Magic {C. It is closed today}</p>\n<p>20. The Pond {B. There are new things to see}</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>", "answerOptions": [{"optionText": "A. Parents must supervise their children"}, {"optionText": "B. There are new things to see"}, {"optionText": "C. It is closed today"}, {"optionText": "D. This is only for school groups"}, {"optionText": "E. There is a quiz for visitors"}, {"optionText": "F. It features something created by students"}, {"optionText": "G. An expert is here today"}, {"optionText": "H. There is a one-way system"}], "matchingItems": []}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('d54dc0cb-ccf0-4a7c-a576-5969538f3751', '35f45f28-0e1d-4c31-8aa9-1c5e5e3494cd', 'checkbox', 'Questions 21–22', '', '<p data-start="29" data-end="57">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="59" data-end="142">Which <strong>TWO </strong>educational skills were shown in the video of children doing origami?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. solving problems"}, {"correct": true, "option_text": "B. following instructions"}, {"correct": false, "option_text": "C. working cooperatively"}, {"correct": true, "option_text": "D. learning through play"}, {"correct": false, "option_text": "E. developing hand-eye coordination"}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('e5146329-d199-4994-ad67-3c271b3a9776', 'cabcf42e-541a-4794-bae1-6e3902ca77e7', 'fillup', 'Questions 14–18', '<p>Complete the summary below</p>
<p>Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the passage for each answer.<br>The thylacine was a dog-like animal which had a {striped} coat and was carnivorous. It was originally spread widely throughout the mainland of {Australia} but started to disappear from that area around {12 million} years ago because of climate change.</p>
<p>In the end, thylacines were found only on the island of {Tasmania} until the arrival of {Europeans} with their farming practices brought about a drastic reduction in thylacine numbers. The last one is thought to have died in Hobart Zoo in 1936.</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. striped</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"It was given the name ‘tiger’ because it had <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"66\">striped fur</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc mô tả loài này được gọi là \"hổ\" vì có bộ lông vằn (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"71\">striped coat/fur</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Australia</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"...many types of thylacine roamed across <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"62\">Australia</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài hổ Tasmania này ban đầu phân bố rộng rãi khắp lục địa <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"71\">Australia</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. 12 million years</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"But when a period of climate change cooled Australia about <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"80\">12 million years ago</strong>, the numbers of these ancient thylacines began to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"151\">decline</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Do biến đổi khí hậu, số lượng loài này bắt đầu giảm sút (bắt đầu biến mất dần) từ khoảng <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"101\">12 triệu năm</strong> trước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Tasmania</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"...so that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"32\">Tasmania</strong>, a large island to the south of Australia, became the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"95\">last remaining place</strong> where thylacines existed.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cuối cùng, nơi duy nhất còn loài này sinh sống là hòn đảo <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"70\">Tasmania</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Europeans</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"They ruled the island’s animal life unchallenged until <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"76\">Europeans</strong> – with sheep, dogs... seem to have brought about their <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"141\">extinction</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự xuất hiện của người <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"35\">Châu Âu</strong> cùng các tập quán chăn nuôi (sheep, dogs) đã dẫn đến sự sụt giảm nghiêm trọng và tuyệt chủng của loài này.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('6d55e1f2-ceeb-49e5-9b75-85a71a5c6d5f', 'cabcf42e-541a-4794-bae1-6e3902ca77e7', 'matrix', 'Questions 19-24', NULL, '<p>Match each statement with the correct person, <strong>A</strong>, <strong>В</strong>, <strong>C </strong>or <strong>D</strong>.</p>
<p>Choose the correct letter, <strong>A</strong>, <strong>В</strong>, <strong>C </strong>or <strong>D</strong>, in boxes 19-24.</p>', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "There is no longer any hope of finding a surviving Tasmanian tiger.", "correctCategoryLetter": "B"}, {"itemText": "It would be preferable not to disturb any surviving Tasmanian tigers.", "correctCategoryLetter": "A"}, {"itemText": "Many who claim to have seen Tasmanian tigers are not objective witnesses.", "correctCategoryLetter": "D"}, {"itemText": "Expert estimates of numbers needed to ensure species survival may be inaccurate.", "correctCategoryLetter": "C"}, {"itemText": "There is a great deal of international interest in Tasmanian tiger stories.", "correctCategoryLetter": "A"}, {"itemText": "Some fresh evidence provided by a visitor to Tasmania seems credible.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Hans Naarding", "categoryLetter": "A"}, {"categoryText": "Randolph Rose", "categoryLetter": "B"}, {"categoryText": "David Pemberton", "categoryLetter": "C"}, {"categoryText": "Nick Mooney", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">19. There is no longer any hope of finding a surviving Tasmanian tiger. — {B. Randolph Rose}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"Randolph Rose... says that he dreamed of seeing a thylacine, but is now <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"93\">convinced that his dream will go unfulfilled</strong>... Take it from me, the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"162\">tiger is gone</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Randolph Rose khẳng định giấc mơ nhìn thấy hổ Tasmania của ông sẽ không thành hiện thực và chốt lại rằng \"con hổ đã biến mất rồi\". Điều này tương ứng với việc không còn hy vọng tìm thấy chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">20. It would be preferable not to disturb any surviving Tasmanian tigers. — {A. Hans Naarding}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"Naarding believes that any discovery... would be rather <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"77\">pointless</strong>... If there are thylacines out there, they are <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"134\">better off right where they are</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hans Naarding cho rằng nếu chúng còn tồn tại thì tốt nhất là cứ để chúng ở yên đó (\"better off right where they are\"), tức là không nên làm phiền hay quấy rầy chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">21. Many who claim to have seen Tasmanian tigers are not objective witnesses. — {D. Nick Mooney}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"Mooney says... Many other sightings have been <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"67\">hoaxes</strong>, and many sincere seekers are <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"104\">victims of obsession</strong>. ‘It is a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"135\">blind optimism</strong>...’\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nick Mooney nhận định nhiều người báo cáo nhìn thấy hổ là do ám ảnh hoặc lạc quan mù quáng, dẫn đến việc họ không còn nhìn nhận một cách khách quan (không đặt câu hỏi đó là con gì mà khẳng định ngay đó là hổ Tasmania).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">22. Expert estimates of numbers needed to ensure species survival may be inaccurate. — {C. David Pemberton}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"Dr David Pemberton... states that, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"56\">despite scientific thinking that a relatively large number of animals required</strong> to sustain a population, the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"164\">Florida panther is down to a dozen or so... and is still ticking along</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> David Pemberton đưa ra ví dụ về loài báo Florida vẫn tồn tại dù số lượng cực thấp để phản bác lại quan điểm khoa học thông thường về số lượng tối thiểu để duy trì bầy đàn. Điều này có nghĩa là các ước tính của chuyên gia có thể không chính xác (inaccurate).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">23. There is a great deal of international interest in Tasmanian tiger stories. — {A. Hans Naarding}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"‘When the news broke,’ said Naarding, ‘I was <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"66\">besieged by television crews, including four or five from Japan, and others from the United Kingdom, Germany, New Zealand and South America</strong>.’\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc các đài truyền hình từ khắp nơi trên thế giới (Nhật, Anh, Đức...) đổ xô đến tìm Naarding sau khi ông báo cáo nhìn thấy hổ chính là minh chứng cho sự quan tâm quốc tế (international interest).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">24. Some fresh evidence provided by a visitor to Tasmania seems credible. — {D. Nick Mooney}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">\"It was Mooney who was first consulted... about the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"72\">authenticity of new digital photographic images</strong>... allegedly taken by a <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"144\">tourist</strong>... this particular account... amount to one of the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"203\">most convincing cases</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nick Mooney đánh giá những tấm ảnh kỹ thuật số mới từ một khách du lịch (tourist/visitor) là một trong những bằng chứng thuyết phục (convincing/credible) nhất mà ông từng thấy.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('eef29c77-a4e0-4d06-b82c-1713f6a38473', 'cabcf42e-541a-4794-bae1-6e3902ca77e7', 'radio', 'Questions 25-26', NULL, '<p>Choose the correct answers.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "the capture of the tiger."}, {"content": "an extensive follow up."}, {"content": "many other sightings."}, {"content": "the death of the tiger."}], "question": " Hans Naarding’s sighting of a Tasamanian tiger resulted in"}, {"correct": 3, "options": [{"content": "new animal species are still evolving."}, {"content": "animals can possess surprising physical characteristics."}, {"content": "species of sea animals can be saved from extinction."}, {"content": "opinions regarding extinction of animal species can be mistaken."}], "question": "The example of the coelacanth is used to show that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">25. Hans Naarding’s sighting of a Tasmanian tiger resulted in</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Câu hỏi</strong>: Việc Hans Naarding nhìn thấy một con hổ Tasmania đã dẫn đến kết quả gì?</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dịch nghĩa đáp án đúng</strong>: Một cuộc theo dõi/điều tra trên diện rộng (an extensive follow up).</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Đáp án</strong>: <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"8\">an extensive follow up</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"2,3,0\"><strong data-path-to-node=\"2,3,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “Naarding, whose sighting of a thylacine in 1982 is the most widely accepted… resulted in an official search by the Tasmanian Parks and Wildlife Service.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,4,0\"><strong data-path-to-node=\"2,4,0\" data-index-in-node=\"0\">Giải thích</strong>: Trong bài đọc, việc Naarding nhìn thấy hổ Tasmania vào năm 1982 được coi là báo cáo đáng tin cậy nhất, dẫn đến việc cơ quan chức năng (Wildlife Service) phải tổ chức một cuộc tìm kiếm chính thức và quy mô (official search = extensive follow up).</p>\n</li>\n</ul>\n<hr data-path-to-node=\"3\" />\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">26. The example of the coelacanth is used to show that</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Câu hỏi</strong>: Ví dụ về cá vây tay (coelacanth) được sử dụng để chỉ ra điều gì?</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dịch nghĩa đáp án đúng</strong>: Các ý kiến liên quan đến sự tuyệt chủng của các loài động vật có thể sai lầm.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Đáp án</strong>: <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"8\">opinions regarding extinction of animal species can be mistaken</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “The most famous example is the coelacanth… thought to have been extinct for 70 million years until one was caught in 1938.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,4,0\"><strong data-path-to-node=\"5,4,0\" data-index-in-node=\"0\">Giải thích</strong>: Tác giả dùng ví dụ cá vây tay — một loài vật từng bị cho là đã tuyệt chủng từ 70 triệu năm trước nhưng sau đó lại được tìm thấy còn sống vào năm 1938 — để chứng minh rằng nhận định của con người về việc một loài đã “tuyệt chủng” hoàn toàn có thể bị nhầm lẫn (mistaken).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('385dc44b-8811-459a-863f-054c394b5375', '35f45f28-0e1d-4c31-8aa9-1c5e5e3494cd', 'matching', 'Questions 23–27', '', '<p data-start="310" data-end="399"><strong data-start="310" data-end="399">Which comment do the students make about each of the following children in the video?</strong></p>
<p data-start="401" data-end="505">Choose <strong data-start="408" data-end="416">FIVE</strong> answers from the box and write the correct letter, <strong data-start="468" data-end="475">A–G</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<h3 data-section-id=\"t63lzp\" data-start=\"757\" data-end=\"769\">Children</h3>\n<p>23. Sid {D. seemed to find the activity calming}</p>\n<p>24. Jack {A. demonstrated independence}</p>\n<p>25. Naomi {C. developed a competitive attitude}</p>\n<p>26. Anya {G. seemed to find the activity easy}</p>\n<p>27. Zara {F. seemed confused}</p>", "answerOptions": [{"optionText": "A. demonstrated independence"}, {"optionText": "B. asked for teacher support"}, {"optionText": "C. developed a competitive attitude"}, {"optionText": "D. seemed to find the activity calming"}, {"optionText": "E. seemed pleased with the results"}, {"optionText": "F. seemed confused"}, {"optionText": "G. seemed to find the activity easy"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('97c1f2fb-f71f-48f1-bdc6-1c6792208f21', 'c1d994c3-f090-4530-add8-9cfe3a340b2d', 'checkbox', 'Questions 23 and 24', '', '<p data-start="367" data-end="395">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="397" data-end="480">Which <strong>TWO </strong>predictions about the future of work are the students doubtful about?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "Work will be more rewarding"}, {"correct": true, "option_text": "Unemployment will fall"}, {"correct": false, "option_text": "People will want to delay retiring"}, {"correct": true, "option_text": "Working hours will be shorter"}, {"correct": false, "option_text": "People will change jobs more frequently"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('1aa99f1c-eca2-440c-936e-db238b6d1c3e', '35f45f28-0e1d-4c31-8aa9-1c5e5e3494cd', 'radio', 'F. seemed confused', '', '<p data-start="905" data-end="946"><strong data-start="905" data-end="946">Choose the correct letter, A, B or C.</strong></p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. make models that demonstrate the different stages"}, {"option_text": "B. check children understand the terminology involved"}, {"option_text": "C. tell children not to worry if they find the activity difficult"}], "question": "Before starting an origami activity in class, the students think it is important for the teacher to"}, {"correct": 1, "options": [{"option_text": "A. they may not think that crafts are important"}, {"option_text": "B. they may not have the necessary skills."}, {"option_text": "C. they may worry that it will take up too much time"}], "question": "The students agree that some teachers might be unwilling to use origami in class because"}, {"correct": 2, "options": [{"option_text": "A. to correct a particular misunderstanding"}, {"option_text": "B. to set a challenge"}, {"option_text": "C. to introduce a new concept"}], "question": "Why do the students decide to use origami in their maths teaching practice?"}]', 'null', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('ec573fd7-ec10-4894-9228-35ea339a3d0d', 'd60f9097-f454-4b9a-9480-70077e7b2580', 'radio', 'Questions 27–30', '', '<p>Choose <strong data-start="154" data-end="161">YES</strong> – if the statement agrees with the claims of the writer, <strong data-start="220" data-end="226">NO</strong> – if the statement contradicts the claims of the writer, <strong data-start="285" data-end="298">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Human beings have a fixed supply of energy"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People tend to experience hunger at the end of an energy cycle"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Taking regular breaks is seen as inappropriate in the majority of organisations"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Negative emotions in the workplace can increase staff absences"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. NO</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“The problem with working longer hours is that time is a finite resource. However, energy is a different story. Energy comes from four main wellsprings... and in each area, energy can be systematically expanded.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định con người có một nguồn cung cấp năng lượng cố định (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"83\">fixed supply</em>). Tuy nhiên, bài đọc chỉ ra rằng thời gian mới là tài nguyên hữu hạn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"166\">finite resource</em>), còn năng lượng thì ngược lại (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"214\">a different story</em>) vì nó có thể được mở rộng một cách có hệ thống (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"281\">systematically expanded</strong>). Vì thông tin mâu thuẫn trực tiếp nên đáp án là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"354\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“Toward the end of each cycle, our systems crave recovery. The signals include restlessness and difficulty concentrating, but we often ignore them and keep working.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về dấu hiệu khi cơ thể rơi vào cuối chu kỳ năng lượng là thèm sự phục hồi (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"102\">crave recovery</em>), biểu hiện qua sự bồn chồn (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"146\">restlessness</em>) và khó tập trung (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"178\">difficulty concentrating</em>). Bài viết <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"214\">hoàn toàn không đề cập</strong> đến việc con người có xu hướng cảm thấy đói bụng (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"287\">experience hunger</em>) vào thời điểm này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. YES</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“While having breaks every hour or so goes against the culture of most organizations, their value is multifaceted.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói việc nghỉ giải lao thường xuyên bị xem là không phù hợp/không đúng mực ở phần lớn các tổ chức (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"119\">seen as inappropriate in the majority of organisations</em>). Điều này trùng khớp hoàn toàn với thông tin trong bài: việc nghỉ ngơi mỗi giờ hoặc mớ tương tự là đi ngược lại với văn hóa của hầu hết các tổ chức (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"324\">goes against the culture of most organizations</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“This drains energy, causes friction between workers and makes it impossible to think clearly.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn có nêu tác hại của cảm xúc tiêu cực nơi công sở là làm cạn kiệt năng lượng, gây xích mích giữa các đồng nghiệp (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"133\">causes friction between workers</em>) và không thể suy nghĩ thấu đáo. Tuy nhiên, việc những cảm xúc tiêu cực này có làm gia tăng tỷ lệ nghỉ việc hay vắng mặt của nhân viên (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"301\">increase staff absences</em>) hay không thì <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"340\">không được nhắc tới</strong> trong bài.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('3b58051f-4073-420f-8c9c-27e6c0e0fd2a', 'c210477f-2e46-44cb-90f4-ba28ee76de45', 'fillup', 'Questions 31–40', '<h3 data-section-id="1i6hwlk" data-start="29" data-end="58">Complete the notes below.</h3>
<p data-start="59" data-end="99"><strong data-start="59" data-end="99">Write ONE WORD ONLY for each answer.</strong></p>
<table style="border-collapse: collapse; width: 99.999%; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8778%;"></colgroup>
<tbody>
<tr>
<td style="border-color: #000000;">
<div class="relative basis-auto flex-col -mb-(--composer-overlap-px) pb-(--composer-overlap-px) [--composer-overlap-px:28px] grow flex" data-voice-floating-orb-focus-background="">
<div class="flex flex-col text-sm">
<div class="qMYqUG_convSearchResultHighlightRoot">
<div class="" data-turn-id-container="request-6a1d50e9-7334-83ec-b2b6-dce3774730fe-6" data-is-intersecting="true">
<section class="text-token-text-primary w-full focus:outline-none has-data-writing-block:pointer-events-none [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto R6Vx5W_threadScrollVars scroll-mb-[calc(var(--scroll-root-safe-area-inset-bottom,0px)+var(--thread-response-height))] scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]" dir="auto" data-turn-id="request-6a1d50e9-7334-83ec-b2b6-dce3774730fe-6" data-turn-id-container="request-6a1d50e9-7334-83ec-b2b6-dce3774730fe-6" data-testid="conversation-turn-168" data-scroll-anchor="false" data-turn="assistant">
<div class="text-base my-auto mx-auto pb-10 [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn" data-conversation-screenshot-content="">
<div class="flex max-w-full flex-col gap-4 grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal outline-none keyboard-focused:focus-ring [.text-message+&amp;]:mt-1" dir="auto" tabindex="0" data-message-author-role="assistant" data-message-id="eb15e33d-9fc4-451f-97b9-def5e4807839" data-message-model-slug="gpt-5-5" data-turn-start-message="true">
<div class="flex w-full flex-col gap-1 empty:hidden">
<div class="markdown prose dark:prose-invert wrap-break-word w-full light markdown-new-styling">
<p style="text-align: center;" data-section-id="19kq91i" data-start="101" data-end="114"><span style="font-size: 14pt;"><strong>Victor Hugo</strong></span></p>
<p data-section-id="1km1lop" data-start="116" data-end="147"><strong><span role="text">His novel, <em data-start="131" data-end="147">Les Misérables</em></span></strong></p>
<ul data-start="148" data-end="267">
<li data-section-id="1ddc5ii" data-start="148" data-end="193">It has been adapted for theatre and cinema.</li>
<li data-section-id="1qle42f" data-start="194" data-end="267">We know more about its overall {plot} than about its author.</li>
</ul>
<p data-section-id="nq7xlh" data-start="269" data-end="289"><strong>His early career</strong></p>
<ul data-start="290" data-end="493">
<li data-section-id="1h8ier1" data-start="290" data-end="361">In Paris, his career was successful and he led the Romantic movement.</li>
<li data-section-id="g03b9u" data-start="362" data-end="443">He spoke publicly about social issues, such as {poverty} and education.</li>
<li data-section-id="1jioyqc" data-start="444" data-end="493">Napoleon III disliked his views and exiled him.</li>
</ul>
<p data-section-id="xdh0i" data-start="495" data-end="520"><strong>His exile from France</strong></p>
<ul data-start="521" data-end="682">
<li data-section-id="1r7npkj" data-start="521" data-end="578">Victor Hugo had to live elsewhere in {Europe}.</li>
<li data-section-id="118ow69" data-start="579" data-end="682">He used his income from the sale of some {poetry} he had written to buy a house on Guernsey.</li>
</ul>
<p data-section-id="asgwvp" data-start="684" data-end="709"><strong>His house on Guernsey</strong></p>
<ul data-start="710" data-end="1392" data-is-last-node="" data-is-only-node="">
<li data-section-id="17gq1c1" data-start="710" data-end="782">Victor Hugo lived in this house until the end of the Empire in France.</li>
<li data-section-id="mxz1ol" data-start="783" data-end="870">The ground floor contains portraits, {drawings} and tapestries that he valued.</li>
<li data-section-id="14o03fe" data-start="871" data-end="965">He bought cheap {furniture} made of wood and turned this into beautiful wall carvings.</li>
<li data-section-id="1or37o2" data-start="966" data-end="1076">The first floor consists of furnished areas with wallpaper and {lamps} that have a Chinese design.</li>
<li data-section-id="a6qm3a" data-start="1077" data-end="1134">The library still contains many of his favourite books.</li>
<li data-section-id="n1fzhl" data-start="1135" data-end="1221">He wrote in a room at the top of the house that had a view of the {harbour|harbor}.</li>
<li data-section-id="1jd565f" data-start="1222" data-end="1300">He entertained other writers as well as poor {children} in his house.</li>
<li data-section-id="36pwtx" data-start="1301" data-end="1392" data-is-last-node="">Victor Hugo’s {relatives} gave ownership of the house to the city of Paris in 1927.</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</section>
</div>
