<h1 data-section-id="19kq91i" data-start="101" data-end="114"> </h1>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('b25f1754-d3ac-44e0-abdb-337b0be916ea', 'fc1f0087-2780-471b-b1b3-7cac9ffe5d55', 'radio', 'Questions 1–4', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Ruamahanga River often floods."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "When Tobin first found the object in the river, he mistook it for something else."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Tobin could not decide what part of the body the bone came from."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Tobin''s mother was surprised that the skull caused debate among specialists."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">1. The Ruamahanga River often floods.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a four-metre-high flood bank testifies to its natural tendency to flood.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một bờ đê ngăn lũ cao 4 mét là bằng chứng cho thấy con sông này có xu hướng tự nhiên là hay bị lũ lụt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">2. When Tobin first found the object in the river, he mistook it for something else.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…he noticed what he initially took to be a whitish rock…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lúc đầu Sam Tobin đã nhầm hộp sọ là một <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"52\">viên đá trắng</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">3. Tobin could not decide what part of the body the bone came from.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As he picked it up, he saw it was a <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"48\">skull</strong>, discoloured with age.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Tobin không thể quyết định mảnh xương từ bộ phận nào, nhưng bài đọc khẳng định ngay khi cầm lên anh đã nhận ra đó là một <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"145\">hộp sọ</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">4. Tobin’s mother was surprised that the skull caused debate among specialists.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…hurried home to tell his mother what the river had delivered to their doorstep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói Sam về nhà kể cho mẹ nghe về khám phá, không đề cập đến cảm xúc “ngạc nhiên” của bà trước những tranh luận của các chuyên gia sau này.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('67da484e-3da4-4939-9cd7-fdcea6135172', 'fc1f0087-2780-471b-b1b3-7cac9ffe5d55', 'fillup', 'Questions 5–9', '<p>Complete the flow-chart below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the passage for each answer.</p>
<h3 style="text-align: center;">The events after the river flooded</h3>
<p style="text-align: center;">Tobin found a human skull.</p>
<p class="MsoNormal"><img decoding="async" style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">The  {POLICE}   were initially involved in trying to explain the presence of the skull.</p>
<p style="text-align: center;"><img decoding="async" style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">Dr Ferris believed the skull belonged to a female.</p>
<p style="text-align: center;"><img decoding="async" style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">Dr Koelmeyer suggested it was a  {EUROPEAN}   skull.</p>
<p style="text-align: center;"><img decoding="async" style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">Dr Watt recommended  {Radiocarbon dating}   to establish the skull’s age.</p>
<p style="text-align: center;"><img decoding="async" style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">A bone  {SAMPLE}  was sent to the GNS.</p>
<p style="text-align: center;"><img decoding="async" style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">The age of the skull was about  {296}   years.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5 . </strong><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> POLICE</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The police were immediately called, but despite a thorough search could find nothing…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi Sam kể cho gia đình, cảnh sát là lực lượng đầu tiên tham gia vào việc tìm kiếm và cố gắng giải thích sự xuất hiện của hộp sọ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. </strong><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> EUROPEAN</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the skull appeared to be European in origin.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bác sĩ Koelmeyer, sau khi tham vấn, đã đưa ra nhận định quan trọng rằng hộp sọ này có đặc điểm nhân chủng học của người Châu Âu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7 . </strong><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Radiocarbon dating</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…proposed the use of radiocarbon dating to make sure it wasn’t a recent death.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tiến sĩ Watt đã đề xuất sử dụng phương pháp đo carbon phóng xạ để xác định chính xác thời điểm tử vong và đảm bảo đây không phải là một vụ án gần đây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">8. </strong><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> SAMPLE</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…provided with a sample of bone that had originated in the top of the skull.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong data-path-to-node=\"19,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một mẫu xương (sample) lấy từ phần đỉnh hộp sọ đã được gửi tới Viện Khoa học Địa chất và Hạt nhân (GNS) để phân tích.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">9. </strong><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án:</strong> 296</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…conventional radiocarbon age approximately 296 years.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong data-path-to-node=\"21,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả từ phòng thí nghiệm GNS xác định tuổi của hộp sọ là xấp xỉ 296 năm, một con số gây kinh ngạc vì nó lâu đời hơn rất nhiều so với các giả định trước đó.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('ae306f46-01c1-47da-9728-56bb52d2e487', 'fc1f0087-2780-471b-b1b3-7cac9ffe5d55', 'fillup', 'Questions 10–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Problem of the skull’s origins</strong></p>
<p>Old bones common in NZ – Maori living there for 800 years – Ruamahanga skull surprising because of its<br />– Age<br />–  {RACE}<br />– Gender</p>
<p>Mendana expedition<br />Possible source of skull<br />But probably did not visit NZ<br />Evidence of this expedition found elsewhere by  {ARCHAEOLOGISTS}</p>
<p>New Zealand<br />First European explorer arrived in 1642<br />Hagerty and Edgar arrived in 1806 from  {AUSTRALIA}   where they had been imprisoned</p>
<p>Possible solution<br />Ruamahanga skull may have reached NZ in 17th century after a  {SHIPWRECK}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">10 </strong><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> RACE</p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The fascinating question, however, was how a skull of this race, let alone this gender, had reached these remote islands…”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hộp sọ gây ngạc nhiên không chỉ bởi giới tính nữ mà còn bởi chủng tộc (race) của nó, vì nó có niên đại trước khi người Châu Âu định cư tại New Zealand.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">11  </strong><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> ARCHAEOLOGISTS</p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…while a team of archaeologists working in the Solomon Islands in 1970 did discover the remains of European vessels dating from the 16th century.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù không thấy bằng chứng của đoàn thám hiểm Mendana tại NZ, nhưng các nhà khảo cổ (archaeologists) đã tìm thấy dấu vết tàu Châu Âu thế kỷ 16 tại quần đảo Solomon.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">12  </strong><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> AUSTRALIA</p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Two centuries were to pass before the first recorded European females arrived in New Zealand, both having escaped from prison in Australia.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những phụ nữ Châu Âu đầu tiên chính thức được ghi nhận đến NZ vào năm 1806, xuất thân là những tù nhân trốn thoát từ Úc (Australia).</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">13  </strong><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> SHIPWRECK</p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the most likely explanation is that a Spanish or Portuguese trading-ship was washed onto these wild shores as a result of a shipwreck and a woman got ashore.”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Giải thích khả thi nhất cho sự hiện diện của hộp sọ này là kết quả từ một vụ đắm tàu (shipwreck) của Tây Ban Nha hoặc Bồ Đào Nha, giúp một người phụ nữ may mắn sống sót dạt vào bờ.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('a9985b9c-3c94-47bd-99b3-2d4b3b0a9f9c', '86737a36-0f4e-42b3-9229-cd5dc9dfa9af', 'matching', 'Questions 14–19', NULL, '<p>The text has six paragraphs. Choose the correct heading for each paragraph and move it into the gap.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "Sending messages underground"}, {"optionText": "Potential advantages for farmers"}, {"optionText": "The widespread rejection of an idea"}, {"optionText": "One species accelerating growth in another"}, {"optionText": "Some obstacles to plant communication"}, {"optionText": "Evidence leading to renewed belief in a theory"}, {"optionText": "New technologies which helped researchers"}, {"optionText": "A suggested benefit to the sender of plant communication"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-start=\"144\" data-end=\"189\">14. The widespread rejection of an idea</h3>\n<p data-start=\"191\" data-end=\"229\"><strong data-start=\"191\" data-end=\"202\">Vị trí:</strong> Đoạn 14, phần cuối đoạn.</p>\n<p data-start=\"231\" data-end=\"398\"><strong data-start=\"231\" data-end=\"245\">Dẫn chứng:</strong><br data-start=\"245\" data-end=\"248\" />“But the plant research community did not accept this… By the late 1980s, most ecologists felt that Schultz and Baldwin’s ideas had been discredited.”</p>\n<p data-start=\"400\" data-end=\"614\"><strong data-start=\"400\" data-end=\"415\">Giải thích:</strong><br data-start=\"415\" data-end=\"418\" />Đoạn này nói rõ cộng đồng khoa học <strong data-start=\"453\" data-end=\"472\">không chấp nhận</strong> giả thuyết ban đầu. Ý tưởng bị cho là không thể lặp lại và thiếu tính tiến hóa. Vì vậy heading phù hợp là sự <strong data-start=\"582\" data-end=\"613\">bác bỏ rộng rãi một ý tưởng</strong>.</p>\n<h3 data-start=\"621\" data-end=\"677\">15. Evidence leading to renewed belief in a theory</h3>\n<p data-start=\"679\" data-end=\"712\"><strong data-start=\"679\" data-end=\"690\">Vị trí:</strong> Đoạn 15, toàn đoạn.</p>\n<p data-start=\"714\" data-end=\"853\"><strong data-start=\"714\" data-end=\"728\">Dẫn chứng:</strong><br data-start=\"728\" data-end=\"731\" />“A decade later… carefully designed experiments began to yield convincing indications…”<br data-start=\"818\" data-end=\"821\" />“In 2000… Karban showed that…”</p>\n<p data-start=\"855\" data-end=\"1021\"><strong data-start=\"855\" data-end=\"870\">Giải thích:</strong><br data-start=\"870\" data-end=\"873\" />Sau 10 năm, các thí nghiệm được thiết kế cẩn thận hơn đã đưa ra bằng chứng thuyết phục, khôi phục lại niềm tin vào lý thuyết giao tiếp giữa các cây.</p>\n<h3 data-start=\"1028\" data-end=\"1094\">16. A suggested benefit to the sender of plant communication</h3>\n<p data-start=\"1096\" data-end=\"1142\"><strong data-start=\"1096\" data-end=\"1107\">Vị trí:</strong> Đoạn 16, phần giữa và cuối đoạn.</p>\n<p data-start=\"1144\" data-end=\"1330\"><strong data-start=\"1144\" data-end=\"1158\">Dẫn chứng:</strong><br data-start=\"1158\" data-end=\"1161\" />“external communication channels are merely an extension of within-plant signaling”<br data-start=\"1244\" data-end=\"1247\" />“enhances the ‘extended fitness’ of the sender… a strategy known as kin selection.”</p>\n<p data-start=\"1332\" data-end=\"1550\"><strong data-start=\"1332\" data-end=\"1347\">Giải thích:</strong><br data-start=\"1347\" data-end=\"1350\" />Đoạn này giải thích vì sao cây gửi tín hiệu có thể có lợi cho chính nó – hoặc là mở rộng cơ chế tự bảo vệ nội tại, hoặc giúp các cây họ hàng (kin selection). Đây chính là lợi ích dành cho “người gửi”.</p>\n<h3 data-start=\"1557\" data-end=\"1595\">17. Sending messages underground</h3>\n<p data-start=\"1597\" data-end=\"1646\"><strong data-start=\"1597\" data-end=\"1608\">Vị trí:</strong> Đoạn 17, câu đầu và phần giữa đoạn.</p>\n<p data-start=\"1648\" data-end=\"1809\"><strong data-start=\"1648\" data-end=\"1662\">Dẫn chứng:</strong><br data-start=\"1662\" data-end=\"1665\" />“distress signals can be passed through the plants’ roots.”<br data-start=\"1724\" data-end=\"1727\" />“networks of hair-like fungi… served as a channel for warning neighboring plants.”</p>\n<p data-start=\"1811\" data-end=\"1954\"><strong data-start=\"1811\" data-end=\"1826\">Giải thích:</strong><br data-start=\"1826\" data-end=\"1829\" />Đoạn này tập trung vào việc truyền tín hiệu qua rễ và mạng lưới nấm dưới đất → đúng với tiêu đề gửi thông điệp dưới lòng đất.</p>\n<h3 data-start=\"1961\" data-end=\"2013\">18. One species accelerating growth in another</h3>\n<p data-start=\"2015\" data-end=\"2052\"><strong data-start=\"2015\" data-end=\"2026\">Vị trí:</strong> Đoạn 18, phần đầu đoạn.</p>\n<p data-start=\"2054\" data-end=\"2191\"><strong data-start=\"2054\" data-end=\"2068\">Dẫn chứng:</strong><br data-start=\"2068\" data-end=\"2071\" />“chili plant seedlings grown next to fennel plants developed more quickly than seedlings grown with other chili plants.”</p>\n<p data-start=\"2193\" data-end=\"2346\"><strong data-start=\"2193\" data-end=\"2208\">Giải thích:</strong><br data-start=\"2208\" data-end=\"2211\" />Một loài (fennel) ảnh hưởng làm loài khác (chili) phát triển nhanh hơn → đúng tiêu đề về một loài thúc đẩy sự phát triển của loài khác.</p>\n<h3 data-start=\"2353\" data-end=\"2395\">19. Potential advantages for farmers</h3>\n<p data-start=\"2397\" data-end=\"2433\"><strong data-start=\"2397\" data-end=\"2408\">Vị trí:</strong> Đoạn 19, câu đầu đoạn.</p>\n<p data-start=\"2435\" data-end=\"2572\"><strong data-start=\"2435\" data-end=\"2449\">Dẫn chứng:</strong><br data-start=\"2449\" data-end=\"2452\" />“knowledge of this phenomenon could eventually be applied to agriculture, and lead to the cultivation of hardier crops.”</p>\n<p data-start=\"2574\" data-end=\"2696\"><strong data-start=\"2574\" data-end=\"2589\">Giải thích:</strong><br data-start=\"2589\" data-end=\"2592\" />Đoạn cuối nói về ứng dụng vào nông nghiệp và tạo ra cây trồng khỏe hơn → lợi ích tiềm năng cho nông dân.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('12edfb7f-91de-4ab3-82c2-e4db387c1b67', 'bcb24ba8-0d1c-4371-9148-b1db05b0a857', 'checkbox', 'Questions 10 and 11', '', '<p>Which <strong>TWO </strong>advantages of using newer buildings for green roofs are mentioned in Paragraph C of the passage?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. a longer growing season for edible produce"}, {"correct": false, "option_text": "B. more economical use of water"}, {"correct": true, "option_text": "C. greater water-storage capacity"}, {"correct": true, "option_text": "D. ability to cultivate more plant types"}, {"correct": false, "option_text": "E. a large surface area for growing plants"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">C. greater water-storage capacity (Khả năng lưu trữ nước lớn hơn)</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Being able to keep enough water at roof height and distribute it right across the rooftop is crucial to maintaining the plants on any green roof – especially on ‘edible roofs’ where fruit and vegetables are farmed. And it’s not easier to do this in very old buildings...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích chi tiết:</strong> Bài đọc nhấn mạnh một yếu tố cốt lõi để duy trì thực vật trên mái nhà là phải giữ đủ nước ở trên cao và phân phối nó đi khắp mái (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"151\">keep enough water at roof height</em>). Tác giả tiếp tục lập luận rằng việc thực hiện điều này ở các tòa nhà rất cũ (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"263\">very old buildings</em>) là không hề dễ dàng, từ đó suy ra các tòa nhà mới hơn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"338\">newer buildings</em>) có lợi thế vượt trội trong việc chịu lực để tích trữ lượng nước lớn này. Do đó, phương án C phản ánh chính xác đặc tính tăng cường khả năng lưu trữ nước (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"509\">greater water-storage capacity</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">D. ability to cultivate more plant types (Khả năng trồng được nhiều loại cây hơn)</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“Having a stronger roof also makes it easier to grow a greater variety of plants, since the soil can be deeper.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích chi tiết:</strong> Tác giả giải thích mối quan hệ nhân quả: khi một tòa nhà có cấu trúc mái kiên cố, khỏe hơn (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"113\">stronger roof</em>), người ta có thể đổ một lớp đất sâu hơn (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"169\">soil can be deeper</em>). Lớp đất càng sâu thì càng tạo điều kiện để trồng được nhiều chủng loại cây đa dạng, phong phú hơn (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"289\">grow a greater variety of plants</em>). Cụm từ <em data-path-to-node=\"7,1,0\" data-index-in-node=\"331\">\"a greater variety of plants\"</em> trong bài được paraphrase hoàn toàn thành cụm <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"407\">ability to cultivate more plant types</strong> trong câu hỏi.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('4f65eaa6-10dd-46a6-b4fc-7fd774baa2e6', '86737a36-0f4e-42b3-9229-cd5dc9dfa9af', 'fillup', 'Questions 20–23', '<p data-start="609" data-end="685">Complete the summary. Write <strong data-start="637" data-end="654">ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;" data-start="687" data-end="742"><span style="font-size: 12pt;"><strong>Plant communication research in Israel and Scotland</strong></span></p>
<p data-start="744" data-end="1191">Plants may send messages via their {roots} according to Ariel Novoplansky of Ben-Gurion University in Israel. In one study, Novoplansky’s team planted rows of garden peas, and created conditions like a {drought} around the first plant in each row. The plants responded by closing the tiny holes on their leaf surfaces, known as pores. They then appeared to signal to other plants nearby, causing them to respond in a similar way.</p>
<p data-start="1193" data-end="1629">Research at the University of Aberdeen in Scotland, meanwhile, has focused on the networks of {fungi} which connect the plants beneath the soil. These structures, which extract sugars from the plants and supply them with phosphorus and nitrogen, also seem to play a key role in plant communication. Experiments involving broad bean and plant-eating insects called {aphids} have also produced some interesting results.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-start=\"2729\" data-end=\"2744\">20. roots</h3>\n<p data-start=\"2746\" data-end=\"2777\"><strong data-start=\"2746\" data-end=\"2757\">Vị trí:</strong> Đoạn 17, câu đầu.</p>\n<p data-start=\"2779\" data-end=\"2855\"><strong data-start=\"2779\" data-end=\"2793\">Dẫn chứng:</strong><br data-start=\"2793\" data-end=\"2796\" />“distress signals can be passed through the plants’ roots.”</p>\n<p data-start=\"2857\" data-end=\"2940\"><strong data-start=\"2857\" data-end=\"2872\">Giải thích:</strong><br data-start=\"2872\" data-end=\"2875\" />Novoplansky chứng minh cây truyền tín hiệu qua rễ → điền “roots”.</p>\n<hr data-start=\"2942\" data-end=\"2945\" />\n<h3 data-start=\"2947\" data-end=\"2964\">21. drought</h3>\n<p data-start=\"2966\" data-end=\"3003\"><strong data-start=\"2966\" data-end=\"2977\">Vị trí:</strong> Đoạn 17, phần đầu đoạn.</p>\n<p data-start=\"3005\" data-end=\"3077\"><strong data-start=\"3005\" data-end=\"3019\">Dẫn chứng:</strong><br data-start=\"3019\" data-end=\"3022\" />“conditions similar to those experienced in a drought.”</p>\n<p data-start=\"3079\" data-end=\"3160\"><strong data-start=\"3079\" data-end=\"3094\">Giải thích:</strong><br data-start=\"3094\" data-end=\"3097\" />Nhóm nghiên cứu tạo điều kiện giống hạn hán → đáp án “drought”.</p>\n<hr data-start=\"3162\" data-end=\"3165\" />\n<h3 data-start=\"3167\" data-end=\"3182\">22. fungi</h3>\n<p data-start=\"3184\" data-end=\"3222\"><strong data-start=\"3184\" data-end=\"3195\">Vị trí:</strong> Đoạn 17, phần giữa đoạn.</p>\n<p data-start=\"3224\" data-end=\"3301\"><strong data-start=\"3224\" data-end=\"3238\">Dẫn chứng:</strong><br data-start=\"3238\" data-end=\"3241\" />“labyrinths of hair-like fungi that occur around the roots…”</p>\n<p data-start=\"3303\" data-end=\"3390\"><strong data-start=\"3303\" data-end=\"3318\">Giải thích:</strong><br data-start=\"3318\" data-end=\"3321\" />Johnson nghiên cứu mạng lưới nấm nối các cây dưới đất → điền “fungi”.</p>\n<hr data-start=\"3392\" data-end=\"3395\" />\n<h3 data-start=\"3397\" data-end=\"3413\">23. aphids</h3>\n<p data-start=\"3415\" data-end=\"3456\"><strong data-start=\"3415\" data-end=\"3426\">Vị trí:</strong> Đoạn 17, câu gần cuối đoạn.</p>\n<p data-start=\"3458\" data-end=\"3521\"><strong data-start=\"3458\" data-end=\"3472\">Dẫn chứng:</strong><br data-start=\"3472\" data-end=\"3475\" />“broad bean plants were infested with aphids…”</p>\n<p data-start=\"3523\" data-end=\"3605\"><strong data-start=\"3523\" data-end=\"3538\">Giải thích:</strong><br data-start=\"3538\" data-end=\"3541\" />Thí nghiệm dùng côn trùng ăn lá gọi là aphids → đáp án “aphids”.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('147ecdaf-24d5-4edb-b903-941e56837c21', '86737a36-0f4e-42b3-9229-cd5dc9dfa9af', 'matrix', 'Questions 24–26', NULL, '<p>Choose the correct researcher, <strong>A</strong>–<strong>E</strong>, for each statement.</p>', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of ressearchers", "matrixItems": [{"itemText": "It is likely that research into plant communication will one day help to improve our food supply", "correctCategoryLetter": "C"}, {"itemText": "Plant communication could occur as a consequence of internal mechanisms intended to help a single plant", "correctCategoryLetter": "A"}, {"itemText": "Attitudes towards plant communication have changed greatly in recent decades.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Richard Karban", "categoryLetter": "A"}, {"categoryText": "Ariel Novoplansky", "categoryLetter": "B"}, {"categoryText": "David Johnson", "categoryLetter": "C"}, {"categoryText": "Monica Gagliano", "categoryLetter": "D"}, {"categoryText": "Carel ten Cate", "categoryLetter": "E"}]}', '[{"content": "<h3 data-start=\"3638\" data-end=\"3663\">24. C (David Johnson)</h3>\n<p data-start=\"3665\" data-end=\"3700\"><strong data-start=\"3665\" data-end=\"3676\">Vị trí:</strong> Đoạn 19, câu thứ hai.</p>\n<p data-start=\"3702\" data-end=\"3833\"><strong data-start=\"3702\" data-end=\"3716\">Dẫn chứng:</strong><br data-start=\"3716\" data-end=\"3719\" />“Applying our limited knowledge… to agriculture is a big jump… but it is definitely on the horizon,” says Johnson.</p>\n<p data-start=\"3835\" data-end=\"3965\"><strong data-start=\"3835\" data-end=\"3850\">Giải thích:</strong><br data-start=\"3850\" data-end=\"3853\" />Johnson nói việc áp dụng nghiên cứu vào nông nghiệp là có thể trong tương lai → giúp cải thiện nguồn lương thực.</p>\n<hr data-start=\"3967\" data-end=\"3970\" />\n<h3 data-start=\"3972\" data-end=\"3998\">25. A (Richard Karban)</h3>\n<p data-start=\"4000\" data-end=\"4038\"><strong data-start=\"4000\" data-end=\"4011\">Vị trí:</strong> Đoạn 16, phần giữa đoạn.</p>\n<p data-start=\"4040\" data-end=\"4160\"><strong data-start=\"4040\" data-end=\"4054\">Dẫn chứng:</strong><br data-start=\"4054\" data-end=\"4057\" />“external communication channels are merely an extension of within-plant signaling.”<br data-start=\"4141\" data-end=\"4144\" />“Karban agrees…”</p>\n<p data-start=\"4162\" data-end=\"4289\"><strong data-start=\"4162\" data-end=\"4177\">Giải thích:</strong><br data-start=\"4177\" data-end=\"4180\" />Karban cho rằng giao tiếp giữa cây có thể là hệ quả của cơ chế tự bảo vệ nội tại → đúng với nội dung câu hỏi.</p>\n<hr data-start=\"4291\" data-end=\"4294\" />\n<h3 data-start=\"4296\" data-end=\"4325\">26. B (Ariel Novoplansky)</h3>\n<p data-start=\"4327\" data-end=\"4365\"><strong data-start=\"4327\" data-end=\"4338\">Vị trí:</strong> Đoạn 19, phần cuối đoạn.</p>\n<p data-start=\"4367\" data-end=\"4466\"><strong data-start=\"4367\" data-end=\"4381\">Dẫn chứng:</strong><br data-start=\"4381\" data-end=\"4384\" />“During my PhD… this stuff was considered very weird… Today… not strange anymore.”</p>\n<p data-start=\"4468\" data-end=\"4573\"><strong data-start=\"4468\" data-end=\"4483\">Giải thích:</strong><br data-start=\"4483\" data-end=\"4486\" />Novoplansky nói thái độ khoa học đã thay đổi rõ rệt qua thời gian → đúng với statement.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('9633c3b2-2e22-4974-ad15-8843652a70f4', 'de836a66-7fc7-4723-afd8-b1d59632cad0', 'radio', 'Questions 27–31', '', '<p>Choose the correct answers.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "oppose the views of Charles Darwin"}, {"option_text": "compare experts’ opinions of Darwin s theory"}, {"option_text": "explain the theory of evolutionary psychology"}, {"option_text": "name experts in the field of evolutionary psychology"}], "question": "The writers purpose in the first paragraph is to"}, {"correct": 3, "options": [{"option_text": "Our characters determine our career choices"}, {"option_text": "We begin life without any preconceived notions"}, {"option_text": "Our interests and skills depend on our environment"}, {"option_text": "We inherit ideas and characteristics from our ancestors"}], "question": "In the third paragraph which view about evolutionary psychology matches Nicholson’s opinion?"}, {"correct": 1, "options": [{"option_text": "criticise primitive survival strategies"}, {"option_text": "explain attitudes and actions at work"}, {"option_text": "demonstrate the slowness of evolution"}, {"option_text": "suggest companies today are poorly structured"}], "question": "The writer discusses the key element of emotion in order to"}, {"correct": 3, "options": [{"option_text": "Companies will remain in city centres"}, {"option_text": "Promotion will no longer motivate people"}, {"option_text": "Employees will be less independent than now"}, {"option_text": "Social interaction will remain important to workers"}], "question": "Which of the following does Nicholson predict will happen in the business world?"}, {"correct": 1, "options": [{"option_text": "How successful companies manage change"}, {"option_text": "Understanding the origins of workplace behavior"}, {"option_text": "Darwin''s theories rejected by modern management"}, {"option_text": "Why post-industrial organisations need to evolve more quickly"}], "question": "Which of the following is the most suitable title for Reading Passage 3?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. C — explain the theory of evolutionary psychology.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Evolutionary psychology revolves around the notion that our brains, like our bodies, have an inherited evolutionary design that has scarcely changed for 10,000 years.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngay trong đoạn văn đầu tiên, tác giả giới thiệu về một làn sóng ý tưởng mới gọi là tâm lý học tiến hóa và định nghĩa rõ bản chất của học thuyết này: bộ não của chúng ta có một thiết kế tiến hóa thừa kế từ tổ tiên và hầu như không thay đổi suốt 10,000 năm qua. Hành động này chính là để giải thích học thuyết tâm lý học tiến hóa là gì (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"348\">explain the theory of evolutionary psychology</strong>)</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. D — We inherit ideas and characteristics from our ancestors.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p id=\"p-rc_c7dee28e5eb2a2ef-20\" data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\"><span class=\"citation-99 citation-end-99\">“He points out that sophisticated research shows the brain actually houses a store of knowledge when we are born, and now genetic research is establishing there are certain genes that account for abilities, tastes and tendenci<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>es.”</em></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn 3, Nicholson bác bỏ quan điểm cho rằng tâm trí con người là một trang giấy trắng. Ông nhấn mạnh rằng khi sinh ra, não bộ đã chứa sẵn một kho tàng kiến thức từ trước và có những gen quy định năng lực, sở thích và xu hướng của chúng ta. Điều này trùng khớp hoàn toàn với việc chúng ta thừa hưởng các ý tưởng và đặc điểm từ tổ tiên (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"353\">inherit ideas and characteristics from our ancestors</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. B — explain attitudes and actions at work.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“We still use the emotional part of our minds to make sense other people’s behaviour and to create an impression, so we can often be taken in by appearances.”</em> và <em data-path-to-node=\"9,0,0\" data-index-in-node=\"188\">“This mental predisposition actually works best in small communities (the tribe), not in much larger environments filled with people we barely know (the modern workplace).”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa yếu tố cảm xúc (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"40\">emotion</em>) vào cuộc thảo luận nhằm làm rõ cách con người phản ứng, đánh giá người khác bằng trực giác và lý giải vì sao cơ chế tâm lý thời cổ đại này lại gây ra những hiểu lầm, sự thiếu tin tưởng bẩm sinh trong môi trường công sở hiện đại đầy rẫy những người xa lạ. Do đó, mục đích là để giải thích thái độ và hành động của con người khi làm việc (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"386\">explain attitudes and actions at work</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. D — Social interaction will remain important to workers.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“He doubts that the high-tech ideas of virtual companies will ever be very successful because people will still want to meet each other face-to-face.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở đoạn cuối, khi đưa ra dự báo về thế giới kinh doanh, Nicholson nghi ngờ mô hình công ty ảo (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"106\">virtual companies</em>) khó có thể thành công rực rỡ vì con người luôn có nhu cầu được gặp mặt trực tiếp (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"207\">meet each other face-to-face</em>). Gặp mặt trực tiếp chính là biểu hiện của việc tương tác xã hội vẫn giữ vai trò quan trọng đối với người lao động (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"352\">Social interaction will remain important to workers</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. B — Understanding the origins of workplace behavior.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“His book takes the reader on a journey from the Stone Age plains of the savannah to the modern office... It is an effective approach explaining why people behave as they do, particularly at work.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tiêu đề phù hợp nhất cho cả bài đọc phải phản ánh được nội dung xuyên suốt: dùng tâm lý học tiến hóa từ thời kỳ đồ đá để giải thích bản chất, nguồn gốc các hành vi và xung đột của con người nơi công sở ngày nay. Cụm từ \"Understanding the origins\" (Thấu hiểu nguồn gốc) bao quát hoàn chỉnh hành trình từ thời nguyên thủy đến văn phòng hiện đại.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d62e542b-87a5-42d8-a642-227dd04a1394', 'de836a66-7fc7-4723-afd8-b1d59632cad0', 'radio', 'Questions 32–35', NULL, '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
</div>
</div>
<div class="quests-list">
<div id="1094" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="317" data-numctn="6" data-count="6" data-quest="6">
<div class="tt-head"> </div>
</div>
</div>', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Nicholson makes a persuasive argument in his book."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Tooby and Cosmides believe natural selection through the generations has prepared our minds well for the mordern workplace."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Our reliance on technology causes emotional problems in the workplace."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "People today are more trusting than they used to be."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Câu 32: Nicholson makes a persuasive argument in his book.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 2, dòng 3-5: “…published <em data-path-to-node=\"4,1,0\" data-index-in-node=\"50\">Managing the Human Animal</em>. His book takes the reader on a journey… It is an <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"128\">effective approach</strong> explaining why people behave as they do…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài, tác giả nhận xét cuốn sách của Nicholson là một “effective approach” (cách tiếp cận hiệu quả). Từ “effective” đồng nghĩa với “persuasive” (có sức thuyết phục) trong ngữ cảnh này. Vì bài đọc xác nhận lập luận của ông ấy hiệu quả, đáp án là <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"262\">YES</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong>Câu 33: Tooby and Cosmides believe natural selection through the generations has prepared our minds well for the modern workplace.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 3, 3 dòng cuối: “As Tooby and Cosmides stress, there have <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"81\">not been enough generations</strong> for a brain that is <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"129\">well adapted to our post-industrial life</strong> to evolve through natural selection.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói rằng Tooby và Cosmides tin là chọn lọc tự nhiên đã chuẩn bị “tốt” (well prepared) cho bộ não chúng ta với môi trường làm việc hiện đại. Tuy nhiên, bài đọc khẳng định ngược lại: <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"201\">chưa có đủ thời gian (số thế hệ)</strong> để bộ não thích nghi tốt với cuộc sống hậu công nghiệp. Thông tin bị mâu thuẫn trực tiếp, nên đáp án là <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"338\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong>Câu 34: Our reliance on technology causes emotional problems in the workplace.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 4 đề cập đến “emotion” (cảm xúc), “predators” (thú săn mồi), và “techno defined business world” (thế giới kinh doanh định nghĩa bởi công nghệ).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói cảm xúc là cái “radar” giúp chúng ta định hướng trong thế giới công nghệ hiện nay. Tuy nhiên, <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"121\">không có thông tin nào</strong> khẳng định việc “phụ thuộc vào công nghệ” (reliance on technology) là <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"214\">nguyên nhân gây ra</strong> “các vấn đề về cảm xúc” (emotional problems). Bài chỉ nói thế giới kinh doanh coi trọng lý trí hơn cảm xúc, chứ không nói công nghệ gây ra bệnh tâm lý/cảm xúc. Vì vậy, đáp án là <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"411\">NOT GIVEN</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong>Câu 35: People today are more trusting than they used to be.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 4, dòng 10-12: “As a consequence, it takes very little to trigger people’s <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"98\">innate distrust of others</strong> because our safety in antiquity depended on supporting our near family…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng con người có sự “nghi ngờ bẩm sinh” (innate distrust) đối với người lạ do di truyền từ tổ tiên. Tuy nhiên, bài <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"140\">không hề so sánh</strong> mức độ tin tưởng của con người “ngày nay” so với “ngày xưa” (more trusting than they used to be). Chúng ta chỉ biết bản chất là hay nghi ngờ, còn việc mức độ đó tăng hay giảm theo thời gian thì không được nhắc tới. Đáp án là <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"382\">NOT GIVEN</strong>.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b5443018-9567-4071-b1a0-b8a12da70028', 'de836a66-7fc7-4723-afd8-b1d59632cad0', 'matching', 'Questions 36–40', NULL, '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the summary using the list of words, <strong>A–I</strong>,<strong> </strong>below.</p>
</div>
</div>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong>Nicholson’s advice to the corporate world</strong></span></p>\n<p>Nicholson believes that if we know why people act the way they do, we can change {H. business environments} so employees will work more efficiently. Nicholson’s ideas are unwelcome to {B. MBA graduates} but some executives are more open to what evolutionary psychology says. However, these executives still believe that there is a {E. magic formula} that will make employees act according to the company’s practices. According to Nicholson, these senior executives are engaging in {G. back-to-front thinking} and we should not try to change {I. human nature} but instead we should change our business structures.</p>", "answerOptions": [{"optionText": "A. business leaders"}, {"optionText": "B. MBA graduates"}, {"optionText": "C. promotion structures"}, {"optionText": "D. reward strategy"}, {"optionText": "E. magic formula"}, {"optionText": "F. strategic planning"}, {"optionText": "G. back-to-front thinking"}, {"optionText": "H. business environments"}, {"optionText": "I. human nature"}], "matchingItems": null}', 'null', '[{"content": "<h4 data-path-to-node=\"3\">Câu 36: …we can change {H. business environments}</h4>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 5, câu 2: “He thinks that by knowing the reasons for people’s behaviour it is possible to mould <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"119\">corporate environments</strong> into places…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài dùng từ “corporate environments” (môi trường doanh nghiệp). Từ này đồng nghĩa với phương án <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"114\">H. business environments</strong>. Nicholson tin rằng hiểu được hành vi sẽ giúp chúng ta nhào nặn/thay đổi môi trường làm việc tốt hơn.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"5\">Câu 37: …unwelcome to {B. MBA graduates}</h4>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 5, câu 4: “One group that resist the theory of evolutionary psychology is young <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"103\">MBA graduates</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “unwelcome” (không được chào đón/phản đối) trong đoạn tóm tắt tương ứng với từ “resist” (kháng cự/phản đối) trong bài đọc. Nhóm đối tượng được nhắc đích danh là các học viên cao học quản trị kinh doanh. Do đó, đáp án là <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"235\">B</strong>.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"7\">Câu 38: …believe that there is a {E. magic formula}</h4>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 5, câu 5: “Older and wiser executives point out that they still tend to cling to the idea of a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"118\">magic formula</strong> to bring people into line…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà điều hành (executives) kỳ cựu thường có xu hướng bám lấy (cling to) ý tưởng về một “công thức kỳ diệu” để bắt nhân viên tuân thủ chiến lược công ty. Cụm từ này khớp hoàn toàn với phương án <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"209\">E</strong>.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"9\">Câu 39: …engaging in {G. back-to-front thinking}</h4>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 5, câu 6: “But that is <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"46\">back-to-front thinking</strong> according to Nicholson…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nicholson nhận định cách tư duy của các nhà điều hành (muốn dùng công thức để thay đổi con người) là kiểu tư duy “ngược đời” hoặc “từ sau ra trước”. Đáp án là <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"171\">G</strong>.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"11\">Câu 40: …should not try to change {I. human nature}</h4>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Đoạn 5, câu 6 (vế cuối): “…who contends that we should be reinventing our business structures, not our fundamental <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"135\">human nature</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nicholson cho rằng chúng ta nên cải tổ cấu trúc kinh doanh chứ không phải thay đổi “bản chất con người”. Từ “fundamental human nature” trong bài khớp với phương án <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"176\">I</strong>.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('a1a24ed7-6690-4b3f-9a79-5aa1a481bfc4', '325bd595-0fc4-4c68-8cc4-6a408a3c4bb7', 'fillup', 'Questions 1–4', '<p>Complete the form below.</p>
