INSERT INTO public.questions VALUES ('4a9e0ba1-c74b-498e-8748-d577a64a5d2f', '784abe17-25a4-4988-bebd-1bbbba08ffff', 'matching', 'Questions 31–35', '', '<p data-start="845" data-end="906">Complete the summary using the list of words, <strong data-start="891" data-end="898">A–I</strong>, below.</p>
<p data-start="908" data-end="983">Write the correct letter, <strong data-start="934" data-end="941">A–I</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 14pt;\"><strong>The writers’ arguments against Field and Wroe’s analysis of the scientific data from Cuddie Springs</strong></span></p>\n<p data-start=\"1089\" data-end=\"1436\">One objection to Field and Wroe’s interpretation is the large quantity of charcoal, {B. stone} and artefacts found at Cuddie Springs. Such large numbers of artefacts would be impossible if the area had been covered with {F. water} for a period. There is also a complete lack of man-made structures, for instance those used for {D. cooking}.</p>\n<p data-start=\"1438\" data-end=\"1861\">Other evidence that casts doubt on Field and Wroe’s claim is the fact that while some material in the highest levels of sediment is 36,000 years old, the {C. sand} in the same levels is much more recent. The tools used to process plants and animals may also be newer than Field and Wroe believe. Further evidence against human occupation of the area is the absence of tools and {G. fossil bones} just a short distance away.</p>", "answerOptions": [{"optionText": "seeds"}, {"optionText": "stone"}, {"optionText": "sand"}, {"optionText": "cooking"}, {"optionText": "deep drill core"}, {"optionText": "water"}, {"optionText": "fossil bones"}, {"optionText": "sediment"}, {"optionText": "storage"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. B (stone)</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“The amount of anthropological evidence found at the site is remarkable: we estimate there are more than 3 tonnes of charcoal and more than 300 tonnes of stone buried there.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn tóm tắt liệt kê số lượng lớn của các vật liệu gồm than củi (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"77\">charcoal</em>), cổ vật (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"96\">artefacts</em>) và một chất còn thiếu. Đối chiếu với bài đọc, ba thứ có khối lượng khổng lồ tại đây là than củi (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"204\">charcoal</em>), công cụ đá (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"227\">stone</strong>) và cổ vật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. F (water)</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“This plethora of tools is hard to reconcile with a site that was only available for occupation when the lake was dry.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc lập luận số lượng công cụ khổng lồ này rất khó hợp lý hóa với một địa điểm mà con người chỉ có thể ở khi hồ bị khô cạn. Điều này nghĩa là việc có nhiều cổ vật như vậy là bất khả thi nếu khu vực này bị bao phủ bởi nước (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"239\">water / lake</strong>) trong một khoảng thời gian.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. D (cooking)</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“Furthermore, no cultural features such as oven pits have been discovered.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn tóm tắt nói về sự thiếu vắng các cấu trúc nhân tạo dùng cho mục đích gì đó. Bài đọc chỉ ra không tìm thấy các đặc điểm văn hóa như hố lò/hố lò nướng (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"167\">oven pits</em>). Tiện ích của hố lò nướng chính là dùng để nấu nướng (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"232\">cooking</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. C (sand)</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“Second, sand in the two upper levels is considerably younger than charcoal from the same levels.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong khi than củi ở tầng trên cùng có tuổi đời 36,000 năm, thì hạt cát (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"85\">sand</strong>) ở cùng các tầng này lại có tuổi đời trẻ hơn/gần đây hơn rất nhiều (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"158\">considerably younger / much more recent</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. G (fossil bones)</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“Also of interest is the fact that a deep drill core made a mere 60 metres from the site recovered no stone artefacts or fossil bones whatsoever.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở một khoảng cách ngắn cách đó (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"44\">a short distance away / 60 metres</em>), việc khoan sâu trích mẫu đã không thu lại được bất kỳ công cụ đá hay xương hóa thạch (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"166\">fossil bones</strong>) nào.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('7a3ad52b-f36f-42ee-aab0-ed11c6adb9c6', '2f7de8da-a469-418d-a7d4-9a16517adeca', 'matrix', 'Questions 27–30', '', '<p data-start="71" data-end="122">Which paragraph contains the following information?</p>
<p data-start="124" data-end="199">Write the correct letter, <strong data-start="150" data-end="157">A–H</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a comparison between people''s preferences towards language and art", "correctCategoryLetter": ""}, {"itemText": "why people may have misunderstood how a certain animal moves", "correctCategoryLetter": ""}, {"itemText": "a contrast between the techniques used in two pictures", "correctCategoryLetter": ""}, {"itemText": "a possible negative effect of using the term ‘art’", "correctCategoryLetter": ""}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. F — a comparison between people''s preferences towards language and art</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Just as some of us would rather people use few words and gestures and leave something to be guessed, so some of us would rather look at paintings or sculptures which are open to interpretation.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F đưa ra một phép so sánh tương đồng (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"55\">Just as..., so...</em>): cũng giống như một số người thích người khác sử dụng ít ngôn từ/cử chỉ (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"147\">few words and gestures</em> - ngôn ngữ) để tự đoán, thì một số người cũng thích ngắm nhìn những bức tranh hoặc bức tượng mở ra nhiều cách hiểu (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"286\">open to interpretation</em> - nghệ thuật).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. H — why people may have misunderstood how a certain animal moves</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“For generations, paintings showed horses galloping with outstretched legs in full flight through the air, and we came to believe that this was indeed how they moved.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn H giải thích lý do vì sao mọi người bị hiểu lầm về cách loài ngựa di chuyển: đó là do trong nhiều thế hệ, các bức tranh luôn vẽ ngựa phi nước đại với đôi chân duỗi thẳng trên không, khiến người xem tin rằng đó là cách chúng chuyển động ngoài đời thực cho đến khi nhiếp ảnh ra đời chứng minh điều ngược lại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. G — a contrast between the techniques used in two pictures</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“But who would say that Rembrandt''s drawing of an elephant is necessarily less good because it shows fewer details? Indeed Rembrandt gave us the feel of the elephant''s wrinkly skin with just a few lines of his chalk.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn G tạo ra một sự tương phản rõ rệt giữa hai kỹ thuật vẽ: một bên là Dürer với bức vẽ con thỏ rừng cực kỳ tỉ mỉ, ghi lại từng chi tiết nhỏ nhất (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"160\">every tiny detail is carefully recorded</em>), và một bên là Rembrandt vẽ con voi bằng kỹ thuật tối giản, ít chi tiết hơn nhưng vẫn tạo ra cảm giác chân thực chỉ bằng vài đường phấn (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"338\">just a few lines of his chalk</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. A — a possible negative effect of using the term ‘art’</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“You may crush an artist by telling him that what he has just done may be quite good in its own way, only it is not true art.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A chỉ ra một tác động tiêu cực (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"49\">negative effect</em>) khi chúng ta sử dụng từ \"nghệ thuật\" (viết hoa chữ cái đầu thành một nỗi ám ảnh) là bạn có thể hủy hoại, đè bẹp một người nghệ sĩ (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"197\">crush an artist</em>) bằng cách phán xét rằng tác phẩm của họ không phải là nghệ thuật chân chính (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"291\">not true art</em>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d826ab36-fe02-4a83-80f6-9f8f0ec740a0', '325bd595-0fc4-4c68-8cc4-6a408a3c4bb7', 'fillup', 'Questions 5–10', '<p data-start="490" data-end="519">Complete the table below.</p>
<p data-start="521" data-end="570">Write <strong>NO MORE THAN TWO WORDS</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.999%; height: 174.609px; border: 1px solid #000000;" border="1"><colgroup><col style="width: 33.3032%;"><col style="width: 33.3032%;"><col style="width: 33.3032%;"></colgroup>
<tbody>
<tr style="height: 40.1562px;">
<td style="text-align: center; border-color: #000000;" colspan="3"><span style="font-size: 14pt;"><strong>Photography competitions</strong></span></td>
</tr>
<tr style="height: 33.6133px;">
<td style="border-color: #000000; text-align: center;"><strong>Title of competition</strong></td>
<td style="border-color: #000000; text-align: center;"><strong>Instructions</strong></td>
<td style="border-color: #000000; text-align: center;"><strong>Feedback to Dan</strong></td>
</tr>
<tr style="height: 33.6133px;">
<td style="border-color: #000000;">{Domestic Life}</td>
<td style="border-color: #000000;">A scene in the home</td>
<td style="border-color: #000000;">The picture’s composition was not good.</td>
</tr>
<tr style="height: 33.6133px;">
<td style="border-color: #000000;">‘Beautiful Sunsets’</td>
<td style="border-color: #000000;">Scene must show some {clouds}</td>
<td style="border-color: #000000;">The {timing} was wrong.</td>
</tr>
<tr style="height: 33.6133px;">
<td style="border-color: #000000;">{Animal Magic}</td>
<td style="border-color: #000000;">Scene must show {movement| animal movement}</td>
<td style="border-color: #000000;">The photograph was too {dark}.</td>
</tr>
</tbody>
</table>
<p data-start="521" data-end="570"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('bd91ad86-e59a-4a13-89da-c3e35f5c16c9', '9bb9d3cd-623d-4475-b2c2-f63014599a36', 'checkbox', 'Questions 11 and 12', '', '<p data-start="54" data-end="82">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="84" data-end="145">Which <strong>TWO </strong>warnings does Dan give about picking mushrooms?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "Don’t pick more than one variety of mushroom at a time."}, {"correct": true, "option_text": "Don’t pick mushrooms near busy roads"}, {"correct": true, "option_text": "Don’t eat mushrooms given to you"}, {"correct": false, "option_text": "Don’t eat mushrooms while picking them"}, {"correct": false, "option_text": "Don’t pick old mushrooms"}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('1a28c5b0-0d57-43cc-a373-732a86df58e0', '9bb9d3cd-623d-4475-b2c2-f63014599a36', 'checkbox', 'Questions 13 and 14', '', '<p data-start="395" data-end="423">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="425" data-end="491">Which <strong>TWO </strong>ideas about wild mushrooms does Dan say are correct?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "Mushrooms should always be peeled before eating"}, {"correct": true, "option_text": "Mushrooms eaten by animals may be unsafe"}, {"correct": false, "option_text": "Cooking destroys toxins in mushrooms"}, {"correct": true, "option_text": "Brightly coloured mushrooms can be edible"}, {"correct": false, "option_text": "All poisonous mushrooms have a bad smell"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('04012ade-424d-42b2-aedb-8cb02837323e', '9bb9d3cd-623d-4475-b2c2-f63014599a36', 'radio', 'Questions 15–20', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. Choose wooded areas"}, {"option_text": "B. Don’t disturb wildlife"}, {"option_text": "C. Get there early"}], "question": "What advice does Dan give about picking mushrooms in parks?"}, {"correct": 1, "options": [{"option_text": "A. use a mushroom app"}, {"option_text": "B. join a group"}, {"option_text": "C. take a reference book"}], "question": "Dan says it is a good idea for beginners to"}, {"correct": 1, "options": [{"option_text": "A. selecting only fully grown mushrooms"}, {"option_text": "B. picking a limited amount of mushrooms"}, {"option_text": "C. avoiding areas where rare mushroom species grow"}], "question": "What does Dan say is important for conservation?"}, {"correct": 2, "options": [{"option_text": "A. a huge demand for them from restaurants"}, {"option_text": "B. a lack of rain in this part of the country"}, {"option_text": "C. a rise in building developments locally"}], "question": "According to Dan, some varieties of wild mushrooms are in decline because there is"}, {"correct": 0, "options": [{"option_text": "A. keep them in the fridge for no more than two days"}, {"option_text": "B. keep them in a brown bag in a dark room"}, {"option_text": "C. leave them for a period after washing them"}], "question": "Dan says that when storing mushrooms, people should"}, {"correct": 0, "options": [{"option_text": "A. Experiment with different recipes"}, {"option_text": "B. Expect some to have a strong taste"}, {"option_text": "C. Cook them for a long time"}], "question": "What does Dan say about trying new varieties of mushrooms?"}]', 'null', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('70ec9492-abfe-4cac-9ea4-25bfd83011ac', 'c1d994c3-f090-4530-add8-9cfe3a340b2d', 'matching', 'Questions 25–30', '', '<p data-start="693" data-end="764">What comment do the students make about each of the following jobs?</p>
<p data-start="766" data-end="861">Choose <strong>SIX</strong> answers from the box and write the correct letter, <strong>A</strong>–<strong>G</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<h3 data-section-id=\"ynj14i\" data-start=\"1296\" data-end=\"1304\">Jobs</h3>\n<p data-start=\"1306\" data-end=\"1336\"><strong data-start=\"1306\" data-end=\"1325\">25. Accountants</strong> {G. Both employment and productivity have risen}</p>\n<p data-start=\"1338\" data-end=\"1369\"><strong data-start=\"1338\" data-end=\"1358\">26. Hairdressers</strong> {E. Higher disposable income has led to a huge increase in jobs}</p>\n<p data-start=\"1371\" data-end=\"1410\"><strong data-start=\"1371\" data-end=\"1399\">27. Administrative staff</strong> {A. These jobs are likely to be at risk}</p>\n<p data-start=\"1412\" data-end=\"1451\"><strong data-start=\"1412\" data-end=\"1440\">28. Agricultural workers</strong> {C. The number of people working in this sector has fallen dramatically}</p>\n<p data-start=\"1453\" data-end=\"1484\"><strong data-start=\"1453\" data-end=\"1473\">29. Care workers</strong> {F. There is likely to be a significant rise in demand for this service}</p>\n<p data-start=\"1486\" data-end=\"1516\" data-is-last-node=\"\" data-is-only-node=\"\"><strong data-start=\"1486\" data-end=\"1505\">30. Bank clerks</strong> {A. These jobs are likely to be at risk}</p>", "answerOptions": [{"optionText": "A. These jobs are likely to be at risk"}, {"optionText": "B. Their role has become more interesting in recent years"}, {"optionText": "C. The number of people working in this sector has fallen dramatically"}, {"optionText": "D. This job will require more qualifications"}, {"optionText": "E. Higher disposable income has led to a huge increase in jobs"}, {"optionText": "F. There is likely to be a significant rise in demand for this service"}, {"optionText": "G. Both employment and productivity have risen"}], "matchingItems": []}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('6b927125-e521-4d74-9886-a441e7bb71f5', 'b5eb756c-7cb7-4dad-b1bf-633f7bceeb61', 'fillup', 'Questions 31–40', '<div class="text-base my-auto mx-auto [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn">
<div class="flex max-w-full flex-col gap-4 grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal outline-none keyboard-focused:focus-ring [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="e999c604-b2d5-49aa-9f53-732b6e019312" data-message-model-slug="gpt-5-5">
<div class="flex w-full flex-col gap-1 empty:hidden">
<div class="markdown prose dark:prose-invert wrap-break-word w-full light markdown-new-styling">
<p data-section-id="1i6hwlk" data-start="29" data-end="58">Complete the notes below.</p>
<p data-start="60" data-end="100">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p data-section-id="18t7yl8" data-start="102" data-end="128"><span style="font-size: 14pt;"><strong>Space Traffic Management</strong></span></p>
<p data-section-id="1o071aw" data-start="130" data-end="167"><strong>A Space Traffic Management system</strong></p>
<ul data-start="169" data-end="370">
<li data-section-id="1ui7xk5" data-start="169" data-end="254">is a concept similar to Air Traffic Control, but for satellites rather than planes.</li>
<li data-section-id="1tsph5y" data-start="255" data-end="332">would aim to set up legal and {technical} ways of improving safety.</li>
<li data-section-id="53fwxk" data-start="333" data-end="370">does not actually exist at present.</li>
</ul>
<p data-section-id="msza7j" data-start="372" data-end="433"><strong>Problems in developing effective Space Traffic Management</strong></p>
<ul data-start="435" data-end="1095">
<li data-section-id="1g765om" data-start="435" data-end="589">Satellites are now quite {cheap} and therefore more widespread (e.g. there are constellations made up of {thousands} of satellites).</li>
<li data-section-id="3d5dhi" data-start="590" data-end="695">At present, satellites are not required to transmit information to help with their {identification}.</li>
<li data-section-id="p5kxm1" data-start="696" data-end="755">There are few systems for {tracking} satellites.</li>
<li data-section-id="1gcm7at" data-start="756" data-end="810">Small pieces of debris may be difficult to identify.</li>
<li data-section-id="179nce0" data-start="811" data-end="922">Operators may be unwilling to share details of satellites used for {military} or commercial reasons.</li>
<li data-section-id="175h2" data-start="923" data-end="1011">It may be hard to collect details of the object''s {location} at a given time.</li>
<li data-section-id="1n35yc9" data-start="1012" data-end="1095">Scientists can only make a {prediction} about where the satellite will go.</li>
</ul>
<strong>Solutions</strong>
<ul data-start="1112" data-end="1336" data-is-last-node="" data-is-only-node="">
<li data-section-id="hxi9ql" data-start="1112" data-end="1187">Common standards should be agreed on for the presentation of information.</li>
<li data-section-id="47msup" data-start="1188" data-end="1252">The information should be combined in one {database}.</li>
<li data-section-id="q24q9r" data-start="1253" data-end="1336" data-is-last-node="">A coordinated system must be designed to create {trust} in its users.</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('a596a767-7682-457e-9892-af0825f88967', '4eeb856a-ca65-42d1-8b38-9ed76fcc9e10', 'fillup', 'Questions 9–13', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes <strong>9–13</strong> on your answer sheet. </p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="text-align: center; padding: 2px; border-color: #000000;">
<p style="text-align: left;"><span style="font-size: 14pt;"><strong> Fund-raising campaigns</strong></span></p>
<p style="text-align: left;"><strong>The first modern appeals</strong></p>
<ul>
<li style="text-align: left;">
<p>an appeal was made in the 1960s to help build the Student Union buildings</p>
</li>
<li style="text-align: left;">
<p>Henry Cooper’s campaign marked the {centenary} of the University</p>
</li>
<li style="text-align: left;">
<p>modern campaigns have focused on raising money from businesses and individuals</p>
</li>
</ul>
<p style="text-align: left;"><strong>‘Leading the Way’</strong></p>
<ul>
<li style="text-align: left;">
<p>this appeal is raising money to invest in the University’s {staff}</p>
</li>
<li style="text-align: left;">
<p>gifts are being sought from graduates who are located {overseas}</p>
</li>
<li style="text-align: left;">
<p>John Taylor believes research at the University helps the whole country</p>
</li>
</ul>
<p style="text-align: left;"><strong>Financial matters</strong></p>
<ul>
<li style="text-align: left;">
<p>some donations had not been {recorded} by the University</p>
</li>
<li style="text-align: left;">
<p>there is a new financial {target} for the campaign </p>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p style="text-align: left;"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">9. centenary — {Henry Cooper’s campaign marked the centenary of the University}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“This was followed by another appeal in 1983 under the then Chancellor Henry Cooper, who raised $800,000 <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"125\">to celebrate the University’s centenary</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Marked\" (đánh dấu) đồng nghĩa với \"to celebrate\" (kỷ niệm/chúc mừng). Chiến dịch của Henry Cooper được tổ chức để kỷ niệm 100 năm ngày thành lập trường (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"166\">centenary</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">10. staff — {this appeal is raising money to invest in the University’s staff}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“It is intended as a drive to secure support for the whole University, with a <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"98\">focus on generating funds to recruit, support and retain the very best staff</strong> for the University.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Invest in\" (đầu tư vào) tương ứng với hành động cấp vốn để tuyển dụng, hỗ trợ và giữ chân (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"104\">recruit, support and retain</em>). Đối tượng được đầu tư ở đây chính là đội ngũ nhân sự/giảng viên (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"199\">staff</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">11. overseas — {gifts are being sought from graduates who are located overseas}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“...and targeting <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"38\">alumni, or former students now living overseas</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Graduates\" (những người đã tốt nghiệp) đồng nghĩa với từ \"alumni\" hoặc \"former students\" (cựu sinh viên). Những người này hiện đang sinh sống ở nước ngoài (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"169\">overseas</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">12. recorded — {some donations had not been recorded by the University}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“...we have come to realise that there has been <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"68\">considerable giving to the University that has not been previously recorded</strong> through our Advancement Office...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Donations\" (khoản quyên góp) tương ứng với từ \"giving\". Bài đọc chỉ ra lỗi sai là có nhiều khoản đóng góp trước đó chưa từng được ghi nhận lại (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"157\">recorded</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">13. target — {there is a new financial target for the campaign}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"20\">“The good news from this error is that... it was announced that <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"84\">the campaign target was now being increased from $100 million to $150 million</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Financial\" (thuộc về tài chính/tiền bạc) được thể hiện qua con số cụ thể từ 100 triệu lên 150 triệu đô-la. Việc tăng số tiền này đồng nghĩa với việc chiến dịch đã đặt ra một mục tiêu (<strong data-path-to-node=\"18,1,0\" data-index-in-node=\"197\">target</strong>) tài chính mới.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('21a67d52-4f86-46a1-afcc-199c831ad1ab', '2796ed0b-ef22-4a02-a8be-9415f27180d1', 'fillup', 'Questions 14–19', '<p><span class="fontstyle0">Complete the flow-chart below.</span></p>
<p><span class="fontstyle0">Write </span><span class="fontstyle2"><strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> </span><span class="fontstyle0">from the passage for each answer.</span></p>
<p><span class="fontstyle0">Write your answers in boxes 14-19 on your answer sheet.</span> </p>
<p style="text-align: center;"><strong><span style="font-size: 14pt;"><span class="fontstyle0">Step-by-step guide to making Flynn’s water filters</span> </span></strong></p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Make the mixture for the filter from organic material (e.g., tea, coffee, rice), {clay} and {water}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Shape into pots and place them in a fire made from {straw} and {cow manure}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9582%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8745%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Fuel the fire to reach a maximum temperature of {950 degrees}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9582%; height: 2px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8745%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Remove the filters from the fire.</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;">🔽</p>
<table style="border-collapse: collapse; width: 99.9582%; height: 33.7083px; border-spacing: 2px; margin-left: auto; margin-right: auto; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8745%;"></colgroup>
<tbody>
<tr style="height: 33.7083px;">
<td style="padding: 2px; border-color: #000000;">
<p style="text-align: center;">Bake the filters in the fire for a maximum period of {60 minutes}</p>
</td>
</tr>
</tbody>
</table>
<p style="text-align: center;"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14 &amp; 15. clay — water — {Make the mixture for the filter from organic material (e.g., tea, coffee, rice), clay and water}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Take a handful of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"39\">clay</strong>, mix it with a handful of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"70\">organic material</strong> such as used tea leaves, coffee grounds or rice hulls, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"142\">add water</strong> in a sufficient quantity to make a stiff mixture...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để làm ra hỗn hợp làm bộ lọc, bài đọc hướng dẫn lấy một nắm đất sét (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"81\">clay</strong>), trộn với một nắm nguyên liệu hữu cơ (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"125\">organic material</em> như trà, cà phê, vỏ trấu) và thêm nước (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"182\">water</strong>). Do đó hai từ cần điền ở đây là <em data-path-to-node=\"5,1,0\" data-index-in-node=\"221\">clay</em> và <em data-path-to-node=\"5,1,0\" data-index-in-node=\"229\">water</em>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16 &amp; 17. straw — cow manure — {Shape into pots and place them in a fire made from straw and cow manure}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“...Next, surround the pots with <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"53\">straw</strong>, put them in a mound of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"83\">cow manure</strong>, light the straw and then top up the burning manure as required.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi nặn thành các chậu gốm, bước tiếp theo là bao bọc chúng bằng rơm (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"86\">straw</strong>), đặt vào một đống phân bò (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"120\">cow manure</strong>) rồi đốt rơm để mồi lửa. Lửa này được tạo ra từ hai chất liệu là <em data-path-to-node=\"7,1,0\" data-index-in-node=\"196\">straw</em> và <em data-path-to-node=\"7,1,0\" data-index-in-node=\"205\">cow manure</em>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">18. 950 degrees — {Fuel the fire to reach a maximum temperature of 950 degrees}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“...as the fuel can reach a temperature of 700 degrees in half an hour, and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"96\">will be up to 950 degrees after another 20 to 30 minutes</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"up to\" trong bài đọc đồng nghĩa với từ \"maximum\" (tối đa). Đống lửa sau khi cháy thêm một thời gian sẽ đạt đến nhiệt độ tối đa là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"150\">950 degrees</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">19. 60 minutes — {Bake the filters in the fire for a maximum period of 60 minutes}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The filters are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"37\">finished in 45 to 60 minutes</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Quá trình nung bánh/lọc này sẽ hoàn thành (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"55\">finished</em>) trong khoảng từ 45 đến 60 phút. Vì đề bài dùng chữ \"maximum period\" (thời gian tối đa) nên con số lớn nhất cần điền chính là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"190\">60 minutes</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('37867edc-86ff-42aa-bee1-eeff60854c9f', '2796ed0b-ef22-4a02-a8be-9415f27180d1', 'radio', 'Questions 20–23', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information,<strong>FALSE</strong> if the statement contradicts the information,<strong>NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The clay in the Manatuto project was initially unsuitable for the purpose of the project."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Coffee grounds produce filters that are twice as efficient as those using other organic materials."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It takes half an hour for a cow manure fire to reach 950 degrees."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "E. coli is the most difficult bacterium to remove from water by filtration"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">20. TRUE — {The clay in the Manatuto project was initially unsuitable for the purpose of the project.}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">“A charity operating there wanted to help set up a small industrial site manufacturing water filters, but <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"126\">initial research found the local clay to be too fine — a problem solved by the addition of organic material</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dự án ban đầu muốn dùng đất sét địa phương để làm bộ lọc, nhưng nghiên cứu ban đầu thấy đất sét này bị <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"115\">quá mịn (too fine)</strong> và đây là một <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"148\">vấn đề (problem)</strong> cần giải quyết bằng cách trộn thêm chất hữu cơ. Điều này đồng nghĩa với việc ban đầu (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"251\">initially</em>) loại đất sét này chưa phù hợp/chưa dùng ngay được (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"313\">unsuitable</strong>) cho mục đích của dự án.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">21. NOT GIVEN — {Coffee grounds produce filters that are twice as efficient as those using other organic materials.}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“According to Flynn, <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"41\">used coffee grounds have given the best results to date</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ khẳng định bã cà phê cho kết quả tốt nhất từ trước đến nay (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"84\">the best results</em>). Tuy nhiên, bài viết <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"123\">không hề đưa ra số liệu so sánh cụ thể</strong> xem nó hiệu quả gấp đôi (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"187\">twice as efficient</strong>) hay gấp mấy lần so với các nguyên liệu hữu cơ khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">22. FALSE — {It takes half an hour for a cow manure fire to reach 950 degrees.}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“...as the fuel <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"36\">can reach a temperature of 700 degrees in half an hour</strong>, and <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"96\">will be up to 950 degrees after another 20 to 30 minutes</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Theo bài đọc, đống lửa phân bò mất <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"47\">nửa tiếng (half an hour) để đạt 700 độ</strong>, và phải mất <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"99\">thêm 20 đến 30 phút nữa (another 20 to 30 minutes)</strong> thì mới lên được 950 độ. Câu hỏi nói chỉ mất nửa tiếng để đạt 950 độ là sai lệch mốc thời gian của bài (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"254\">FALSE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">23. NOT GIVEN — {E. coli is the most difficult bacterium to remove from water by filtration.}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“Tests with the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"36\">deadly E. coli bacterium</strong> have seen the filters remove 96.4 to 99.8 per cent of the pathogen...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến vi khuẩn E. coli là một loại vi khuẩn chết người (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"82\">deadly</em>) và bộ lọc có thể loại bỏ tới 99.8% loại khuẩn này. Tuy nhiên, bài đọc <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"160\">không hề có sự so sánh</strong> xem E. coli có phải là loại vi khuẩn cứng đầu/khó loại bỏ nhất (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"247\">the most difficult</strong>) bằng phương pháp lọc hay không.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('352aefb9-a587-4e7a-aad8-c259c13640c9', '2796ed0b-ef22-4a02-a8be-9415f27180d1', 'radio', 'Questions 24—26', '', '<p><span class="fontstyle0">Choose the correct letter, </span><strong><span class="fontstyle2">A</span></strong><span class="fontstyle0">, </span><strong><span class="fontstyle2">B</span></strong><span class="fontstyle0">, </span><strong><span class="fontstyle2">C </span></strong><span class="fontstyle0">or </span><strong><span class="fontstyle2">D</span></strong><span class="fontstyle0">.</span></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A charitable trust"}, {"option_text": "B filtration experiment."}, {"option_text": "C water filter factory."}, {"option_text": "D community kiln."}], "question": "The Manatuto project aimed to set up a"}, {"correct": 1, "options": [{"option_text": "A remove all dangerous pathogens"}, {"option_text": "B be a particular thickness"}, {"option_text": "C filter water as quickly as possible"}, {"option_text": "D be made from 100 per cent clay."}], "question": "To be effective, the Flynn filters must"}, {"correct": 0, "options": [{"option_text": "A wants it to be freely available"}, {"option_text": "B has produced a very simple design."}, {"option_text": "C cannot make a profit in poor countries."}, {"option_text": "D has already given the idea to a charity."}], "question": "Flynn does not intend to patent his filter because he"}]', 'null', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('3ac32b68-f29a-4357-98b9-c28740ec93e9', 'd4442ed6-70fd-4868-b9fe-1e6e77dd3530', 'radio', 'Questions 27–30', '', '<p>Choose <strong data-start="155" data-end="162">YES</strong> if the statement agrees with the claims of the writer, <strong data-start="218" data-end="224">NO</strong> if the statement contradicts the claims of the writer, <strong data-start="280" data-end="293">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Field and Wroe argue that findings at the Cuddie Springs site show that people lived in this area at the same time as megafauna"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Field and Wroe believe it is likely that smaller megafauna species survived the last Ice Age"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The writers believe that the dating of earth up to 1.7 m below the present surface at Cuddie Springs is unreliable"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Some artefacts found at Cuddie Springs were preserved well enough to reveal their function"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. YES</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Drs Judith Field and Stephen Wroe of the University of Sydney, who excavated the site, claim that it provides unequivocal evidence of a long overlap of humans and megafauna...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Field và Wroe lập luận rằng các phát hiện tại Cuddie Springs cho thấy con người và đại động vật sống cùng thời kỳ (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"139\">at the same time</em>). Điều này trùng khớp hoàn toàn với cụm \"unequivocal evidence of a long overlap of humans and megafauna\" (bằng chứng rõ ràng về một sự chồng chéo/giao thoa thời gian dài giữa người và đại động vật) trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“...and conclude that aridity leading up to the last Ice Age brought about their eventual demise.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu thông tin là Field và Wroe kết luận rằng sự khô hạn dẫn tới Kỷ băng hà cuối cùng đã gây ra sự tuyệt chủng (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"135\">demise</em>) của đại động vật nói chung, chứ <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"175\">hoàn toàn không đề cập</strong> hay phân loại xem các loài đại động vật có kích thước nhỏ hơn (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"261\">smaller megafauna species</em>) có sống sót qua Kỷ băng hà hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. NO</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“The dating of these layers is accurate: ages for the sediments were obtained through radiocarbon dating of charcoal fragments and luminescence dating of sand grains from the same levels...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định các tác giả bài viết (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"53\">the writers</em>) tin rằng việc đo niên đại của các lớp đất sâu đến 1.7m là không đáng tin cậy (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"144\">unreliable</em>). Tuy nhiên, ngay đầu đoạn 3, tác giả lại khẳng định điều ngược lại: \"The dating of these layers is accurate\" (Việc đo niên đại của các lớp này là chính xác). Vì thông tin mâu thuẫn trực tiếp nên đáp án là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"361\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. YES</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“Intriguingly, some of the stone tools show surface features indicating their use for processing plants, and a few even have well-preserved blood and hair residues suggesting they were used in butchering animals.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói một số cổ vật được bảo quản đủ tốt để tiết lộ chức năng của chúng (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"91\">reveal their function</em>). Bài đọc viết một số công cụ đá có các đặc điểm bề mặt biểu thị chúng dùng để chế biến thực vật (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"211\">processing plants</em>) và một số vẫn lưu lại dấu vết máu và lông (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"273\">blood and hair residues</em>) chứng minh dùng để xẻ thịt động vật (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"335\">butchering animals</em>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7ee55c02-1e5b-458d-8653-f8761141f033', 'd4442ed6-70fd-4868-b9fe-1e6e77dd3530', 'matching', 'Questions 31–35', '', '<p data-start="845" data-end="906">Complete the summary using the list of words, <strong data-start="891" data-end="898">A–I</strong>, below.</p>
<p data-start="908" data-end="983">Write the correct letter, <strong data-start="934" data-end="941">A–I</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 14pt;\"><strong>The writers’ arguments against Field and Wroe’s analysis of the scientific data from Cuddie Springs</strong></span></p>\n<p data-start=\"1089\" data-end=\"1436\">One objection to Field and Wroe’s interpretation is the large quantity of charcoal, {B. stone} and artefacts found at Cuddie Springs. Such large numbers of artefacts would be impossible if the area had been covered with {F. water} for a period. There is also a complete lack of man-made structures, for instance those used for {D. cooking}.</p>\n<p data-start=\"1438\" data-end=\"1861\">Other evidence that casts doubt on Field and Wroe’s claim is the fact that while some material in the highest levels of sediment is 36,000 years old, the {C. sand} in the same levels is much more recent. The tools used to process plants and animals may also be newer than Field and Wroe believe. Further evidence against human occupation of the area is the absence of tools and {G. fossil bones} just a short distance away.</p>", "answerOptions": [{"optionText": "A seeds"}, {"optionText": "B stone"}, {"optionText": "C sand"}, {"optionText": "D cooking"}, {"optionText": "E deep drill core"}, {"optionText": "F water"}, {"optionText": "G fossil bones"}, {"optionText": "H sediment"}, {"optionText": "I storage"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. B (stone)</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“The amount of anthropological evidence found at the site is remarkable: we estimate there are more than 3 tonnes of charcoal and more than 300 tonnes of stone buried there.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn tóm tắt liệt kê số lượng lớn của các vật liệu gồm than củi (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"77\">charcoal</em>), cổ vật (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"96\">artefacts</em>) và một chất còn thiếu. Đối chiếu với bài đọc, ba thứ có khối lượng khổng lồ tại đây là than củi (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"204\">charcoal</em>), công cụ đá (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"227\">stone</strong>) và cổ vật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. F (water)</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“This plethora of tools is hard to reconcile with a site that was only available for occupation when the lake was dry.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc lập luận số lượng công cụ khổng lồ này rất khó hợp lý hóa với một địa điểm mà con người chỉ có thể ở khi hồ bị khô cạn. Điều này nghĩa là việc có nhiều cổ vật như vậy là bất khả thi nếu khu vực này bị bao phủ bởi nước (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"239\">water / lake</strong>) trong một khoảng thời gian.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. D (cooking)</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“Furthermore, no cultural features such as oven pits have been discovered.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn tóm tắt nói về sự thiếu vắng các cấu trúc nhân tạo dùng cho mục đích gì đó. Bài đọc chỉ ra không tìm thấy các đặc điểm văn hóa như hố lò/hố lò nướng (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"167\">oven pits</em>). Tiện ích của hố lò nướng chính là dùng để nấu nướng (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"232\">cooking</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. C (sand)</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“Second, sand in the two upper levels is considerably younger than charcoal from the same levels.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong khi than củi ở tầng trên cùng có tuổi đời 36,000 năm, thì hạt cát (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"85\">sand</strong>) ở cùng các tầng này lại có tuổi đời trẻ hơn/gần đây hơn rất nhiều (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"158\">considerably younger / much more recent</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. G (fossil bones)</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“Also of interest is the fact that a deep drill core made a mere 60 metres from the site recovered no stone artefacts or fossil bones whatsoever.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở một khoảng cách ngắn cách đó (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"44\">a short distance away / 60 metres</em>), việc khoan sâu trích mẫu đã không thu lại được bất kỳ công cụ đá hay xương hóa thạch (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"166\">fossil bones</strong>) nào.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b123183a-b0e1-46bf-b0f1-bf3f8e2ebb16', 'd4442ed6-70fd-4868-b9fe-1e6e77dd3530', 'radio', 'Questions 36–40', '', '<p data-start="2019" data-end="2063">Choose the correct letter, <strong data-start="2046" data-end="2062">A, B, C or D</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. The different layers of sediment have been mixed over time"}, {"option_text": "B. The sand evidence is unhelpful and should be disregarded"}, {"option_text": "C. The area needs to be re-examined when technology improves"}, {"option_text": "D. The charcoal found in the area cannot be dated"}], "question": "What conclusions did the writers reach about the inconsistencies in the data from Cuddie Springs?"}, {"correct": 1, "options": [{"option_text": "A. Floods could have caused the death of the megafauna"}, {"option_text": "B. Floods could have disturbed the archaeological evidence"}, {"option_text": "C. Bushfires could have prevented humans from settling in the area for any length of time"}, {"option_text": "D. Bushfires could have destroyed much of the evidence left by megafauna and humans"}], "question": "According to the writers, what impact could a natural phenomenon have had on this site?"}, {"correct": 3, "options": [{"option_text": "A. They bred cattle whose bones could have been confused with megafauna"}, {"option_text": "B. They found that the soil was too waterlogged for farming"}, {"option_text": "C. They allowed cattle to move around freely at the site"}, {"option_text": "D. They brought stones there from another area"}], "question": "What did the writers speculate about the people who lived at this site in 1876?"}, {"correct": 1, "options": [{"option_text": "A. A rapid change in climate may have been responsible for the extinction of the megafauna"}, {"option_text": "B. Megafauna could have died out as a result of small numbers being killed year after year"}, {"option_text": "C. The population of humans at that time was probably insufficient to cause the extinction of the megafauna"}, {"option_text": "D. The extinction of ancient animals should not be compared to that of modern-day species"}], "question": "In the final paragraph, what suggestion do the writers make about Australia’s megafauna?"}, {"correct": 3, "options": [{"option_text": "A. Their methods were not well thought out"}, {"option_text": "B. The excavations did not go deep enough"}, {"option_text": "C. Their technology failed to obtain precise data"}, {"option_text": "D. Their conclusions were based on inconsistent data"}], "question": "Which of the following best represents the writers’ criticism of Field and Wroe?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">36. A — The different layers of sediment have been mixed over time.</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"27,0,0\" data-index-in-node=\"26\">“These points suggest strongly that the sediments have been moved about and some of the old charcoal has been re-deposited in younger layers.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ những điểm bất nhất về tuổi thọ giữa cát và than củi, tác giả kết luận rằng các lớp trầm tích đã bị dịch chuyển qua lại (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"136\">moved about</em>) và tái tích tụ lại, tức là chúng đã bị trộn lẫn vào nhau theo thời gian (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"222\">mixed over time</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">37. B — Floods could have disturbed the archaeological evidence.</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“Flood events more likely explain the accumulation of megafauna remains, and could have mixed old bones with fresh deposits.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cho rằng hiện tượng thiên nhiên là các trận lũ hoang dã (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"77\">Flood events</em>) có thể đã làm xáo trộn, trộn lẫn xương cũ với các trầm tích mới (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"156\">mixed old bones with fresh deposits</em>), tức là làm nhiễu loạn các bằng chứng khảo cổ (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"240\">disturbed the archaeological evidence</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">38. D — They brought stones there from another area.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“...we speculate that the graziers made sure it was protected from damage... by lining the surface with small stones collected from further afield...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả suy đoán những người chăn nuôi gia súc năm 1876 đã bảo vệ giếng nước bằng cách rải lên bề mặt các viên đá nhỏ được thu lượm từ những nơi xa hơn (<strong data-path-to-node=\"31,1,0\" data-index-in-node=\"165\">collected from further afield / brought stones there from another area</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">39. B — Megafauna could have died out as a result of small numbers being killed year after year.</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"33,0,0\" data-index-in-node=\"26\">“Using a mathematical model, it was found that a group of 10 people killing only one juvenile Diprotodon each year would be sufficient to bring about the extinction of that species within 1,000 years.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô hình toán học chỉ ra chỉ cần một nhóm 10 người giết <em data-path-to-node=\"33,1,0\" data-index-in-node=\"67\">chỉ một</em> con đại động vật non mỗi năm (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"105\">killing only one... each year</em>) là đủ để làm loài đó tuyệt chủng trong 1,000 năm. Ý này tương ứng với việc chết dần do một số lượng nhỏ bị giết từ năm này qua năm khác (<strong data-path-to-node=\"33,1,0\" data-index-in-node=\"273\">small numbers being killed year after year</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">40. D — Their conclusions were based on inconsistent data.</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"35,0,0\" data-index-in-node=\"26\">“We carried out a reanalysis of the scientific data from Cuddie Springs that brings into question their conclusions.”</em> và <em data-path-to-node=\"35,0,0\" data-index-in-node=\"147\">“However, our analysis revealed a number of inconsistencies.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong data-path-to-node=\"35,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lời chỉ trích lớn nhất và xuyên suốt của tác giả đối với Field và Wroe là các kết luận của họ không vững chắc, bởi vì khi phân tích lại dữ liệu khoa học thì phát hiện ra rất nhiều điểm mâu thuẫn, bất hợp lý (<strong data-path-to-node=\"35,1,0\" data-index-in-node=\"220\">based on inconsistent data / a number of inconsistencies</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('5f496b99-dc05-4509-add7-6b4ee0ebc8b4', 'bcb24ba8-0d1c-4371-9148-b1db05b0a857', 'matrix', 'Questions 1–5', '', '<p>Which paragraph contains the following information?</p>
<p>Write the correct letter, A–E</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "mention of several challenges to be overcome before a green roof can be installed", "correctCategoryLetter": "D"}, {"itemText": "reference to a city where green roofs have been promoted for many years", "correctCategoryLetter": "C"}, {"itemText": "examples of how green roofs can work in combination with other green urban initiatives", "correctCategoryLetter": "B"}, {"itemText": "a belief that existing green roofs should be used as a model for new ones", "correctCategoryLetter": "E"}, {"itemText": "the need to make a persuasive argument for the financial benefits of green roofs", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. D — {mention of several challenges to be overcome before a green roof can be installed}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p id=\"p-rc_9c3cfb84cbada3ae-24\" data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"24\">“Other considerations <span class=\"citation-322\">include installing drainage paths, meeting health and safety requirements and perhaps allowing access for the public, as well as planning restrictions and disruption from regular activities in and around the buildings during installation.”</span></em><span class=\"citation-322 citation-end-322\"><sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D liệt kê hàng loạt thách thức và yếu tố phải cân nhắc, xử lý trước và trong khi thi công mái nhà xanh bao gồm: lắp đặt đường thoát nước, đáp ứng yêu cầu an toàn sức khỏe, các hạn chế về quy hoạch và sự gián đoạn các hoạt động thường nhật quanh tòa nhà (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"271\">several challenges / considerations / restrictions / disruption</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. C — {reference to a city where green roofs have been promoted for many years}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"24\">“Canada, has policies dating from the 1990s, encouraging the development of urban farms on rooftops.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A city/country... promoted for many years\" (một thành phố/quốc gia nơi mái nhà xanh được thúc đẩy trong nhiều năm) tương ứng với thông tin về Canada đã có các chính sách khuyến khích nông trại đô thị trên mái nhà bắt đầu từ tận những năm 1990 (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"257\">policies dating from the 1990s</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. B — {examples of how green roofs can work in combination with other green urban initiatives}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"24\">“Ongoing research is showcasing how green roofs in cities can integrate with ‘living walls’... Research also indicates that green roofs can be integrated with drainage systems on the ground, such as street trees...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Work in combination with other green urban initiatives\" (kết hợp với các sáng kiến đô thị xanh khác) tương ứng với cụm từ \"integrate/integrated with\" (tích hợp với) được đoạn B minh họa qua hai ví dụ: tích hợp với tường cây xanh (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"243\">living walls</em>) và tích hợp với hệ thống thoát nước mặt đất như cây xanh đường phố (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"325\">street trees</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. E — {a belief that existing green roofs should be used as a model for new ones}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"24\">“The success stories need to be studied and replicated elsewhere, to make green, blue, brown and food-producing roofs the norm in cities around the world.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Existing green roofs should be used as a model\" (những mái nhà xanh hiện tại nên được dùng làm mô hình/khuôn mẫu) tương ứng với cụm từ \"The success stories need to be studied and replicated elsewhere\" (các câu chuyện thành công cần được nghiên cứu và nhân rộng, bắt chước ở những nơi khác) nhằm biến mô hình này thành chuẩn mực toàn cầu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. D — {the need to make a persuasive argument for the financial benefits of green roofs}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"24\">“To convince investors and developers that installing green roofs is worthwhile, meanwhile, economic arguments are still the most important.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Persuasive argument for the financial benefits\" (lập luận thuyết phục về lợi ích tài chính) tương ứng hoàn toàn với câu viết: để thuyết phục các nhà đầu tư thấy việc này là xứng đáng (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"197\">convince investors... is worthwhile</em>), các lập luận về mặt kinh tế vẫn giữ vai trò quan trọng nhất (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"296\">economic arguments are still the most important</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('b699894c-3f72-4a06-be3b-2cf4c14094d7', 'bcb24ba8-0d1c-4371-9148-b1db05b0a857', 'fillup', 'Questions 6–9', '<p data-section-id="1lzk6qv" data-start="720" data-end="751">Complete the summary below.</p>
<p data-start="753" data-end="811">Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-section-id="6u8mkr" data-start="813" data-end="842"><span style="font-size: 14pt;"><strong>Advantages of green roofs</strong></span></p>
<p data-start="844" data-end="1144">City rooftops covered with greenery have many advantages. These include lessening the likelihood that floods will occur, reducing how much money is spent on <strong data-start="1001" data-end="1017">{energy}</strong> and creating environments that are suitable for wildlife. In many cases, they can also be used for producing <strong data-start="1127" data-end="1143">{food}</strong>.</p>
<p data-start="1146" data-end="1436">There are also social benefits of green roofs. For example, the medical profession recommends <strong data-start="1240" data-end="1256">{gardening}</strong> as an activity to help people cope with mental health issues. Studies have also shown that the availability of green spaces can prevent physical problems such as <strong data-start="1419" data-end="1435">{obesity}</strong>.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">6. energy — {...reducing how much money is spent on energy and creating environments...}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"24\">“Among these benefits are saving on energy costs, mitigating the risk of floods, making habitats for urban wildlife...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"reducing how much money is spent on...\" (giảm số tiền chi trả cho...) đồng nghĩa với cụm từ \"saving on... costs\" (tiết kiệm chi phí về...). Thứ chi phí được tiết kiệm ở đây chính là năng lượng (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"214\">energy</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">7. food — {In many cases, they can also be used for producing food.}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"24\">“Among these benefits are saving on energy costs... and even growing food.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"producing\" (sản xuất/tạo ra) đồng nghĩa với động từ \"growing\" (trồng trọt) trong đoạn A. Mục tiêu gieo trồng ở đây chính là thực phẩm (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"151\">food</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">8. gardening — {...the medical profession recommends gardening as an activity to help...}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"24\">“Doctors are increasingly prescribing time spent gardening outdoors for patients dealing with anxiety and depression.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The medical profession recommends\" (giới y khoa khuyến nghị) tương ứng với hành động \"Doctors are increasingly prescribing\" (bác sĩ ngày càng kê đơn thuốc/chỉ định). Hoạt động ngoài trời được bác sĩ chỉ định để giúp bệnh nhân đối phó với lo âu và trầm cảm là làm vườn (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"282\">gardening</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. obesity — {...can prevent physical problems such as obesity.}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"23,0,0\" data-index-in-node=\"24\">“And research has found that access to even the most basic green spaces can provide a better quality of life for dementia sufferers and help people avoid obesity.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"prevent\" (ngăn chặn/phòng ngừa) đồng nghĩa với động từ \"avoid\" (tránh khỏi) trong đoạn B. Căn bệnh, vấn đề về mặt thể chất (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"140\">physical problems</em>) cần phòng tránh được bài đọc gọi tên là bệnh béo phì (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"213\">obesity</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('3a4f17ea-d8f4-4375-8b08-a7cf6fd7f292', 'bcb24ba8-0d1c-4371-9148-b1db05b0a857', 'checkbox', 'Questions 12 and 13', '', '<p>Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="2013" data-end="2124">Which <strong>TWO </strong>aims of new variations on the concept of green roofs are mentioned in Paragraph E of the passage?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. to provide habitats for a wide range of species"}, {"correct": false, "option_text": "B. to grow plants successfully even in the hottest climates"}, {"correct": false, "option_text": "C. to regulate the temperature of the immediate environment"}, {"correct": true, "option_text": "D. to generate power from a sustainable source"}, {"correct": false, "option_text": "E. to collect water to supply other buildings"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">A. to provide habitats for a wide range of species (Cung cấp môi trường sống cho nhiều loài)</strong></p>\n<ul>\n<li data-path-to-node=\"31,0,1,0,0\"><strong data-path-to-node=\"31,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"31,0,1,0,0\" data-index-in-node=\"24\">“...and ‘brown roofs’ which are wilder in nature and maximise biodiversity.”</em></li>\n<li data-path-to-node=\"31,0,1,1,0\"><strong data-path-to-node=\"31,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Biến thể \"mái nhà nâu\" (<em data-path-to-node=\"31,0,1,1,0\" data-index-in-node=\"36\">brown roofs</em>) mang tính chất hoang dã tự nhiên nhằm mục đích tối đa hóa đa dạng sinh học (<em data-path-to-node=\"31,0,1,1,0\" data-index-in-node=\"125\">maximise biodiversity</em>). Tối đa hóa đa dạng sinh học đồng nghĩa với việc cung cấp nơi ở cho nhiều loài sinh vật khác nhau (<strong data-path-to-node=\"31,0,1,1,0\" data-index-in-node=\"247\">provide habitats for a wide range of species</strong>).</li>\n</ul>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">D. to generate power from a sustainable source (Tạo ra năng lượng từ nguồn bền vững)</strong></p>\n<ul>\n<li data-path-to-node=\"31,1,1,0,0\"><strong data-path-to-node=\"31,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"31,1,1,0,0\" data-index-in-node=\"24\">“There are also combinations of green roofs with solar panels...”</em></li>\n<li data-path-to-node=\"31,1,1,1,0\"><strong data-path-to-node=\"31,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Biến thể kết hợp giữa mái nhà xanh và các tấm pin năng lượng mặt trời (<em data-path-to-node=\"31,1,1,1,0\" data-index-in-node=\"83\">solar panels</em>) chính là nhằm phục vụ cho mục tiêu sản xuất, thu hoạch điện năng từ nguồn năng lượng xanh bền vững (<strong data-path-to-node=\"31,1,1,1,0\" data-index-in-node=\"197\">generate power from a sustainable source</strong>).</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('42026067-3e22-4d5b-824b-e3095cf1a6d0', '82b8d1a2-2290-41a7-8ff9-7973d391d415', 'radio', 'Questions 14–16', '', '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. where the notion of innate intelligence first began"}, {"option_text": "B. when ideas about the nature of intelligence began to shift"}, {"option_text": "C. how scientists have responded to changing views of intelligence"}, {"option_text": "D. why thinkers turned away from the idea of intelligence being fixed"}], "question": "What can we learn from the first paragraph?"}, {"correct": 2, "options": [{"option_text": "A. identify their personal ambitions"}, {"option_text": "B. help each other to realise their goals"}, {"option_text": "C. have confidence in their potential to succeed"}, {"option_text": "D. concentrate on where their particular strengths lie."}], "question": "The second paragraph describes how schools encourage students to"}, {"correct": 3, "options": [{"option_text": "A. tend to be less competitive"}, {"option_text": "B. generally have a low sense of self-esteem"}, {"option_text": "C. will only work hard if they are given constant encouragement"}, {"option_text": "D. are afraid to push themselves beyond what they see as their limitations"}], "question": "In the third paragraph, the writer suggests that students with a fixed mindset"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. B — when ideas about the nature of intelligence began to shift</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"24\">“Then, in the early 20th century, progressive thinkers revolted against the notion that inherent ability is destiny. Instead, educators such as John Dewey argued that every child’s intelligence could be developed...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 1 phác thảo dòng thời gian của sự thay đổi nhận thức: từ thế kỷ 19 với quan điểm trí thông minh là bẩm sinh, sang đến đầu thế kỷ 20 (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"150\">early 20th century</em>), các nhà tư tưởng tiến bộ đã bắt đầu phản kháng lại quan điểm đó. Mốc thời gian này chỉ ra thời điểm các ý tưởng về bản chất trí thông minh bắt đầu dịch chuyển (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"331\">when ideas... began to shift</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. C — have confidence in their potential to succeed.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"24\">“A major focus of the growth mindset in schools is coaxing students away from seeing failure as an indication of their ability, and towards seeing it as a chance to improve that ability.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi hỏi về điều trường học khuyến khích học sinh thực hiện. Đoạn 2 viết các trường học đang hướng học sinh coi thất bại chỉ là cơ hội để cải thiện năng lực cá nhân, tin rằng \"thông minh là thứ bạn có thể rèn luyện để đạt được\". Điều này đồng nghĩa với việc thúc đẩy các em có niềm tin vào tiềm năng thành công của bản thân (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"340\">have confidence in their potential to succeed</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. D — are afraid to push themselves beyond what they see as their limitations.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p id=\"p-rc_4d3415b4350924cd-27\" data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"24\"><span class=\"citation-467 citation-end-467\">“Meanwhile, the former took on only those tasks that would not risk their sense of worth. This group had inferred that success or failure is due to innate ability, and this ‘fixed mindset’ had led them to fe<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>ar failure and lack of effort.”</em></p>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhóm học sinh có tư duy cố định (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"45\">fixed mindset</em>) tin rằng thành bại hoàn toàn do năng lực bẩm sinh quy định, dẫn đến tâm lý sợ thất bại (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"148\">fear failure</em>) và chỉ nhận những nhiệm vụ an toàn, không gây tổn hại đến giá trị bản thân. Điều này đồng nghĩa với việc họ sợ phải bứt phá, đẩy bản thân vượt qua những giới hạn mà họ tự nhìn nhận (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"344\">afraid to push themselves beyond... limitations</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c17584c2-27c8-4c67-bae9-f35c63056151', '82b8d1a2-2290-41a7-8ff9-7973d391d415', 'matrix', 'Questions 17–22', '', '<p data-start="1137" data-end="1201">Match each statement with the correct person or people, <strong data-start="1193" data-end="1200">A–E</strong>.</p>
<p data-start="1203" data-end="1278">Write the correct letter, <strong data-start="1229" data-end="1236">A–E</strong></p>
<p data-start="1203" data-end="1278"><strong>NB </strong>You may use any letter more than once</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of People", "matrixItems": [{"itemText": "The methodology behind the growth mindset studies was not strict enough", "correctCategoryLetter": "C"}, {"itemText": "The idea of the growth mindset has been incorrectly interpreted", "correctCategoryLetter": "B"}, {"itemText": "Intellectual ability is an unchangeable feature of each individual", "correctCategoryLetter": "A"}, {"itemText": "The growth mindset should be promoted without students being aware of it", "correctCategoryLetter": "E"}, {"itemText": "The growth mindset is not simply about boosting students’ morale", "correctCategoryLetter": "B"}, {"itemText": "Research shows that the growth mindset has no effect on academic achievement", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Alfred Binet", "categoryLetter": "A"}, {"categoryText": "Carol Dweck", "categoryLetter": "B"}, {"categoryText": "Andrew Gelman", "categoryLetter": "C"}, {"categoryText": "Timothy Bates", "categoryLetter": "D"}, {"categoryText": "David Yeager and Gregory Walton", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">17. C (Andrew Gelman) — The methodology behind the growth mindset studies was not strict enough.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"24\">“The statistician Andrew Gelman claims that ‘their research designs have enough degrees of freedom that they could take their data to support just about any theory at all’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhà thống kê Andrew Gelman chỉ trích thiết kế nghiên cứu của học thuyết này có quá nhiều \"độ tự do\" đến mức có thể dùng dữ liệu để bẻ lái ủng hộ cho bất kỳ giả thuyết nào. Điều này đồng nghĩa với việc phương pháp luận (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"231\">methodology / research designs</em>) không đủ nghiêm ngặt, chặt chẽ (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"295\">not strict enough</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">18. B (Carol Dweck) — The idea of the growth mindset has been incorrectly interpreted.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"24\">“In fact, she argues that her work has been misunderstood and misapplied in a range of ways.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chính tác giả Carol Dweck đã lên tiếng khẳng định rằng công trình nghiên cứu của cô đã bị hiểu sai (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"112\">misunderstood</em>) và áp dụng sai lệch theo nhiều cách khác nhau. Từ <em data-path-to-node=\"15,1,0\" data-index-in-node=\"177\">\"misunderstood\"</em> đồng nghĩa với cụm <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"212\">incorrectly interpreted</strong> (bị diễn giải sai).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">19. A (Alfred Binet) — Intellectual ability is an unchangeable feature of each individual.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"24\">“Psychologist Alfred Binet, the developer of the first intelligence tests, was one of many 19th-century scientists who held the earlier view and sought to quantify cognitive ability.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The earlier view\" ở đầu đoạn chính là khái niệm trí thông minh là thứ bẩm sinh và cố định (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"104\">intelligence as something innate... fixed</em>). Alfred Binet là một trong những nhà khoa học nắm giữ góc nhìn sơ khai này, tức là coi năng lực trí tuệ là một đặc điểm không thể thay đổi của mỗi cá nhân (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"303\">unchangeable feature</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. E (David Yeager and Gregory Walton) — The growth mindset should be promoted without students being aware of it.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"24\">“Growth mindset supporters David Yeager and Gregory Walton claim that interventions should be delivered in a subtle way to maximise their effectiveness. They say that adolescents perceive a teacher’s intervention as conveying that they are in need of help...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai nhà nghiên cứu Yeager và Walton cho rằng các biện pháp can thiệp cần phải được phân phối một cách tinh tế (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"123\">subtle way</em>), bởi nếu học sinh nhận ra giáo viên đang cố can thiệp, các em sẽ nghĩ mình là kẻ kém cỏi cần giúp đỡ và làm phản tác dụng. Ý này tương ứng hoàn toàn với việc nên thúc đẩy tư duy phát triển mà không để học sinh nhận biết, ý thức được điều đó (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"377\">without students being aware of it</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. B (Carol Dweck) — The growth mindset is not simply about boosting students’ morale.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"24\">“‘For me the growth mindset is a tool for learning and improvement. It’s not just a vehicle for making children feel good.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Carol Dweck bày tỏ lo ngại khi lý thuyết của mình bị đánh đồng với phong trào nâng cao lòng tự trọng. Cô nhấn mạnh tư duy phát triển là công cụ để học tập và tiến bộ, chứ không đơn thuần là một phương tiện chỉ để làm trẻ em cảm thấy vui vẻ, tự mãn (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"261\">not simply about boosting students’ morale / making children feel good</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. D (Timothy Bates) — Research shows that the growth mindset has no effect on academic achievement.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"23,0,0\" data-index-in-node=\"24\">“He notes that: ‘People with a growth mindset don’t cope any better with failure ... Kids with the growth mindset aren’t getting better grades, either before or after our intervention study.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Giáo sư Timothy Bates chỉ ra kết quả thực tế từ nghiên cứu lặp lại của ông là hoàn toàn vô hiệu (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"109\">null</em>): trẻ em có tư duy phát triển không hề đạt được điểm số tốt hơn (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"179\">aren''t getting better grades</em>). Điểm số không tăng đồng nghĩa với việc không có tác động đến thành tích học tập (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"291\">no effect on academic achievement</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('4f23dbb6-dfe6-499c-b61c-0e5b6c6f82c5', '82b8d1a2-2290-41a7-8ff9-7973d391d415', 'radio', 'Questions 23–26', '', '<p>Choose <strong data-start="2089" data-end="2096">YES</strong> – if the statement agrees with the views of the writer, <strong data-start="2154" data-end="2160">NO</strong> – if the statement contradicts the views of the writer, <strong data-start="2218" data-end="2231">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Dweck has handled criticisms of her work in an admirable way"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Students’ self-perception is a more effective driver of self-confidence than actual achievement"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Recent evidence about growth mindset interventions has attracted unfair coverage in the media"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Deliberate attempts to encourage students to strive for high achievement may have a negative effect"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">23. YES</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"27,0,0\" data-index-in-node=\"24\">“Much of this criticism is not lost on Dweck, and she deserves great credit for responding to it and adapting her work accordingly.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nhận định Dweck đã xử lý các lời chỉ trích nhắm vào công trình của mình theo một cách đáng ngưỡng mộ (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"122\">handle criticisms in an admirable way</em>). Điều này đồng nhất với quan điểm của tác giả khi khen ngợi cô ấy xứng đáng nhận được điểm cộng lớn (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"262\">deserves great credit</em>) vì đã phản hồi và tự điều chỉnh công việc của mình một cách phù hợp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">24. NO</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"29,0,0\" data-index-in-node=\"24\">“There is a strong correlation between self-perception and achievement, but there is evidence to suggest that the actual effect of achievement on self-perception is stronger than the other way round.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định nhận thức của học sinh về bản thân là động lực thúc đẩy sự tự tin hiệu quả hơn so với thành tích thực tế đạt được. Ngược lại, tác giả chỉ ra bằng chứng khoa học cho thấy tác động của thành tích thực tế lên nhận thức bản thân mới là chiều có tác động mạnh mẽ hơn (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"294\">actual effect of achievement on self-perception is stronger</em>). Thông tin bị đảo ngược mối quan hệ nên chọn <strong data-path-to-node=\"29,1,0\" data-index-in-node=\"400\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">25. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"31,0,0\" data-index-in-node=\"24\">“Recent evidence would suggest that growth mindset interventions are not the elixir of student learning that its proponents claim it to be.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có đề cập đến việc các bằng chứng gần đây cho thấy các biện pháp can thiệp tư duy phát triển không phải là thần dược như những người ủng hộ tuyên bố, chứ trong toàn bộ văn bản <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"196\">không hề xuất hiện thông tin</strong> nào nói về việc các bằng chứng này có bị truyền thông đưa tin một cách bất công (<em data-path-to-node=\"31,1,0\" data-index-in-node=\"306\">unfair coverage in the media</em>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">26. YES</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"33,0,0\" data-index-in-node=\"24\">“Paradoxically, however, that aspiration is not well served by direct interventions that try to instil it.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói những nỗ lực cố ý nhằm khuyến khích học sinh phấn đấu đạt thành tích cao có thể mang lại tác động tiêu cực (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"132\">negative effect</em>). Điều này trùng khớp hoàn toàn với quan điểm mang tính nghịch lý (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"215\">Paradoxically</em>) của tác giả ở cuối đoạn: khát vọng thay đổi của học sinh sẽ không được phục vụ tốt bởi các biện pháp can thiệp trực tiếp cố tình nhồi nhét nó (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"373\">not well served by direct interventions</em>), và các buổi nói chuyện truyền động lực đôi khi chỉ là sự lãng phí thời gian.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('37022b1a-cca5-4aba-abc3-01a051e8436c', '19176a13-0da7-4df5-aca9-ca5eb5700b0d', 'radio', 'Questions 27–30', '', '<p>Choose <strong data-start="159" data-end="166">YES</strong> – if the statement agrees with the claims of the writer, <strong data-start="225" data-end="231">NO</strong> – if the statement contradicts the claims of the writer, <strong data-start="290" data-end="303">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Wegener’s ideas about continental drift were widely disputed while he was alive"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The idea that the continents remained fixed in place was defended in a number of respected scientific publications"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Wegener relied on a limited range of scientific fields to support his theory of continental drift"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The similarities between Wegener’s theory of continental drift and modern-day plate tectonics are enormous"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. YES</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“His book on the subject, The Origin of Continents and Oceans, went through four editions and was the focus of an international controversy in his lifetime and for some years after his death.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định các ý tưởng của Wegener về trôi dạt lục địa bị tranh cãi rộng rãi khi ông còn sống (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"115\">widely disputed while he was alive</em>). Điều này trùng khớp hoàn toàn với thông tin trong bài: cuốn sách của ông là tâm điểm của một cuộc tranh cãi mang tầm quốc tế ngay trong chính cuộc đời ông (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"308\">the focus of an international controversy in his lifetime</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“Wegener’s basic idea was that many mysteries about the Earth’s history could be solved if one supposed that the continents moved laterally, rather than supposing that they remained fixed in place.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến quan điểm cũ trước đó coi các lục địa nằm cố định một chỗ (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"91\">remained fixed in place</em>). Tuy nhiên, việc quan điểm cố định này có được bảo vệ trong <em data-path-to-node=\"7,1,0\" data-index-in-node=\"176\">hàng loạt ấn phẩm khoa học uy tín</em> (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"211\">defended in a number of respected scientific publications</em>) hay không thì <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"284\">hoàn toàn không được đề cập</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. NO</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p id=\"p-rc_655a8b56d95366fe-31\" data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\"><span class=\"citation-768 citation-end-768\">“Wegener showed in great detail how such continental movements were plausible and how they worked, using evidence from a large number of sciences including geology, geophysics, paleontology, and climatology.”<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span></em></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Wegener chỉ dựa vào một phạm vi hạn chế các lĩnh vực khoa học (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"87\">relied on a limited range</em>) để chứng minh học thuyết của mình. Ngược lại, bài đọc khẳng định ông đã sử dụng bằng chứng từ một số lượng lớn các ngành khoa học (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"245\">using evidence from a large number of sciences</strong>) bao gồm cả địa chất, địa vật lý, cổ sinh vật học và khí hậu học. Thông tin mâu thuẫn trực tiếp nên chọn <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"397\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. NO</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“Plate tectonics is in many respects quite different from Wegener’s proposal, in the same way that modern evolutionary theory is very different from the ideas Charles Darwin proposed...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định sự giống nhau giữa thuyết trôi dạt lục địa của Wegener và thuyết kiến tạo mảng hiện đại ngày nay là cực kỳ to lớn (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"146\">similarities... are enormous</em>). Ngược lại, tác giả viết rằng thuyết kiến tạo mảng trên nhiều phương diện là khá khác biệt (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"268\">quite different</strong>) so với đề xuất ban đầu của Wegener. Thông tin bị trái ngược hoàn toàn nên chọn <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"364\">NO</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('ef9a973d-d884-4c5c-8399-6f30eede7993', '19176a13-0da7-4df5-aca9-ca5eb5700b0d', 'matching', 'Questions 31–36', '', '<p>Complete the summary using the list of phrases, <strong>A</strong>–<strong>J</strong>, below.</p>
<p>Write the correct letter, <strong>A</strong>–<strong>J</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<h3 data-section-id=\"15nn0a1\" data-start=\"971\" data-end=\"998\">Wegener’s life and work</h3>\n<p data-start=\"1000\" data-end=\"1634\">One of the remarkable things about Wegener from a {I. biographer’s perspective} is that although he proposed a theory of continental drift, he was not a geologist. His {F. professional interests} were limited to atmospheric physics. However, at the time he proposed his theory of continental drift in 1912, he was already a person of {A. modest fame}. Six years previously, there had been his {C. record-breaking achievement} of 52 hours in a hot-air balloon, followed by his well-publicised but {H. hazardous exploration} of Greenland’s coast. With the publication of his textbook on thermodynamics, he had also come to the attention of a {E. select group} of German scientists.</p>", "optionsTitle": "List of phrases", "answerOptions": [{"optionText": "A. modest fame"}, {"optionText": "B. vast range"}, {"optionText": "C. record-breaking achievement"}, {"optionText": "D. research methods"}, {"optionText": "E. select group"}, {"optionText": "F. professional interests"}, {"optionText": "G. scientific debate"}, {"optionText": "H. hazardous exploration"}, {"optionText": "I. biographer’s perspective"}, {"optionText": "J. narrow investigation"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. I (biographer’s perspective)</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“When I started writing about Wegener’s life and work, one of the most intriguing things about him for me was that, although he came up with a theory on continental drift, he was not a geologist.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người xưng \"Tôi\" (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"30\">I / me</em>) trong bài chính là tác giả Mott T. Greene - người đang đóng vai trò viết lại tiểu sử của Wegener. Do đó, việc nhìn nhận điều kỳ lạ này xuất phát từ góc nhìn/lăng kính của một nhà viết tiểu sử (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"231\">biographer’s perspective</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. F (professional interests)</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“He trained as an astronomer and pursued a career in atmospheric physics.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"career\" (sự nghiệp, ngành nghề theo đuổi) và \"trained as\" (được đào tạo thành) tương ứng hoàn toàn với các mối quan tâm nghề nghiệp, chuyên môn (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"165\">professional interests</strong>) của ông trong lĩnh vực vật lý khí quyển và thiên văn học.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. A (modest fame)</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“However, he was not an ‘unknown’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc viết vào năm 1912 ông không phải là một kẻ \"vô danh\" (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"74\">not an unknown</em>), tức là ông đã có một sự nổi tiếng nhất định, danh tiếng ở mức độ vừa phải (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"166\">modest fame</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. C (record-breaking achievement)</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“In 1906 he had set a world record (with his brother Kurt) for time aloft in a hot-air balloon: 52 hours.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc bay trên khinh khí cầu suốt 52 giờ và thiết lập một kỷ lục thế giới (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"86\">set a world record</em>) chính là một thành tựu phá kỷ lục (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"141\">record-breaking achievement</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. H (hazardous exploration)</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“Between 1906 and 1908 he had taken part in a highly publicized and extremely dangerous expedition to the coast of northeast Greenland.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"expedition\" (cuộc thám hiểm) đồng nghĩa với \"exploration\". Tính từ \"extremely dangerous\" (cực kỳ nguy hiểm) đồng nghĩa với tính từ nguy hiểm, rủi ro cao (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"170\">hazardous</strong>). Do đó cụm phù hợp là <strong data-path-to-node=\"23,1,0\" data-index-in-node=\"203\">hazardous exploration</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">36. E (select group)</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“He had also made a name for himself amongst a small circle of meteorologists and atmospheric physicists in Germany...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"a small circle\" (một nhóm nhỏ, một vòng tròn nhỏ những người quen biết nhau cùng ngành) được paraphrase hoàn toàn thành cụm từ một nhóm chọn lọc, tinh hoa (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"176\">select group</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('28868cbf-e835-474e-a923-57b5bc441d3b', '19176a13-0da7-4df5-aca9-ca5eb5700b0d', 'radio', 'Questions 37–40', '', '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. describing what motivated him to write the book"}, {"option_text": "B. explaining why it is desirable to read the whole book"}, {"option_text": "C. suggesting why Wegener pursued so many different careers"}, {"option_text": "D. indicating what aspects of Wegener’s life interested him most"}], "question": "What is Mott T Greene doing in the fifth paragraph?"}, {"correct": 2, "options": [{"option_text": "A. He was not a particularly ambitious person"}, {"option_text": "B. He kept a record of all his scientific observations"}, {"option_text": "C. He did not adopt many of the scientific practices of the time"}, {"option_text": "D. He enjoyed discussing new discoveries with other scientists"}], "question": "What is said about Wegener in the sixth paragraph?"}, {"correct": 3, "options": [{"option_text": "A. Their published works had a greater impact than Wegener’s did"}, {"option_text": "B. They had fewer doubts about their scientific ideas than Wegener did"}, {"option_text": "C. Their scientific ideas were more controversial than Wegener’s."}, {"option_text": "D. They are easier subjects to write about than Wegener"}], "question": "What does Greene say about some other famous scientists?"}, {"correct": 2, "options": [{"option_text": "A. It is not enough in life to have good intentions"}, {"option_text": "B. People need to plan carefully if they want to succeed"}, {"option_text": "C. People have little control over many aspects of their lives"}, {"option_text": "D. It is important that people ensure they have the freedom to act"}], "question": "What is Greene’s main point in the final paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">37. B — explaining why it is desirable to read the whole book</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p id=\"p-rc_655a8b56d95366fe-32\" data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\"><span class=\"citation-767 citation-end-767\">“My own feeling, however, is that the parts do not make as much sense on their own as do all of his activities taken together. In this respect I urge readers to try to experience Wegener’s life as he lived i<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span>t...”</em></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở đoạn 5, tác giả khuyên độc giả rằng mặc dù có thể dùng bảng mục lục/chỉ mục để tra cứu riêng lẻ từng phần, nhưng nếu tách rời ra thì các phần sẽ không mang lại nhiều ý nghĩa bằng việc gộp tất cả các hoạt động lại với nhau. Từ đó, ông kêu gọi, thúc giục độc giả (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"276\">urge readers</em>) hãy trải nghiệm toàn bộ cuộc đời của Wegener, tức là giải thích lý do vì sao việc đọc trọn vẹn cuốn sách là điều đáng làm (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"413\">desirable to read the whole book</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">38. C — He did not adopt many of the scientific practices of the time.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“He was not active (with a few exceptions) in scientific societies, and did not seek to find influence or advance his ideas through professional contacts and politics...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 6 mô tả Wegener không hề tích cực tham gia vào các hiệp hội khoa học, không tìm kiếm tầm ảnh hưởng bằng con đường quan hệ chính trị hay kết nối nghề nghiệp như thói quen thông thường thời bấy giờ (<em data-path-to-node=\"31,1,0\" data-index-in-node=\"214\">as was standard practice</em>). Thay vào đó, ông chọn ở ẩn một mình để viết lách và đi thực địa. Điều này đồng nghĩa với việc ông không làm theo nhiều thông lệ, thói quen nghiên cứu khoa học cùng thời (<strong data-path-to-node=\"31,1,0\" data-index-in-node=\"411\">did not adopt many of the scientific practices of the time</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">39. D — They are easier subjects to write about than Wegener.</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"33,0,0\" data-index-in-node=\"26\">“The more such material a scientist leaves behind, the better chance a biographer has of forming an accurate picture of how a scientist’s ideas took shape and evolved.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đối chiếu Wegener (người không để lại nhật ký, sổ tay hay thư từ gì) với các vĩ nhân khác như Newton, Darwin, Einstein hay Faraday (những người để lại cả núi tài liệu giấy tờ). Tác giả kết luận: nhà khoa học nào để lại càng nhiều tài liệu thì người viết tiểu sử càng có cơ hội tốt hơn để dựng lại bức tranh chính xác. Vì thế, những nhà khoa học khác là những đối tượng dễ viết tiểu sử hơn so với Wegener (<strong data-path-to-node=\"33,1,0\" data-index-in-node=\"425\">easier subjects to write about</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">40. C — People have little control over many aspects of their lives.</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"35,0,0\" data-index-in-node=\"26\">“We plan, think, and act, often with apparent freedom but most of the time our lives ‘happen to us’, and we only retrospectively turn this happenstance into a coherent narrative of fulfilled intentions.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong data-path-to-node=\"35,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn văn kết bài, luận điểm cốt lõi mà Greene muốn truyền tải là con người thường không thực sự là tác giả làm chủ cuộc đời mình. Chúng ta lên kế hoạch và hành động có vẻ tự do, nhưng phần lớn thời gian cuộc đời tự \"xảy ra\" với chúng ta (<em data-path-to-node=\"35,1,0\" data-index-in-node=\"256\">lives ''happen to us''</em>). Ý này khẳng định con người có rất ít quyền kiểm soát đối với nhiều khía cạnh trong cuộc sống của mình (<strong data-path-to-node=\"35,1,0\" data-index-in-node=\"382\">People have little control over many aspects of their lives</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('bef1bfb4-6c64-40e1-a08f-d9432e83ecfa', '367bbdb6-1a72-4935-9276-4dd4d4e4d671', 'fillup', 'Questions 1-10', '<p>Complete the form below.</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 75.7662%; height: 474.2px; border-width: 2px;" border="1"><colgroup> <col style="width: 100%;"></colgroup>
<tbody>
<tr style="height: 61.2375px;">
<td style="text-align: center; border-width: 2px;">
<p><span style="font-size: 14pt;"><strong>Oz Housesitters-home Owner Registration Form</strong></span></p>
</td>
</tr>
<tr style="height: 412.962px;">
<td style="border-width: 2px;">
<p><span style="font-size: 12pt;"><strong>Name</strong>: Jenny Hall</span></p>
<p><span style="font-size: 12pt;"><strong>Address</strong>: 14 {Gray} St Greenfield</span></p>
<p><span style="font-size: 12pt;"><strong>Mobile no</strong>: {0491577248}</span></p>
<p><span style="font-size: 12pt;"><strong>Date required from</strong>: {29th September|29 September}</span></p>
<p><span style="font-size: 12pt;"><strong>Length of time required</strong>: {3} weeks</span></p>
<p><span style="font-size: 12pt;"><strong>House features</strong>:</span><br><span style="font-size: 12pt;">• it has a new {pool}</span><br><span style="font-size: 12pt;">• it is near a station</span><br><span style="font-size: 12pt;">• there is room for the housesitter’s {car}</span></p>
<p><span style="font-size: 12pt;"><strong>Special duties required</strong>:</span><br><span style="font-size: 12pt;">• water the {lemon} tree</span></p>
<p><span style="font-size: 12pt;"><strong>Housesitter requirements</strong>:</span><br><span style="font-size: 12pt;">• the house is large so a {couple} is preferred.</span><br><span style="font-size: 12pt;">• no {smoking} allowed</span><br><span style="font-size: 12pt;">• would like a check carried out by the {police}</span></p>
</td>
</tr>
</tbody>
</table>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 class=\"\" data-path-to-node=\"2\">PART 1</h2>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Hello,</span><span class=\"\"> Oz House Sitters,</span><span class=\"\"> Adam here.</span></p>\n<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Oh hello.</span><span class=\"\"> My husband and I are going on a trip overseas and we’d like someone to stay in our house and look after it while we’re away.</span><span class=\"\"> Is that something you can help us with?</span></p>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> It most certainly is.</span><span class=\"\"> We can take care of all the arrangements for you.</span></p>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> OK,</span><span class=\"\"> great.</span></p>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Now,</span><span class=\"\"> can I just get some contact details from you for the form?</span><span class=\"\"> Your name is Jenny…</span></p>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Jenny Hall,</span><span class=\"\"> thank you.</span></p>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Now,</span><span class=\"\"> what’s your address?</span></p>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> 14 </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"10\">(1) Gray</strong></span><span class=\"\"> Street.</span></p>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Is that G-R-E-Y or G-R-A-Y?</span></p>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> A-Y,</span><span class=\"\"> right.</span></p>\n<p data-path-to-node=\"13\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> And what’s the suburb?</span></p>\n<p data-path-to-node=\"14\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Greenfield.</span></p>\n<p data-path-to-node=\"15\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Oh,</span><span class=\"\"> I know it.</span><span class=\"\"> And if I can just get a contact telephone number?</span></p>\n<p data-path-to-node=\"16\"><strong class=\"\" data-path-to-node=\"16\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> I’ll give you my mobile number,</span><span class=\"\"> that’s probably the best one to use.</span><span class=\"\"> It’s </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"16\" data-index-in-node=\"81\">(2) 0491577248</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"17\"><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Thanks.</span><span class=\"\"> Now,</span><span class=\"\"> when did you want the house sitter to start?</span></p>\n<p data-path-to-node=\"18\"><strong class=\"\" data-path-to-node=\"18\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> We’re flying out on the 25th of September,</span><span class=\"\"> but my brother will be in the house for a few days until the 28th.</span><span class=\"\"> So from the </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"18\" data-index-in-node=\"129\">(3) 29th September</strong></span><span class=\"\">,</span><span class=\"\"> please.</span></p>\n<p data-path-to-node=\"19\"><strong class=\"\" data-path-to-node=\"19\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> I’ll note that down.</span><span class=\"\"> And how long do you want the house sitter for?</span></p>\n<p data-path-to-node=\"20\"><strong class=\"\" data-path-to-node=\"20\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Well,</span><span class=\"\"> I’ll be attending a training course in Paris for two weeks,</span><span class=\"\"> but we’re also going to visit my niece in Singapore on the way home to Australia for a few days.</span><span class=\"\"> So shall I put down </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"20\" data-index-in-node=\"190\">(4) 3</strong><span class=\"\"> weeks?</span></span></p>\n<p data-path-to-node=\"21\"><strong class=\"\" data-path-to-node=\"21\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Hmm,</span><span class=\"\"> that sounds about right.</span><span class=\"\"> I think 4 would be too long.</span><span class=\"\"> Sure,</span><span class=\"\"> now Jenny,</span><span class=\"\"> can you tell me more about the features of your house?</span><span class=\"\"> This helps us to match house sitters and home owners.</span></p>\n<p data-path-to-node=\"22\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Sure,</span><span class=\"\"> what do you want to know?</span></p>\n<p data-path-to-node=\"23\"><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Does the house have air conditioning?</span></p>\n<p data-path-to-node=\"24\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> No,</span><span class=\"\"> we don’t like using it,</span><span class=\"\"> we prefer the fresh air.</span><span class=\"\"> But last year we did put in a </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"90\">(5) pool</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"25\"><strong class=\"\" data-path-to-node=\"25\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Very nice.</span><span class=\"\"> And are there any other attractive features?</span><span class=\"\"> Is your house near a beach,</span><span class=\"\"> for example?</span></p>\n<p data-path-to-node=\"26\"><strong class=\"\" data-path-to-node=\"26\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> No,</span><span class=\"\"> not really,</span><span class=\"\"> we’re about an hour’s drive away.</span><span class=\"\"> But we are close to a station,</span><span class=\"\"> so it’s handy for anyone getting into work and so on.</span></p>\n<p data-path-to-node=\"27\"><strong class=\"\" data-path-to-node=\"27\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> OK,</span><span class=\"\"> great.</span><span class=\"\"> Now if our house sitter has their own transport,</span><span class=\"\"> is there any space for them to park?</span></p>\n<p data-path-to-node=\"28\"><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Well,</span><span class=\"\"> we won’t be taking our </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"36\">(6) car</strong></span><span class=\"\">,</span><span class=\"\"> but it’s a large double garage,</span><span class=\"\"> there will be space for one more.</span></p>\n<p data-path-to-node=\"29\"><strong class=\"\" data-path-to-node=\"29\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> OK,</span><span class=\"\"> great,</span><span class=\"\"> I’ll note that down too.</span></p>\n<hr class=\"\" data-path-to-node=\"30\">\n<p data-path-to-node=\"31\"><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> And are there any special duties that you’ll need the house sitter to carry out?</span></p>\n<p data-path-to-node=\"32\"><strong class=\"\" data-path-to-node=\"32\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Oh,</span><span class=\"\"> I don’t know.</span><span class=\"\"> What do people normally ask for?</span></p>\n<p data-path-to-node=\"33\"><strong class=\"\" data-path-to-node=\"33\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Well,</span><span class=\"\"> for example,</span><span class=\"\"> one common chore is looking after the garden.</span></p>\n<p data-path-to-node=\"34\"><strong class=\"\" data-path-to-node=\"34\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Oh yes,</span><span class=\"\"> we have an orange tree and an apple tree which are both watered automatically.</span><span class=\"\"> But we haven’t connected the sprinkler to our </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"34\" data-index-in-node=\"140\">(7) lemon</strong></span><span class=\"\"> tree yet,</span><span class=\"\"> so they’ll need to water that one.</span></p>\n<p data-path-to-node=\"35\"><strong class=\"\" data-path-to-node=\"35\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Sure.</span><span class=\"\"> Now Jenny,</span><span class=\"\"> do you have any special requirements for your house sitter?</span></p>\n<p data-path-to-node=\"36\"><strong class=\"\" data-path-to-node=\"36\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Well,</span><span class=\"\"> I don’t know if this is possible,</span><span class=\"\"> but I’d probably rather have a </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"36\" data-index-in-node=\"78\">(8) couple</strong></span><span class=\"\"> than someone who’s single.</span><span class=\"\"> The house might be a bit too big for just one person.</span></p>\n<p data-path-to-node=\"37\"><strong class=\"\" data-path-to-node=\"37\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> Sure.</span><span class=\"\"> Now,</span><span class=\"\"> many of our owners ask for sitters without children.</span><span class=\"\"> What’s your preference?</span></p>\n<p data-path-to-node=\"38\"><strong class=\"\" data-path-to-node=\"38\" data-index-in-node=\"0\">Jenny:</strong><span class=\"\"> Oh,</span><span class=\"\"> that’s no problem,</span><span class=\"\"> there’s nothing they can break.</span></p>\n<p data-path-to-node=\"39\"><strong class=\"\" data-path-to-node=\"39\" data-index-in-node=\"0\">Adam:</strong><span class=\"\"> What about smoking?</span></p>\n<p data-path-to-node=\"40\"><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"0\">Jenny:</strong> Oh no, I can’t stand the smell. Definitely no <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"40\" data-index-in-node=\"53\">(9) smoking</strong></span> allowed.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Adam:</strong> Now, how do I know that my house is going to be safe with the house sitters?</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Jenny:</strong> Well, we check all of our house sitters very carefully. They have to provide references, but as well as that, you can ask for a <span style=\"background-color: #ffe786;\"><strong><span style=\"text-decoration: underline;\">(10) police</span></strong></span> check if you want to.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Adam:</strong> Oh yes, I’d like to do that please.</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Jenny:</strong> OK, no problem. That’s all I need for now, OK.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('32d508ad-2ba6-40e7-ac34-59b17845c9e3', '1cbf83c7-7ff5-4ce8-ac95-a9d34575ab0e', 'radio', 'Questions 11-15', NULL, '<p>Choose the correct answers</p>
<p><strong>Working at Parson’s Fruit Farm</strong></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "The backpackers'' hostel is full."}, {"content": "The motel is close to the farm."}, {"content": "The campground is cheap."}], "question": "What does the manager say about accommodation?"}, {"correct": 2, "options": [{"content": "perfect for growing fruit."}, {"content": "worse than last year."}, {"content": "hard to predict accurately."}], "question": "The weather this summer has been"}, {"correct": 0, "options": [{"content": "require an appropriate licence."}, {"content": "need previous orchard experience."}, {"content": "must be over 18 years old."}], "question": "The manager says that tractor drivers"}, {"correct": 1, "options": [{"content": "may be rather hot."}, {"content": "can be noisy at times."}, {"content": "will often be dirty."}], "question": "Working inside the shed"}, {"correct": 0, "options": [{"content": "Eat and drink regularly."}, {"content": "Try not to damage the trees."}, {"content": "Leave your phones in a secure location."}], "question": "What final advice does the manager give?"}]', 'null', 'null', 'null', '[{"content": "<h2 class=\"\" data-path-to-node=\"2\">PART 2</h2>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong><span class=\"\"> Well hello everyone and welcome to Parsons Fruit Farm.</span><span class=\"\"> It’s good to see a mix of so many different nationalities who have all come here on their working holidays.</span><span class=\"\"> I’m sure you’re gonna enjoy working on our farm.</span></p>\n<p data-path-to-node=\"4\"><span class=\"\">First of all,</span><span class=\"\"> just a few words about accommodation.</span><span class=\"\"> I know that some of you have pitched your tents down at the campground but are looking for something more comfortable.</span><span class=\"\"> So one option is the motel.</span><span class=\"\"> It’s </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"204\">(11) located very conveniently just a few minutes away (B: close to the farm)</strong></span><span class=\"\"> and they often do reduced rates if you’re staying long term.</span><span class=\"\"> And then the Backpackers Hostel is always very popular,</span><span class=\"\"> though it can be busy at this time of year.</span></p>\n<p data-path-to-node=\"5\"><span class=\"\">Okay,</span><span class=\"\"> so the work itself.</span><span class=\"\"> This summer the weather’s been pretty mixed.</span><span class=\"\"> We’ve had a bit of everything and </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"105\">(12) the forecasts have always been wrong (C: hard to predict accurately)</strong><span class=\"\">.</span></span><span class=\"\"> So some of the apples and pears aren’t in great condition.</span><span class=\"\"> That said,</span><span class=\"\"> this season’s been better than some we’ve had recently and the autumn looks like it’s gonna be great,</span><span class=\"\"> so we should have ideal conditions for the harvest.</span></p>\n<p data-path-to-node=\"6\"><span class=\"\">So there are a number of different jobs to do.</span><span class=\"\"> Most of you will be fruit picking.</span><span class=\"\"> We’ll give all the fruit pickers gloves to wear to protect your fingers so you won’t hurt yourselves.</span><span class=\"\"> We’ll also be looking for some tractor drivers.</span><span class=\"\"> Their job is to collect the full baskets of fruit and take them to the shed.</span><span class=\"\"> I should say in this country,</span><span class=\"\"> anyone is allowed to drive a tractor on farmland once they’re 13 rather than 18 as in some countries.</span><span class=\"\"> However,</span><span class=\"\"> we do have certain rules that are specific to our farm.</span><span class=\"\"> You don’t need to have done farm work before,</span><span class=\"\"> but here you </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"565\">(13) must have a relevant document or permit from your country (A: require an appropriate license)</strong></span><span class=\"\"> that allows you to operate this type of vehicle.</span></p>\n<p data-path-to-node=\"7\"><span class=\"\">Then there are also lots of jobs working inside the shed.</span><span class=\"\"> This involves sorting the fruit and cleaning it if necessary.</span><span class=\"\"> There’s a lot of heavy machinery in the shed,</span><span class=\"\"> so </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"169\">(14) when that’s operating, you must wear your ear protection (B: can be noisy)</strong></span><span class=\"\">.</span><span class=\"\"> The big advantage is the shed’s fully air conditioned,</span><span class=\"\"> so it’s a pleasant environment regardless of what the weather’s doing outside.</span></p>\n<p data-path-to-node=\"8\"><span class=\"\">Alright well,</span><span class=\"\"> whatever job you do,</span><span class=\"\"> I’ll just give you some final advice.</span><span class=\"\"> When you’re picking the fruit,</span><span class=\"\"> sometimes you can break off a small branch—that’s not something you need to be worried about,</span><span class=\"\"> it’ll grow back.</span><span class=\"\"> Also </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"220\">(15) remember to have snacks and use your water bottles (A: eat and drink regularly)</strong></span><span class=\"\">; often people get exhausted quickly during harvest time.</span><span class=\"\"> And if you’ve got a mobile or cell,</span><span class=\"\"> keep it with you at all times in case there’s an emergency.</span></p>\n<hr class=\"\" data-path-to-node=\"9\">\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Manager:</strong><span class=\"\"> Alright,</span><span class=\"\"> I’d like to quickly go over where everything is located.</span><span class=\"\"> So look at your maps of Parsons Fruit Farm and find the main yard.</span><span class=\"\"> It’s towards the bottom of your maps—that really is the center of the farm.</span></p>\n<p data-path-to-node=\"11\"><span class=\"\">Okay,</span><span class=\"\"> the first place I’ll mention is the </span><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"42\">workshop</strong><span class=\"\">.</span><span class=\"\"> This is close to the main yard,</span><span class=\"\"> but you actually have to leave the yard to get into it.</span><span class=\"\"> So you need to take the road that goes out to the orchards and you </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"207\">access the workshop from there (16: G)</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"12\"><span class=\"\">Then the </span><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"9\">lunchroom</strong><span class=\"\">.</span><span class=\"\"> On the north side of the map,</span><span class=\"\"> there’s a road that curves sharply round to the left.</span> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"104\">Halfway around this bend (17: B)</strong><span class=\"\">,</span></span><span class=\"\"> you’ll find the entrance to the lunchroom.</span><span class=\"\"> It’s a pretty place next to the river and also beside a little wood.</span></p>\n<p data-path-to-node=\"13\"><span class=\"\">You also need to be able to find the </span><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"37\">farm office</strong><span class=\"\">.</span><span class=\"\"> So if you look at the main yard,</span><span class=\"\"> you’ll see there’s a number of different buildings located around it,</span><span class=\"\"> and the farm office is the </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"180\">smallest one on the south side (18: H)</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"14\"><span class=\"\">Obviously the </span><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"14\">first aid room</strong><span class=\"\"> is important.</span><span class=\"\"> Now this is close to the main yard so it’s quick to get there,</span><span class=\"\"> and it’s actually more or less in the middle of your maps.</span><span class=\"\"> That </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"170\">little building that’s attached to the farmhouse (19: F)</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"15\"><span class=\"\">Then the </span><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"9\">store shed</strong><span class=\"\">.</span><span class=\"\"> From the main yard,</span><span class=\"\"> take the road heading north.</span><span class=\"\"> Go past the farmhouse and turn right.</span><span class=\"\"> <span style=\"text-decoration: underline; background-color: #ffe786;\">The </span></span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"112\">store is down that road (20: C)</strong><span class=\"\">.</span></span><span class=\"\"> If you come to the vegetable gardens,</span><span class=\"\"> you’ve gone too far.</span></p>\n<p data-path-to-node=\"16\"><span class=\"\">Now the other thing is…</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('02470af5-3407-4c5a-b969-95d0844e832c', '1cbf83c7-7ff5-4ce8-ac95-a9d34575ab0e', 'matrix', 'Questions 16-20', '<p>Label the map below.</p>
<p>Choose the correct letter, A–I, next to questions 16–20.</p>
<p><img decoding="async" src="data:image/png;base64," width="382" height="402" loading="lazy"></p>
<p>Workshop  {G}<br />Lunchroom  {B}<br />Farm Office  {H}<br />First Aid Room  {F}<br />Store Shed {C}</p>
', '<p>Label the map below.</p>
<p>Choose the correct letter, A–I, next to questions 16–20.</p>
<p><img decoding="async" src="data:image/png;base64," width="443" height="465" loading="lazy"></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Workshop", "correctCategoryLetter": "G"}, {"itemText": "Lunchroom", "correctCategoryLetter": "B"}, {"itemText": "Farm Office ", "correctCategoryLetter": "H"}, {"itemText": "First Aid Room", "correctCategoryLetter": "F"}, {"itemText": "Store Shed", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('1145a826-6e6d-4ea3-92cf-4b6fd07ab4c7', '24ed850f-141e-4e4f-8cb8-bd684e972215', 'fillup', 'Questions 21-22', '<p>Write <strong>NO MORE THAN THREE WORDS</strong> for each answer.</p>
<p>Reasons for having study Syndicates:</p>
<p>Teaching one another is a good way to learn</p>
<p>It gives the opportunity to {Share ideas}</p>
<p>Shared reading means fuller notes</p>
<p>You can do {Much deeper research}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 3</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Andy:</strong> Right then, are we ready Bob, Helen?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Bob:</strong> Uh, yeah.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Helen:</strong> And is someone taking notes for John? He’s at a tutorial isn&#8217;t he?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Andy:</strong> Yeah, I’ll let him know what we agree. Good, okay. Well, first thing is, has anyone apart from me actually been in a study syndicate before?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Bob/Helen:</strong> No.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Helen:</strong> What does it actually involve, Andy?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Andy:</strong> Well, the idea is that it’s a way for us, for students, to study together without a teacher. When I did it last time I found it helpful because, well as I said, there’s no teacher, so it means we’re teaching one another and I found I really learnt a lot through having to teach it myself. It seemed a very good way to learn.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Bob:</strong> And presumably it gives us the chance to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"10\" data-index-in-node=\"46\">(21) share ideas</strong></span> as well.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Helen:</strong> And you get fuller notes if you’re all doing the reading.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Andy:</strong> That’s right, and as well as that, because of that really, you can do, you know, <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"87\">(22) much deeper research</strong></span>. So I thought we could try it to revise what we’ve done on the geology course, cause I know this is the one that most of us are worried about—the geology exam.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Bob:</strong> Alright, yes. So the idea is we all look at a different topic, um, a different topic from the geology course and then give a presentation and talk about it.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Andy:</strong> That’s right. I’ve drawn up the framework of a table which might be useful here. I’ve made a copy.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Helen:</strong> Oh, thanks.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Andy:</strong> For the first topic, I thought we could maybe do <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"16\" data-index-in-node=\"55\">(23) mountain building</strong>.</span> Is that alright?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Bob:</strong> Yeah, sure. Actually, would you mind if I did that? I’m quite interested in it.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Andy:</strong> Right, right. So is May 9th okay for that?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Bob:</strong> Uh-huh, yeah. I’ll just write that down: May 9th, Bob, Mountain Building.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Andy:</strong> And the following week, it can’t be May 16th because of our tutorial, but what about the<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"20\" data-index-in-node=\"95\">(24) 17th May</strong> (hoặc <strong data-path-to-node=\"20\" data-index-in-node=\"115\">May 17th</strong>)?</span></span></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Bob:</strong> Hmm, okay.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Andy:</strong> And what about the next topic? What would be the next priority?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Helen:</strong> Well, there’s glaciated areas, but I don’t want to do that.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Andy:</strong> Fair enough. Actually, I don’t mind having a bash. I did an assignment on them. So, Glaciated areas, Andy. Then we need someone to do rock formation.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Helen:</strong> Yeah, okay. And John said he’d like to too. So you can put us both down for that. When?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Andy:</strong> May 23rd would be best. Rock formation, Helen and John. Right, that really only leaves one week before the exams. Shall we make it on the 30th?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Bob:</strong> Uh, I can’t make it, I’m afraid. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"27\" data-index-in-node=\"38\">(25) 29th May</strong> (hoặc <strong data-path-to-node=\"27\" data-index-in-node=\"58\">May 29th</strong>)</span>? The exam&#8217;s on June 3rd, it&#8217;ll have to be.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Andy:</strong> OK. Any ideas for a topic?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Helen:</strong> Uh, John said he wouldn’t mind doing something on volcanoes.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Andy:</strong> Great, that’s everyone then.</p>\n<hr data-path-to-node=\"31\" />\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Andy:</strong> And um, how long should these presentations be?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Bob:</strong> Well, it’s obviously up to us. In my experience, 30 minutes is about enough.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Helen:</strong> Hmm, maybe a bit short. I’d have thought 40 minutes would be more like it.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Andy:</strong> Well, should we say <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"35\" data-index-in-node=\"26\">(26) 30–40 minutes</strong></span>?</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Helen:</strong> Okay, and presumably time for <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"36\" data-index-in-node=\"37\">(27) questions and discussion</strong> ?</span></span></p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Andy:</strong> Yes, together they usually take about 20 minutes. Where should we get the information from? Is it mainly lecture notes?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Bob:</strong> Well actually, I suggest we avoid those because we already have all that information. I think it’s better to go more deeply. We could use the bibliography and anything else we find in the library.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Helen:</strong> Any other books? Hmm, and articles, you know, from the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"39\" data-index-in-node=\"62\">(28) journals</strong> (hoặc <strong data-path-to-node=\"39\" data-index-in-node=\"82\">journal</strong>).</span></p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Andy:</strong> And then of course there’s lots of stuff on the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"40\" data-index-in-node=\"54\">(29) internet</strong>.</span></p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Bob:</strong> Yes, that’s the sort of thing.</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Andy:</strong> And what about the presentations? Will we just be talking?</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Bob:</strong> Uh, presumably we can’t use slides, it’d be a bit difficult. But uh, we can use the OHP (Overhead Projector) and the whiteboard of course. And we can make <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"43\" data-index-in-node=\"160\">(30) photocopy </strong></span>of our notes so everyone can have a copy.</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Helen:</strong> Yes, great. So is there anything else?</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('7ab78c75-faff-4f8a-863e-e4642ef3b80a', '24ed850f-141e-4e4f-8cb8-bd684e972215', 'fillup', 'Question 23-25', '<p>Complete the table below</p>
